#include "biblia.h"

void Biblia::CarregarSalmos(Biblia* b) {
    b->dados[SALMOS].nome = _("Salmos");

    b->dados[SALMOS].capitulos[1].versos[1] = _("Bem-aventurado o homem que não anda segundo o conselho dos ímpios, nem se detém no caminho dos pecadores, nem se assenta na roda dos escarnecedores;");
    b->dados[SALMOS].capitulos[1].versos[2] = _("antes tem seu prazer na lei do Senhor, e na sua lei medita de dia e noite.");
    b->dados[SALMOS].capitulos[1].versos[3] = _("Pois será como a árvore plantada junto às correntes de águas, a qual dá o seu fruto na estação própria, e cuja folha não cai; e tudo quanto fizer prosperará.");
    b->dados[SALMOS].capitulos[1].versos[4] = _("Não são assim os ímpios, mas são semelhantes à moinha que o vento espalha.");
    b->dados[SALMOS].capitulos[1].versos[5] = _("Pelo que os ímpios não subsistirão no juízo, nem os pecadores na congregação dos justos;");
    b->dados[SALMOS].capitulos[1].versos[6] = _("porque o Senhor conhece o caminho dos justos, mas o caminho dos ímpios conduz à ruína.");

    b->dados[SALMOS].capitulos[2].versos[1] = _("Por que se amotinam as nações, e os povos tramam em vão?");
    b->dados[SALMOS].capitulos[2].versos[2] = _("Os reis da terra se levantam, e os príncipes juntos conspiram contra o Senhor e contra o seu ungido, dizendo:");
    b->dados[SALMOS].capitulos[2].versos[3] = _("Rompamos as suas ataduras, e sacudamos de nós as suas cordas.");
    b->dados[SALMOS].capitulos[2].versos[4] = _("Aquele que está sentado nos céus se rirá; o Senhor zombará deles.");
    b->dados[SALMOS].capitulos[2].versos[5] = _("Então lhes falará na sua ira, e no seu furor os confundirá, dizendo:");
    b->dados[SALMOS].capitulos[2].versos[6] = _("Eu tenho estabelecido o meu Rei sobre Sião, meu santo monte.");
    b->dados[SALMOS].capitulos[2].versos[7] = _("Falarei do decreto do Senhor; ele me disse: Tu és meu Filho, hoje te gerei.");
    b->dados[SALMOS].capitulos[2].versos[8] = _("Pede-me, e eu te darei as nações por herança, e as extremidades da terra por possessão.");
    b->dados[SALMOS].capitulos[2].versos[9] = _("Tu os quebrarás com uma vara de ferro; tu os despedaçarás como a um vaso de oleiro.");
    b->dados[SALMOS].capitulos[2].versos[10] = _("Agora, pois, ó reis, sede prudentes; deixai-vos instruir, juízes da terra.");
    b->dados[SALMOS].capitulos[2].versos[11] = _("Servi ao Senhor com temor, e regozijai-vos com tremor.");
    b->dados[SALMOS].capitulos[2].versos[12] = _("Beijai o Filho, para que não se ire, e pereçais no caminho; porque em breve se inflamará a sua ira. Bem-aventurados todos aqueles que nele confiam.");

    b->dados[SALMOS].capitulos[3].versos[1] = _("Senhor, como se têm multiplicado os meus adversários! Muitos se levantam contra mim.");
    b->dados[SALMOS].capitulos[3].versos[2] = _("Muitos são os que dizem de mim: Não há socorro para ele em Deus.");
    b->dados[SALMOS].capitulos[3].versos[3] = _("Mas tu, Senhor, és um escudo ao redor de mim, a minha glória, e aquele que exulta a minha cabeça.");
    b->dados[SALMOS].capitulos[3].versos[4] = _("Com a minha voz clamo ao Senhor, e ele do seu santo monte me responde.");
    b->dados[SALMOS].capitulos[3].versos[5] = _("Eu me deito e durmo; acordo, pois o Senhor me sustenta.");
    b->dados[SALMOS].capitulos[3].versos[6] = _("Não tenho medo dos dez milhares de pessoas que se puseram contra mim ao meu redor.");
    b->dados[SALMOS].capitulos[3].versos[7] = _("Levanta-te, Senhor! salva-me, Deus meu! pois tu feres no queixo todos os meus inimigos; quebras os dentes aos ímpios.");
    b->dados[SALMOS].capitulos[3].versos[8] = _("A salvação vem do Senhor; sobre o teu povo seja a tua bênção.");

    b->dados[SALMOS].capitulos[4].versos[1] = _("Responde-me quando eu clamar, ó Deus da minha justiça! Na angústia me deste largueza; tem misericórdia de mim e ouve a minha oração.");
    b->dados[SALMOS].capitulos[4].versos[2] = _("Filhos dos homens, até quando convertereis a minha glória em infâmia? Até quando amareis a vaidade e buscareis a mentira?");
    b->dados[SALMOS].capitulos[4].versos[3] = _("Sabei que o Senhor separou para si aquele que é piedoso; o Senhor me ouve quando eu clamo a ele.");
    b->dados[SALMOS].capitulos[4].versos[4] = _("Irai-vos e não pequeis; consultai com o vosso coração em vosso leito, e calai-vos.");
    b->dados[SALMOS].capitulos[4].versos[5] = _("Oferecei sacrifícios de justiça, e confiai no Senhor.");
    b->dados[SALMOS].capitulos[4].versos[6] = _("Muitos dizem: Quem nos mostrará o bem? Levanta, Senhor, sobre nós a luz do teu rosto.");
    b->dados[SALMOS].capitulos[4].versos[7] = _("Puseste no meu coração mais alegria do que a deles no tempo em que se lhes multiplicam o trigo e o vinho.");
    b->dados[SALMOS].capitulos[4].versos[8] = _("Em paz me deitarei e dormirei, porque só tu, Senhor, me fazes habitar em segurança.");

    b->dados[SALMOS].capitulos[5].versos[1] = _("Dá ouvidos às minhas palavras, ó Senhor; atende aos meus gemidos.");
    b->dados[SALMOS].capitulos[5].versos[2] = _("Atende à voz do meu clamor, Rei meu e Deus meu, pois é a ti que oro.");
    b->dados[SALMOS].capitulos[5].versos[3] = _("Pela manhã ouves a minha voz, ó Senhor; pela manhã te apresento a minha oração, e vigio.");
    b->dados[SALMOS].capitulos[5].versos[4] = _("Porque tu não és um Deus que tenha prazer na iniqüidade, nem contigo habitará o mal.");
    b->dados[SALMOS].capitulos[5].versos[5] = _("Os arrogantes não subsistirão diante dos teus olhos; detestas a todos os que praticam a maldade.");
    b->dados[SALMOS].capitulos[5].versos[6] = _("Destróis aqueles que proferem a mentira; ao sanguinário e ao fraudulento o Senhor abomina.");
    b->dados[SALMOS].capitulos[5].versos[7] = _("Mas eu, pela grandeza da tua benignidade, entrarei em tua casa; e em teu temor me inclinarei para o teu santo templo.");
    b->dados[SALMOS].capitulos[5].versos[8] = _("Guia-me, Senhor, na tua justiça, por causa dos meus inimigos; aplana diante de mim o teu caminho.");
    b->dados[SALMOS].capitulos[5].versos[9] = _("Porque não há fidelidade na boca deles; as suas entranhas são verdadeiras maldades, a sua garganta é um sepulcro aberto; lisonjeiam com a sua língua.");
    b->dados[SALMOS].capitulos[5].versos[10] = _("Declara-os culpados, ó Deus; que caiam por seus próprios conselhos; lança-os fora por causa da multidão de suas transgressões, pois se revoltaram contra ti.");
    b->dados[SALMOS].capitulos[5].versos[11] = _("Mas alegrem-se todos os que confiam em ti; exultem eternamente, porquanto tu os defendes; sim, gloriem-se em ti os que amam o teu nome.");
    b->dados[SALMOS].capitulos[5].versos[12] = _("Pois tu, Senhor, abençoas o justo; tu o circundas do teu favor como de um escudo.");

    b->dados[SALMOS].capitulos[6].versos[1] = _("Senhor, não me repreendas na tua ira, nem me castigues no teu furor.");
    b->dados[SALMOS].capitulos[6].versos[2] = _("Tem compaixão de mim, Senhor, porque sou fraco; sara-me, Senhor, porque os meus ossos estão perturbados.");
    b->dados[SALMOS].capitulos[6].versos[3] = _("Também a minha alma está muito perturbada; mas tu, Senhor, até quando?...");
    b->dados[SALMOS].capitulos[6].versos[4] = _("Volta-te, Senhor, livra a minha alma; salva-me por tua misericórdia.");
    b->dados[SALMOS].capitulos[6].versos[5] = _("Pois na morte não há lembrança de ti; no Seol quem te louvará?");
    b->dados[SALMOS].capitulos[6].versos[6] = _("Estou cansado do meu gemido; toda noite faço nadar em lágrimas a minha cama, inundo com elas o meu leito.");
    b->dados[SALMOS].capitulos[6].versos[7] = _("Os meus olhos estão consumidos pela mágoa, e enfraquecem por causa de todos os meus inimigos.");
    b->dados[SALMOS].capitulos[6].versos[8] = _("Apartai-vos de mim todos os que praticais a iniquidade; porque o Senhor já ouviu a voz do meu pranto.");
    b->dados[SALMOS].capitulos[6].versos[9] = _("O Senhor já ouviu a minha súplica, o Senhor aceita a minha oração.");
    b->dados[SALMOS].capitulos[6].versos[10] = _("Serão envergonhados e grandemente perturbados todos os meus inimigos; tornarão atrás e subitamente serão envergonhados.");

    b->dados[SALMOS].capitulos[7].versos[1] = _("Senhor, Deus meu, confio, salva-me de todo o que me persegue, e livra-me;");
    b->dados[SALMOS].capitulos[7].versos[2] = _("para que ele não me arrebate, qual leão, despedaçando-me, sem que haja quem acuda.");
    b->dados[SALMOS].capitulos[7].versos[3] = _("Senhor, Deus meu, se eu fiz isto, se há perversidade nas minhas mãos,");
    b->dados[SALMOS].capitulos[7].versos[4] = _("se paguei com o mal àquele que tinha paz comigo, ou se despojei o meu inimigo sem causa.");
    b->dados[SALMOS].capitulos[7].versos[5] = _("persiga-me o inimigo e alcance-me; calque aos pés a minha vida no chão, e deite no pó a minha glória.");
    b->dados[SALMOS].capitulos[7].versos[6] = _("Ergue-te, Senhor, na tua ira; levanta-te contra o furor dos meus inimigos; desperta-te, meu Deus, pois tens ordenado o juízo.");
    b->dados[SALMOS].capitulos[7].versos[7] = _("Reúna-se ao redor de ti a assembléia dos povos, e por cima dela remonta-te ao alto.");
    b->dados[SALMOS].capitulos[7].versos[8] = _("O Senhor julga os povos; julga-me, Senhor, de acordo com a minha justiça e conforme a integridade que há em mim.");
    b->dados[SALMOS].capitulos[7].versos[9] = _("Cesse a maldade dos ímpios, mas estabeleça-se o justo; pois tu, ó justo Deus, provas o coração e os rins.");
    b->dados[SALMOS].capitulos[7].versos[10] = _("O meu escudo está em Deus, que salva os retos de coração.");
    b->dados[SALMOS].capitulos[7].versos[11] = _("Deus é um juiz justo, um Deus que sente indignação todos os dias.");
    b->dados[SALMOS].capitulos[7].versos[12] = _("Se o homem não se arrepender, Deus afiará a sua espada; armado e teso está o seu arco;");
    b->dados[SALMOS].capitulos[7].versos[13] = _("já preparou armas mortíferas, fazendo suas setas inflamadas.");
    b->dados[SALMOS].capitulos[7].versos[14] = _("Eis que o mau está com dores de perversidade; concedeu a malvadez, e dará à luz a falsidade.");
    b->dados[SALMOS].capitulos[7].versos[15] = _("Abre uma cova, aprofundando-a, e cai na cova que fez.");
    b->dados[SALMOS].capitulos[7].versos[16] = _("A sua malvadez recairá sobre a sua cabeça, e a sua violência descerá sobre o seu crânio.");
    b->dados[SALMOS].capitulos[7].versos[17] = _("Eu louvarei ao Senhor segundo a sua justiça, e cantarei louvores ao nome do Senhor, o Altíssimo.");

    b->dados[SALMOS].capitulos[8].versos[1] = _("Ó Senhor, Senhor nosso, quão admirável é o teu nome em toda a terra, tu que puseste a tua glória dos céus!");
    b->dados[SALMOS].capitulos[8].versos[2] = _("Da boca das crianças e dos que mamam tu suscitaste força, por causa dos teus adversários para fazeres calar o inimigo e vingador.");
    b->dados[SALMOS].capitulos[8].versos[3] = _("Quando contemplo os teus céus, obra dos teus dedos, a lua e as estrelas que estabeleceste,");
    b->dados[SALMOS].capitulos[8].versos[4] = _("que é o homem, para que te lembres dele? e o filho do homem, para que o visites?");
    b->dados[SALMOS].capitulos[8].versos[5] = _("Contudo, pouco abaixo de Deus o fizeste; de glória e de honra o coroaste.");
    b->dados[SALMOS].capitulos[8].versos[6] = _("Deste-lhe domínio sobre as obras das tuas mãos; tudo puseste debaixo de seus pés:");
    b->dados[SALMOS].capitulos[8].versos[7] = _("todas as ovelhas e bois, assim como os animais do campo,");
    b->dados[SALMOS].capitulos[8].versos[8] = _("as aves do céu, e os peixes do mar, tudo o que passa pelas veredas dos mares.");
    b->dados[SALMOS].capitulos[8].versos[9] = _("Ó Senhor, Senhor nosso, quão admirável é o teu nome em toda a terra!");

    b->dados[SALMOS].capitulos[9].versos[1] = _("Eu te louvarei, Senhor, de todo o meu coração; contarei todas as tuas maravilhas.");
    b->dados[SALMOS].capitulos[9].versos[2] = _("Em ti me alegrarei e exultarei; cantarei louvores ao teu nome, ó Altíssimo;");
    b->dados[SALMOS].capitulos[9].versos[3] = _("porquanto os meus inimigos retrocedem, caem e perecem diante de ti.");
    b->dados[SALMOS].capitulos[9].versos[4] = _("Sustentaste o meu direito e a minha causa; tu te assentaste no tribunal, julgando justamente.");
    b->dados[SALMOS].capitulos[9].versos[5] = _("Repreendeste as nações, destruíste os ímpios; apagaste o seu nome para sempre e eternamente.");
    b->dados[SALMOS].capitulos[9].versos[6] = _("Os inimigos consumidos estão; perpétuas são as suas ruínas.");
    b->dados[SALMOS].capitulos[9].versos[7] = _("Mas o Senhor está entronizado para sempre; preparou o seu trono para exercer o juízo.");
    b->dados[SALMOS].capitulos[9].versos[8] = _("Ele mesmo julga o mundo com justiça; julga os povos com eqüidade.");
    b->dados[SALMOS].capitulos[9].versos[9] = _("O Senhor é também um alto refúgio para o oprimido, um alto refúgio em tempos de angústia.");
    b->dados[SALMOS].capitulos[9].versos[10] = _("Em ti confiam os que conhecem o teu nome; porque tu, Senhor, não abandonas aqueles que te buscam.");
    b->dados[SALMOS].capitulos[9].versos[11] = _("Cantai louvores ao Senhor, que habita em Sião; anunciai entre os povos os seus feitos.");
    b->dados[SALMOS].capitulos[9].versos[12] = _("Pois ele, o vingador do sangue, se lembra deles; não se esquece do clamor dos aflitos.");
    b->dados[SALMOS].capitulos[9].versos[13] = _("Tem misericórdia de mim, Senhor; olha a aflição que sofro daqueles que me odeiam, tu que me levantas das portas da morte.");
    b->dados[SALMOS].capitulos[9].versos[14] = _("para que eu conte todos os teus louvores nas portas da filha de Sião e me alegre na tua salvação.");
    b->dados[SALMOS].capitulos[9].versos[15] = _("Afundaram-se as nações na cova que abriram; na rede que ocultaram ficou preso o seu pé.");
    b->dados[SALMOS].capitulos[9].versos[16] = _("O Senhor deu-se a conhecer, executou o juízo; enlaçado ficou o ímpio nos seus próprios feitos.");
    b->dados[SALMOS].capitulos[9].versos[17] = _("Os ímpios irão para o Seol, sim, todas as nações que se esquecem de Deus.");
    b->dados[SALMOS].capitulos[9].versos[18] = _("Pois o necessitado não será esquecido para sempre, nem a esperança dos pobres será frustrada perpetuamente.");
    b->dados[SALMOS].capitulos[9].versos[19] = _("Levanta-te, Senhor! Não prevaleça o homem; sejam julgadas as nações na tua presença!");
    b->dados[SALMOS].capitulos[9].versos[20] = _("Senhor, incute-lhes temor! Que as nações saibam que não passam de meros homens!");

    b->dados[SALMOS].capitulos[10].versos[1] = _("Por que te conservas ao longe, Senhor? Por que te escondes em tempos de angústia?");
    b->dados[SALMOS].capitulos[10].versos[2] = _("Os ímpios, na sua arrogância, perseguem furiosamente o pobre; sejam eles apanhados nas ciladas que maquinaram.");
    b->dados[SALMOS].capitulos[10].versos[3] = _("Pois o ímpio gloria-se do desejo do seu coração, e o que é dado à rapina despreza e maldiz o Senhor.");
    b->dados[SALMOS].capitulos[10].versos[4] = _("Por causa do seu orgulho, o ímpio não o busca; todos os seus pensamentos são: Não há Deus.");
    b->dados[SALMOS].capitulos[10].versos[5] = _("Os seus caminhos são sempre prósperos; os teus juízos estão acima dele, fora da sua vista; quanto a todos os seus adversários, ele os trata com desprezo.");
    b->dados[SALMOS].capitulos[10].versos[6] = _("Diz em seu coração: Não serei abalado; nunca me verei na adversidade.");
    b->dados[SALMOS].capitulos[10].versos[7] = _("A sua boca está cheia de imprecações, de enganos e de opressão; debaixo da sua língua há malícia e iniqüidade.");
    b->dados[SALMOS].capitulos[10].versos[8] = _("Põe-se de emboscada nas aldeias; nos lugares ocultos mata o inocente; os seus olhos estão de espreita ao desamparado.");
    b->dados[SALMOS].capitulos[10].versos[9] = _("Qual leão no seu covil, está ele de emboscada num lugar oculto; está de emboscada para apanhar o pobre; apanha-o, colhendo-o na sua rede.");
    b->dados[SALMOS].capitulos[10].versos[10] = _("Abaixa-se, curva-se; assim os desamparados lhe caem nas fortes garras.");
    b->dados[SALMOS].capitulos[10].versos[11] = _("Diz ele em seu coração: Deus se esqueceu; cobriu o seu rosto; nunca verá isto.");
    b->dados[SALMOS].capitulos[10].versos[12] = _("Levanta-te, Senhor; ó Deus, levanta a tua mão; não te esqueças dos necessitados.");
    b->dados[SALMOS].capitulos[10].versos[13] = _("Por que blasfema de Deus o ímpio, dizendo no seu coração: Tu não inquirirás?");
    b->dados[SALMOS].capitulos[10].versos[14] = _("Tu o viste, porque atentas para o trabalho e enfado, para o tomares na tua mão; a ti o desamparado se entrega; tu és o amparo do órfão.");
    b->dados[SALMOS].capitulos[10].versos[15] = _("Quebra tu o braço do ímpio e malvado; esquadrinha a sua maldade, até que a descubras de todo.");
    b->dados[SALMOS].capitulos[10].versos[16] = _("O Senhor é Rei sempre e eternamente; da sua terra perecerão as nações.");
    b->dados[SALMOS].capitulos[10].versos[17] = _("Tu, Senhor, ouvirás os desejos dos mansos; confortarás o seu coração; inclinarás o teu ouvido,");
    b->dados[SALMOS].capitulos[10].versos[18] = _("para fazeres justiça ao órfão e ao oprimido, a fim de que o homem, que é da terra, não mais inspire terror.");

    b->dados[SALMOS].capitulos[11].versos[1] = _("No Senhor confio. Como, pois, me dizeis: Foge para o monte, como um pássaro?");
    b->dados[SALMOS].capitulos[11].versos[2] = _("Pois eis que os ímpios armam o arco, põem a sua flecha na corda, para atirarem, às ocultas, aos retos de coração.");
    b->dados[SALMOS].capitulos[11].versos[3] = _("Quando os fundamentos são destruídos, que pode fazer o justo?");
    b->dados[SALMOS].capitulos[11].versos[4] = _("O Senhor está no seu santo templo, o trono do Senhor está nos céus; os seus olhos contemplam, as suas pálpebras provam os filhos dos homens.");
    b->dados[SALMOS].capitulos[11].versos[5] = _("O Senhor prova o justo e o ímpio; a sua alma odeia ao que ama a violência.");
    b->dados[SALMOS].capitulos[11].versos[6] = _("Sobre os ímpios fará chover brasas de fogo e enxofre; um vento abrasador será a porção do seu copo.");
    b->dados[SALMOS].capitulos[11].versos[7] = _("Porque o Senhor é justo; ele ama a justiça; os retos, pois, verão o seu rosto.");

    b->dados[SALMOS].capitulos[12].versos[1] = _("Salva-nos, Senhor, pois não existe mais o piedoso; os fiéis desapareceram dentre os filhos dos homens.");
    b->dados[SALMOS].capitulos[12].versos[2] = _("Cada um fala com falsidade ao seu próximo; falam com lábios lisonjeiros e coração dobre.");
    b->dados[SALMOS].capitulos[12].versos[3] = _("Corte o Senhor todos os lábios lisonjeiros e a língua que fala soberbamente,");
    b->dados[SALMOS].capitulos[12].versos[4] = _("os que dizem: Com a nossa língua prevaleceremos; os nossos lábios a nós nos pertencem; quem sobre nós é senhor?");
    b->dados[SALMOS].capitulos[12].versos[5] = _("Por causa da opressão dos pobres, e do gemido dos necessitados, levantar-me-ei agora, diz o Senhor; porei em segurança quem por ela suspira.");
    b->dados[SALMOS].capitulos[12].versos[6] = _("As palavras do Senhor são palavras puras, como prata refinada numa fornalha de barro, purificada sete vezes.");
    b->dados[SALMOS].capitulos[12].versos[7] = _("Guarda-nos, ó Senhor; desta geração defende-nos para sempre.");
    b->dados[SALMOS].capitulos[12].versos[8] = _("Os ímpios andam por toda parte, quando a vileza se exalta entre os filhos dos homens.");

    b->dados[SALMOS].capitulos[13].versos[1] = _("Até quando, ó Senhor, te esquecerás de mim? para sempre? Até quando esconderás de mim o teu rosto?");
    b->dados[SALMOS].capitulos[13].versos[2] = _("Até quando encherei de cuidados a minha alma, tendo tristeza no meu coração cada dia? Até quando o meu inimigo se exaltará sobre mim?");
    b->dados[SALMOS].capitulos[13].versos[3] = _("Considera e responde-me, ó Senhor, Deus meu; alumia os meus olhos para que eu não durma o sono da morte;");
    b->dados[SALMOS].capitulos[13].versos[4] = _("para que o meu inimigo não diga: Prevaleci contra ele; e os meus adversários não se alegrem, em sendo eu abalado.");
    b->dados[SALMOS].capitulos[13].versos[5] = _("Mas eu confio na tua benignidade; o meu coração se regozija na tua salvação.");
    b->dados[SALMOS].capitulos[13].versos[6] = _("Cantarei ao Senhor, porquanto me tem feito muito bem.");

    b->dados[SALMOS].capitulos[14].versos[1] = _("Diz o néscio no seu coração: Não há Deus. Os homens têm-se corrompido, fazem-se abomináveis em suas obras; não há quem faça o bem.");
    b->dados[SALMOS].capitulos[14].versos[2] = _("O Senhor olhou do céu para os filhos dos homens, para ver se havia algum que tivesse entendimento, que buscasse a Deus.");
    b->dados[SALMOS].capitulos[14].versos[3] = _("Desviaram-se todos e juntamente se fizeram imundos; não há quem faça o bem, não há sequer um.");
    b->dados[SALMOS].capitulos[14].versos[4] = _("Acaso não tem conhecimento nem sequer um dos que praticam a iniqüidade, que comem o meu povo como se comessem pão, e que não invocam o Senhor?");
    b->dados[SALMOS].capitulos[14].versos[5] = _("Achar-se-ão ali em grande pavor, porque Deus está na geração dos justos.");
    b->dados[SALMOS].capitulos[14].versos[6] = _("Vós quereis frustar o conselho dos pobres, mas o Senhor é o seu refúgio.");
    b->dados[SALMOS].capitulos[14].versos[7] = _("Oxalá que de Sião viesse a salvação de Israel! Quando o Senhor fizer voltar os cativos do seu povo, então se regozijará Jacó e se alegrará Israel.");

    b->dados[SALMOS].capitulos[15].versos[1] = _("Quem, Senhor, habitará na tua tenda? quem morará no teu santo monte?");
    b->dados[SALMOS].capitulos[15].versos[2] = _("Aquele que anda irrepreensivelmente e pratica a justiça, e do coração fala a verdade;");
    b->dados[SALMOS].capitulos[15].versos[3] = _("que não difama com a sua língua, nem faz o mal ao seu próximo, nem contra ele aceita nenhuma afronta;");
    b->dados[SALMOS].capitulos[15].versos[4] = _("aquele a cujos olhos o réprobo é desprezado, mas que honra os que temem ao Senhor; aquele que, embora jure com dano seu, não muda;");
    b->dados[SALMOS].capitulos[15].versos[5] = _("que não empresta o seu dinheiro a juros, nem recebe peitas contra o inocente. Aquele que assim procede nunca será abalado.");

    b->dados[SALMOS].capitulos[16].versos[1] = _("Guarda-me, ó Deus, porque em ti me refugio.");
    b->dados[SALMOS].capitulos[16].versos[2] = _("Digo ao Senhor: Tu és o meu Senhor; além de ti não tenho outro bem.");
    b->dados[SALMOS].capitulos[16].versos[3] = _("Quanto aos santos que estão na terra, eles são os ilustres nos quais está todo o meu prazer.");
    b->dados[SALMOS].capitulos[16].versos[4] = _("Aqueles que escolhem a outros deuses terão as suas dores multiplicadas; eu não oferecerei as suas libações de sangue, nem tomarei os seus nomes nos meus lábios.");
    b->dados[SALMOS].capitulos[16].versos[5] = _("Tu, Senhor, és a porção da minha herança e do meu cálice; tu és o sustentáculo do meu quinhão.");
    b->dados[SALMOS].capitulos[16].versos[6] = _("As sortes me caíram em lugares deliciosos; sim, coube-me uma formosa herança.");
    b->dados[SALMOS].capitulos[16].versos[7] = _("Bendigo ao Senhor que me aconselha; até os meus rins me ensinam de noite.");
    b->dados[SALMOS].capitulos[16].versos[8] = _("Tenho posto o Senhor continuamente diante de mim; porquanto ele está à minha mão direita, não serei abalado.");
    b->dados[SALMOS].capitulos[16].versos[9] = _("Porquanto está alegre o meu coração e se regozija a minha alma; também a minha carne habitará em segurança.");
    b->dados[SALMOS].capitulos[16].versos[10] = _("Pois não deixarás a minha alma no Seol, nem permitirás que o teu Santo veja corrupção.");
    b->dados[SALMOS].capitulos[16].versos[11] = _("Tu me farás conhecer a vereda da vida; na tua presença há plenitude de alegria; à tua mão direita há delícias perpetuamente.");

    b->dados[SALMOS].capitulos[17].versos[1] = _("Ouve, Senhor, a justa causa; atende ao meu clamor; dá ouvidos à minha oração, que não procede de lábios enganosos.");
    b->dados[SALMOS].capitulos[17].versos[2] = _("Venha de ti a minha sentença; atendam os teus olhos à eqüidade.");
    b->dados[SALMOS].capitulos[17].versos[3] = _("Provas-me o coração, visitas-me de noite; examinas-me e não achas iniqüidade; a minha boca não transgride.");
    b->dados[SALMOS].capitulos[17].versos[4] = _("Quanto às obras dos homens, pela palavra dos teus lábios eu me tenho guardado dos caminhos do homem violento.");
    b->dados[SALMOS].capitulos[17].versos[5] = _("Os meus passos apegaram-se às tuas veredas, não resvalaram os meus pés.");
    b->dados[SALMOS].capitulos[17].versos[6] = _("A ti, ó Deus, eu clamo, pois tu me ouvirás; inclina para mim os teus ouvidos, e ouve as minhas palavras.");
    b->dados[SALMOS].capitulos[17].versos[7] = _("Faze maravilhosas as tuas beneficências, ó Salvador dos que à tua destra se refugiam daqueles que se levantam contra eles.");
    b->dados[SALMOS].capitulos[17].versos[8] = _("Guarda-me como à menina do olho; esconde-me, à sombra das tuas asas,");
    b->dados[SALMOS].capitulos[17].versos[9] = _("dos ímpios que me despojam, dos meus inimigos mortais que me cercam.");
    b->dados[SALMOS].capitulos[17].versos[10] = _("Eles fecham o seu coração; com a boca falam soberbamente.");
    b->dados[SALMOS].capitulos[17].versos[11] = _("Andam agora rodeando os meus passos; fixam em mim os seus olhos para me derrubarem por terra.");
    b->dados[SALMOS].capitulos[17].versos[12] = _("Parecem-se com o leão que deseja arrebatar a sua presa, e com o leãozinho que espreita em esconderijos.");
    b->dados[SALMOS].capitulos[17].versos[13] = _("Levanta-te, Senhor, detém-nos, derruba-os; livra-me dos ímpios, pela tua espada,");
    b->dados[SALMOS].capitulos[17].versos[14] = _("dos homens, pela tua mão, Senhor, dos homens do mundo, cujo quinhão está nesta vida. Enche-lhes o ventre da tua ira entesourada. Fartem-se dela os seus filhos, e dêem ainda os sobejos por herança aos seus pequeninos.");
    b->dados[SALMOS].capitulos[17].versos[15] = _("Quanto a mim, em retidão contemplarei a tua face; eu me satisfarei com a tua semelhança quando acordar.");

    b->dados[SALMOS].capitulos[18].versos[1] = _("Eu te amo, ó Senhor, força minha.");
    b->dados[SALMOS].capitulos[18].versos[2] = _("O Senhor é a minha rocha, a minha fortaleza e o meu libertador; o meu Deus, o meu rochedo, em quem me refúgio; o meu escudo, a força da minha salvação, e o meu alto refúgio.");
    b->dados[SALMOS].capitulos[18].versos[3] = _("Invoco o Senhor, que é digno de louvor, e sou salvo dos meus inimigos.");
    b->dados[SALMOS].capitulos[18].versos[4] = _("Cordas de morte me cercaram, e torrentes de perdição me amedrontaram.");
    b->dados[SALMOS].capitulos[18].versos[5] = _("Cordas de Seol me cingiram, laços de morte me surpreenderam.");
    b->dados[SALMOS].capitulos[18].versos[6] = _("Na minha angústia invoquei o Senhor, sim, clamei ao meu Deus; do seu templo ouviu ele a minha voz; o clamor que eu lhe fiz chegou aos seus ouvidos.");
    b->dados[SALMOS].capitulos[18].versos[7] = _("Então a terra se abalou e tremeu, e os fundamentos dos montes também se moveram e se abalaram, porquanto ele se indignou.");
    b->dados[SALMOS].capitulos[18].versos[8] = _("Das suas narinas subiu fumaça, e da sua boca saiu fogo devorador; dele saíram brasas ardentes.");
    b->dados[SALMOS].capitulos[18].versos[9] = _("Ele abaixou os céus e desceu; trevas espessas havia debaixo de seus pés.");
    b->dados[SALMOS].capitulos[18].versos[10] = _("Montou num querubim, e voou; sim, voou sobre as asas do vento.");
    b->dados[SALMOS].capitulos[18].versos[11] = _("Fez das trevas o seu retiro secreto; o pavilhão que o cercava era a escuridão das águas e as espessas nuvens do céu.");
    b->dados[SALMOS].capitulos[18].versos[12] = _("Do resplendor da sua presença saíram, pelas suas espessas nuvens, saraiva e brasas de fogo.");
    b->dados[SALMOS].capitulos[18].versos[13] = _("O Senhor trovejou a sua voz; e havia saraiva e brasas de fogo.");
    b->dados[SALMOS].capitulos[18].versos[14] = _("Despediu as suas setas, e os espalhou; multiplicou raios, e os perturbou.");
    b->dados[SALMOS].capitulos[18].versos[15] = _("Então foram vistos os leitos das águas, e foram descobertos os fundamentos do mundo, à tua repreensão, Senhor, ao sopro do vento das tuas narinas.");
    b->dados[SALMOS].capitulos[18].versos[16] = _("Do alto estendeu o braço e me tomou; tirou-me das muitas águas.");
    b->dados[SALMOS].capitulos[18].versos[17] = _("Livrou-me do meu inimigo forte e daqueles que me odiavam; pois eram mais poderosos do que eu.");
    b->dados[SALMOS].capitulos[18].versos[18] = _("Surpreenderam-me eles no dia da minha calamidade, mas o Senhor foi o meu amparo.");
    b->dados[SALMOS].capitulos[18].versos[19] = _("Trouxe-me para um lugar espaçoso; livrou-me, porque tinha prazer em mim.");
    b->dados[SALMOS].capitulos[18].versos[20] = _("Recompensou-me o Senhor conforme a minha justiça, retribuiu-me conforme a pureza das minhas mãos.");
    b->dados[SALMOS].capitulos[18].versos[21] = _("Pois tenho guardado os caminhos do Senhor, e não me apartei impiamente do meu Deus.");
    b->dados[SALMOS].capitulos[18].versos[22] = _("Porque todas as suas ordenanças estão diante de mim, e nunca afastei de mim os seus estatutos.");
    b->dados[SALMOS].capitulos[18].versos[23] = _("Também fui irrepreensível diante dele, e me guardei da iniqüidade.");
    b->dados[SALMOS].capitulos[18].versos[24] = _("Pelo que o Senhor me recompensou conforme a minha justiça, conforme a pureza de minhas mãos perante os seus olhos.");
    b->dados[SALMOS].capitulos[18].versos[25] = _("Para com o benigno te mostras benigno, e para com o homem perfeito te mostras perfeito.");
    b->dados[SALMOS].capitulos[18].versos[26] = _("Para com o puro te mostras puro, e para com o perverso te mostras contrário.");
    b->dados[SALMOS].capitulos[18].versos[27] = _("Porque tu livras o povo aflito, mas os olhos altivos tu os abates.");
    b->dados[SALMOS].capitulos[18].versos[28] = _("Sim, tu acendes a minha candeia; o Senhor meu Deus alumia as minhas trevas.");
    b->dados[SALMOS].capitulos[18].versos[29] = _("Com o teu auxílio dou numa tropa; com o meu Deus salto uma muralha.");
    b->dados[SALMOS].capitulos[18].versos[30] = _("Quanto a Deus, o seu caminho é perfeito; a promessa do Senhor é provada; ele é um escudo para todos os que nele confiam.");
    b->dados[SALMOS].capitulos[18].versos[31] = _("Pois, quem é Deus senão o Senhor? e quem é rochedo senão o nosso Deus?");
    b->dados[SALMOS].capitulos[18].versos[32] = _("Ele é o Deus que me cinge de força e torna perfeito o meu caminho;");
    b->dados[SALMOS].capitulos[18].versos[33] = _("faz os meus pés como os das corças, e me coloca em segurança nos meus lugares altos.");
    b->dados[SALMOS].capitulos[18].versos[34] = _("Adestra as minhas mãos para a peleja, de sorte que os meus braços vergam um arco de bronze.");
    b->dados[SALMOS].capitulos[18].versos[35] = _("Também me deste o escudo da tua salvação; a tua mão direita me sustém, e a tua clemência me engrandece.");
    b->dados[SALMOS].capitulos[18].versos[36] = _("Alargas o caminho diante de mim, e os meus pés não resvalam.");
    b->dados[SALMOS].capitulos[18].versos[37] = _("Persigo os meus inimigos, e os alcanço; não volto senão depois de os ter consumido.");
    b->dados[SALMOS].capitulos[18].versos[38] = _("Atravesso-os, de modo que nunca mais se podem levantar; caem debaixo dos meus pés.");
    b->dados[SALMOS].capitulos[18].versos[39] = _("Pois me cinges de força para a peleja; prostras debaixo de mim aqueles que contra mim se levantam.");
    b->dados[SALMOS].capitulos[18].versos[40] = _("Fazes também que os meus inimigos me dêem as costas; aos que me odeiam eu os destruo.");
    b->dados[SALMOS].capitulos[18].versos[41] = _("Clamam, porém não há libertador; clamam ao Senhor, mas ele não lhes responde.");
    b->dados[SALMOS].capitulos[18].versos[42] = _("Então os esmiuço como o pó diante do vento; lanço-os fora como a lama das ruas.");
    b->dados[SALMOS].capitulos[18].versos[43] = _("Livras-me das contendas do povo, e me fazes cabeça das nações; um povo que eu não conhecia se me sujeita.");
    b->dados[SALMOS].capitulos[18].versos[44] = _("Ao ouvirem de mim, logo me obedecem; com lisonja os estrangeiros se me submetem.");
    b->dados[SALMOS].capitulos[18].versos[45] = _("Os estrangeiros desfalecem e, tremendo, saem dos seus esconderijos.");
    b->dados[SALMOS].capitulos[18].versos[46] = _("Vive o Senhor; bendita seja a minha rocha, e exaltado seja o Deus da minha salvação,");
    b->dados[SALMOS].capitulos[18].versos[47] = _("o Deus que me dá vingança, e sujeita os povos debaixo de mim,");
    b->dados[SALMOS].capitulos[18].versos[48] = _("que me livra de meus inimigos; sim, tu me exaltas sobre os que se levantam contra mim; tu me livras do homem violento.");
    b->dados[SALMOS].capitulos[18].versos[49] = _("Pelo que, ó Senhor, te louvarei entre as nações, e entoarei louvores ao teu nome.");
    b->dados[SALMOS].capitulos[18].versos[50] = _("Ele dá grande livramento ao seu rei, e usa de benignidade para com o seu ungido, para com Davi e sua posteridade, para sempre.");

    b->dados[SALMOS].capitulos[19].versos[1] = _("Os céus proclamam a glória de Deus e o firmamento anuncia a obra das suas mãos.");
    b->dados[SALMOS].capitulos[19].versos[2] = _("Um dia faz declaração a outro dia, e uma noite revela conhecimento a outra noite.");
    b->dados[SALMOS].capitulos[19].versos[3] = _("Não há fala, nem palavras; não se lhes ouve a voz.");
    b->dados[SALMOS].capitulos[19].versos[4] = _("Por toda a terra estende-se a sua linha, e as suas palavras até os consfins do mundo. Neles pôs uma tenda para o sol,");
    b->dados[SALMOS].capitulos[19].versos[5] = _("que é qual noivo que sai do seu tálamo, e se alegra, como um herói, a correr a sua carreira.");
    b->dados[SALMOS].capitulos[19].versos[6] = _("A sua saída é desde uma extremidade dos céus, e o seu curso até a outra extremidade deles; e nada se esconde ao seu calor.");
    b->dados[SALMOS].capitulos[19].versos[7] = _("A lei do Senhor é perfeita, e refrigera a alma; o testemunho do Senhor é fiel, e dá sabedoria aos simples.");
    b->dados[SALMOS].capitulos[19].versos[8] = _("Os preceitos do Senhor são retos, e alegram o coração; o mandamento do Senhor é puro, e alumia os olhos.");
    b->dados[SALMOS].capitulos[19].versos[9] = _("O temor do Senhor é limpo, e permanece para sempre; os juízos do Senhor são verdadeiros e inteiramente justos.");
    b->dados[SALMOS].capitulos[19].versos[10] = _("Mais desejáveis são do que o ouro, sim, do que muito ouro fino; e mais doces do que o mel e o que goteja dos favos.");
    b->dados[SALMOS].capitulos[19].versos[11] = _("Também por eles o teu servo é advertido; e em os guardar há grande recompensa.");
    b->dados[SALMOS].capitulos[19].versos[12] = _("Quem pode discernir os próprios erros? Purifica-me tu dos que me são ocultos.");
    b->dados[SALMOS].capitulos[19].versos[13] = _("Também de pecados de presunção guarda o teu servo, para que não se assenhoreiem de mim; então serei perfeito, e ficarei limpo de grande transgressão.");
    b->dados[SALMOS].capitulos[19].versos[14] = _("Sejam agradáveis as palavras da minha boca e a meditação do meu coração perante a tua face, Senhor, Rocha minha e Redentor meu!");

    b->dados[SALMOS].capitulos[20].versos[1] = _("O Senhor te ouça no dia da angústia; o nome do Deus de Jacó te proteja.");
    b->dados[SALMOS].capitulos[20].versos[2] = _("Envie-te socorro do seu santuário, e te sustenha de Sião.");
    b->dados[SALMOS].capitulos[20].versos[3] = _("Lembre-se de todas as tuas ofertas, e aceite os teus holocaustos.");
    b->dados[SALMOS].capitulos[20].versos[4] = _("Conceda-te conforme o desejo do teu coração, e cumpra todo o teu desígnio.");
    b->dados[SALMOS].capitulos[20].versos[5] = _("Nós nos alegraremos pela tua salvação, e em nome do nosso Deus arvoraremos pendões; satisfaça o Senhor todas as tuas petições.");
    b->dados[SALMOS].capitulos[20].versos[6] = _("Agora sei que o Senhor salva o seu ungido; ele lhe responderá lá do seu santo céu, com a força salvadora da sua destra.");
    b->dados[SALMOS].capitulos[20].versos[7] = _("Uns confiam em carros e outros em cavalos, mas nós faremos menção do nome do Senhor nosso Deus.");
    b->dados[SALMOS].capitulos[20].versos[8] = _("Uns encurvam-se e caem, mas nós nos erguemos e ficamos de pé.");
    b->dados[SALMOS].capitulos[20].versos[9] = _("Salva-nos, Senhor; ouça-nos o Rei quando clamarmos.");

    b->dados[SALMOS].capitulos[21].versos[1] = _("Na tua força, ó Senhor, o rei se alegra; e na tua salvação quão grandemente se regozija!");
    b->dados[SALMOS].capitulos[21].versos[2] = _("Concedeste-lhe o desejo do seu coração, e não lhe negaste a petição dos seus lábios.");
    b->dados[SALMOS].capitulos[21].versos[3] = _("Pois o proveste de bênçãos excelentes; puseste-lhe na cabeça uma coroa de ouro fino.");
    b->dados[SALMOS].capitulos[21].versos[4] = _("Vida te pediu, e lha deste, longura de dias para sempre e eternamente.");
    b->dados[SALMOS].capitulos[21].versos[5] = _("Grande é a sua glória pelo teu socorro; de honra e de majestade o revestes.");
    b->dados[SALMOS].capitulos[21].versos[6] = _("Sim, tu o fazes para sempre abençoado; tu o enches de gozo na tua presença.");
    b->dados[SALMOS].capitulos[21].versos[7] = _("Pois o rei confia no Senhor; e pela bondade do Altíssimo permanecerá inabalável.");
    b->dados[SALMOS].capitulos[21].versos[8] = _("A tua mão alcançará todos os teus inimigos, a tua destra alcançará todos os que te odeiam.");
    b->dados[SALMOS].capitulos[21].versos[9] = _("Tu os farás qual fornalha ardente quando vieres; o Senhor os consumirá na sua indignação, e o fogo os devorará.");
    b->dados[SALMOS].capitulos[21].versos[10] = _("A sua prole destruirás da terra, e a sua descendência dentre os filhos dos homens.");
    b->dados[SALMOS].capitulos[21].versos[11] = _("Pois intentaram o mal contra ti; maquinaram um ardil, mas não prevalecerão.");
    b->dados[SALMOS].capitulos[21].versos[12] = _("Porque tu os porás em fuga; contra os seus rostos assestarás o teu arco.");
    b->dados[SALMOS].capitulos[21].versos[13] = _("Exalta-te, Senhor, na tua força; então cantaremos e louvaremos o teu poder.");

    b->dados[SALMOS].capitulos[22].versos[1] = _("Deus meu, Deus meu, por que me desamparaste? por que estás afastado de me auxiliar, e das palavras do meu bramido?");
    b->dados[SALMOS].capitulos[22].versos[2] = _("Deus meu, eu clamo de dia, porém tu não me ouves; também de noite, mas não acho sossego.");
    b->dados[SALMOS].capitulos[22].versos[3] = _("Contudo tu és santo, entronizado sobre os louvores de Israel.");
    b->dados[SALMOS].capitulos[22].versos[4] = _("Em ti confiaram nossos pais; confiaram, e tu os livraste.");
    b->dados[SALMOS].capitulos[22].versos[5] = _("A ti clamaram, e foram salvos; em ti confiaram, e não foram confundidos.");
    b->dados[SALMOS].capitulos[22].versos[6] = _("Mas eu sou verme, e não homem; opróbrio dos homens e desprezado do povo.");
    b->dados[SALMOS].capitulos[22].versos[7] = _("Todos os que me vêem zombam de mim, arreganham os beiços e meneiam a cabeça, dizendo:");
    b->dados[SALMOS].capitulos[22].versos[8] = _("Confiou no Senhor; que ele o livre; que ele o salve, pois que nele tem prazer.");
    b->dados[SALMOS].capitulos[22].versos[9] = _("Mas tu és o que me tiraste da madre; o que me preservaste, estando eu ainda aos seios de minha mãe.");
    b->dados[SALMOS].capitulos[22].versos[10] = _("Nos teus braços fui lançado desde a madre; tu és o meu Deus desde o ventre de minha mãe.");
    b->dados[SALMOS].capitulos[22].versos[11] = _("Não te alongues de mim, pois a angústia está perto, e não há quem acuda.");
    b->dados[SALMOS].capitulos[22].versos[12] = _("Muitos touros me cercam; fortes touros de Basã me rodeiam.");
    b->dados[SALMOS].capitulos[22].versos[13] = _("Abrem contra mim sua boca, como um leão que despedaça e que ruge.");
    b->dados[SALMOS].capitulos[22].versos[14] = _("Como água me derramei, e todos os meus ossos se desconjuntaram; o meu coração é como cera, derreteu-se no meio das minhas entranhas.");
    b->dados[SALMOS].capitulos[22].versos[15] = _("A minha força secou-se como um caco e a língua se me pega ao paladar; tu me puseste no pó da morte.");
    b->dados[SALMOS].capitulos[22].versos[16] = _("Pois cães me rodeiam; um ajuntamento de malfeitores me cerca; transpassaram-me as mãos e os pés.");
    b->dados[SALMOS].capitulos[22].versos[17] = _("Posso contar todos os meus ossos. Eles me olham e ficam a mirar-me.");
    b->dados[SALMOS].capitulos[22].versos[18] = _("Repartem entre si as minhas vestes, e sobre a minha túnica lançam sortes.");
    b->dados[SALMOS].capitulos[22].versos[19] = _("Mas tu, Senhor, não te alongues de mim; força minha, apressa-te em socorrer-me.");
    b->dados[SALMOS].capitulos[22].versos[20] = _("Livra-me da espada, e a minha vida do poder do cão.");
    b->dados[SALMOS].capitulos[22].versos[21] = _("Salva-me da boca do leão, sim, livra-me dos chifres do boi selvagem.");
    b->dados[SALMOS].capitulos[22].versos[22] = _("Então anunciarei o teu nome aos meus irmãos; louvar-te-ei no meio da congregação.");
    b->dados[SALMOS].capitulos[22].versos[23] = _("Vós, que temeis ao Senhor, louvai-o; todos vós, filhos de Jacó, glorificai-o; temei-o todos vós, descendência de Israel.");
    b->dados[SALMOS].capitulos[22].versos[24] = _("Porque não desprezou nem abominou a aflição do aflito, nem dele escondeu o seu rosto; antes, quando ele clamou, o ouviu.");
    b->dados[SALMOS].capitulos[22].versos[25] = _("De ti vem o meu louvor na grande congregação; pagarei os meus votos perante os que o temem.");
    b->dados[SALMOS].capitulos[22].versos[26] = _("Os mansos comerão e se fartarão; louvarão ao Senhor os que o buscam. Que o vosso coração viva eternamente!");
    b->dados[SALMOS].capitulos[22].versos[27] = _("Todos os limites da terra se lembrarão e se converterão ao Senhor, e diante dele adorarão todas as famílias das nações.");
    b->dados[SALMOS].capitulos[22].versos[28] = _("Porque o domínio é do Senhor, e ele reina sobre as nações.");
    b->dados[SALMOS].capitulos[22].versos[29] = _("Todos os grandes da terra comerão e adorarão, e todos os que descem ao pó se prostrarão perante ele, os que não podem reter a sua vida.");
    b->dados[SALMOS].capitulos[22].versos[30] = _("A posteridade o servirá; falar-se-á do Senhor à geração vindoura.");
    b->dados[SALMOS].capitulos[22].versos[31] = _("Chegarão e anunciarão a justiça dele; a um povo que há de nascer contarão o que ele fez.");

    b->dados[SALMOS].capitulos[23].versos[1] = _("O Senhor é o meu pastor; nada me faltará.");
    b->dados[SALMOS].capitulos[23].versos[2] = _("Deitar-me faz em pastos verdejantes; guia-me mansamente a águas tranqüilas.");
    b->dados[SALMOS].capitulos[23].versos[3] = _("Refrigera a minha alma; guia-me nas veredas da justiça por amor do seu nome.");
    b->dados[SALMOS].capitulos[23].versos[4] = _("Ainda que eu ande pelo vale da sombra da morte, não temerei mal algum, porque tu estás comigo; a tua vara e o teu cajado me consolam.");
    b->dados[SALMOS].capitulos[23].versos[5] = _("Preparas uma mesa perante mim na presença dos meus inimigos; unges com óleo a minha cabeça, o meu cálice transborda.");
    b->dados[SALMOS].capitulos[23].versos[6] = _("Certamente que a bondade e a misericórdia me seguirão todos os dias da minha vida, e habitarei na casa do Senhor por longos dias.");

    b->dados[SALMOS].capitulos[24].versos[1] = _("Do Senhor é a terra e a sua plenitude; o mundo e aqueles que nele habitam.");
    b->dados[SALMOS].capitulos[24].versos[2] = _("Porque ele a fundou sobre os mares, e a firmou sobre os rios.");
    b->dados[SALMOS].capitulos[24].versos[3] = _("Quem subirá ao monte do Senhor, ou quem estará no seu lugar santo?");
    b->dados[SALMOS].capitulos[24].versos[4] = _("Aquele que é limpo de mãos e puro de coração; que não entrega a sua alma à vaidade, nem jura enganosamente.");
    b->dados[SALMOS].capitulos[24].versos[5] = _("Este receberá do Senhor uma bênção, e a justiça do Deus da sua salvação.");
    b->dados[SALMOS].capitulos[24].versos[6] = _("Tal é a geração daqueles que o buscam, daqueles que buscam a tua face, ó Deus de Jacó.");
    b->dados[SALMOS].capitulos[24].versos[7] = _("Levantai, ó portas, as vossas cabeças; levantai-vos, ó entradas eternas, e entrará o Rei da Glória.");
    b->dados[SALMOS].capitulos[24].versos[8] = _("Quem é o Rei da Glória? O Senhor forte e poderoso, o Senhor poderoso na batalha.");
    b->dados[SALMOS].capitulos[24].versos[9] = _("Levantai, ó portas, as vossas cabeças; levantai-vos, ó entradas eternas, e entrará o Rei da Glória.");
    b->dados[SALMOS].capitulos[24].versos[10] = _("Quem é esse Rei da Glória? O Senhor dos exércitos; ele é o Rei da Glória.");

    b->dados[SALMOS].capitulos[25].versos[1] = _("A ti, Senhor, elevo a minha alma.");
    b->dados[SALMOS].capitulos[25].versos[2] = _("Deus meu, em ti confio; não seja eu envergonhado; não triunfem sobre mim os meus inimigos.");
    b->dados[SALMOS].capitulos[25].versos[3] = _("Não seja envergonhado nenhum dos que em ti esperam; envergonhados sejam os que sem causa procedem traiçoeiramente.");
    b->dados[SALMOS].capitulos[25].versos[4] = _("Faze-me saber os teus caminhos, Senhor; ensina-me as tuas veredas.");
    b->dados[SALMOS].capitulos[25].versos[5] = _("Guia-me na tua verdade, e ensina-me; pois tu és o Deus da minha salvação; por ti espero o dia todo.");
    b->dados[SALMOS].capitulos[25].versos[6] = _("Lembra-te, Senhor, da tua compaixão e da tua benignidade, porque elas são eternas.");
    b->dados[SALMOS].capitulos[25].versos[7] = _("Não te lembres dos pecado da minha mocidade, nem das minhas transgressões; mas, segundo a tua misericórdia, lembra-te de mim, pela tua bondade, ó Senhor.");
    b->dados[SALMOS].capitulos[25].versos[8] = _("Bom e reto é o Senhor; pelo que ensina o caminho aos pecadores.");
    b->dados[SALMOS].capitulos[25].versos[9] = _("Guia os mansos no que é reto, e lhes ensina o seu caminho.");
    b->dados[SALMOS].capitulos[25].versos[10] = _("Todas as veredas do Senhor são misericórdia e verdade para aqueles que guardam o seu pacto e os seus testemunhos.");
    b->dados[SALMOS].capitulos[25].versos[11] = _("Por amor do teu nome, Senhor, perdoa a minha iniqüidade, pois é grande.");
    b->dados[SALMOS].capitulos[25].versos[12] = _("Qual é o homem que teme ao Senhor? Este lhe ensinará o caminho que deve escolher.");
    b->dados[SALMOS].capitulos[25].versos[13] = _("Ele permanecerá em prosperidade, e a sua descendência herdará a terra.");
    b->dados[SALMOS].capitulos[25].versos[14] = _("O conselho do Senhor é para aqueles que o temem, e ele lhes faz saber o seu pacto.");
    b->dados[SALMOS].capitulos[25].versos[15] = _("Os meus olhos estão postos continuamente no Senhor, pois ele tirará do laço os meus pés.");
    b->dados[SALMOS].capitulos[25].versos[16] = _("Olha para mim, e tem misericórdia de mim, porque estou desamparado e aflito.");
    b->dados[SALMOS].capitulos[25].versos[17] = _("Alivia as tribulações do meu coração; tira-me das minhas angústias.");
    b->dados[SALMOS].capitulos[25].versos[18] = _("Olha para a minha aflição e para a minha dor, e perdoa todos os meus pecados.");
    b->dados[SALMOS].capitulos[25].versos[19] = _("Olha para os meus inimigos, porque são muitos e me odeiam com ódio cruel.");
    b->dados[SALMOS].capitulos[25].versos[20] = _("Guarda a minha alma, e livra-me; não seja eu envergonhado, porque em ti me refúgio.");
    b->dados[SALMOS].capitulos[25].versos[21] = _("A integridade e a retidão me protejam, porque em ti espero.");
    b->dados[SALMOS].capitulos[25].versos[22] = _("Redime, ó Deus, a Israel de todas as suas angústias.");

    b->dados[SALMOS].capitulos[26].versos[1] = _("Julga-me, ó Senhor, pois tenho andado na minha integridade; no Senhor tenho confiado sem vacilar.");
    b->dados[SALMOS].capitulos[26].versos[2] = _("Examina-me, Senhor, e prova-me; esquadrinha o meu coração e a minha mente.");
    b->dados[SALMOS].capitulos[26].versos[3] = _("Pois a tua benignidade está diante dos meus olhos, e tenho andado na tua verdade.");
    b->dados[SALMOS].capitulos[26].versos[4] = _("Não me tenho assentado com homens falsos, nem associo com dissimuladores.");
    b->dados[SALMOS].capitulos[26].versos[5] = _("Odeio o ajuntamento de malfeitores; não me sentarei com os ímpios.");
    b->dados[SALMOS].capitulos[26].versos[6] = _("Lavo as minhas mãos na inocência; e assim, ó Senhor, me acerco do teu altar,");
    b->dados[SALMOS].capitulos[26].versos[7] = _("para fazer ouvir a voz de louvor, e contar todas as tuas maravilhas.");
    b->dados[SALMOS].capitulos[26].versos[8] = _("Senhor, eu amo o recinto da tua casa e o lugar onde permanece a tua glória.");
    b->dados[SALMOS].capitulos[26].versos[9] = _("Não colhas a minha alma com a dos pecadores, nem a minha vida a dos homens sanguinolentos,");
    b->dados[SALMOS].capitulos[26].versos[10] = _("em cujas mãos há malefício, e cuja destra está cheia de subornos.");
    b->dados[SALMOS].capitulos[26].versos[11] = _("Quanto a mim, porém, ando na minha integridade; resgata-me e tem compaixão de mim.");
    b->dados[SALMOS].capitulos[26].versos[12] = _("O meu pé está firme em terreno plano; nas congregações bendirei ao Senhor.");

    b->dados[SALMOS].capitulos[27].versos[1] = _("O Senhor é a minha luz e a minha salvação; a quem temerei? O Senhor é a força da minha vida; de quem me recearei?");
    b->dados[SALMOS].capitulos[27].versos[2] = _("Quando os malvados investiram contra mim, para comerem as minhas carnes, eles, meus adversários e meus inimigos, tropeçaram e caíram.");
    b->dados[SALMOS].capitulos[27].versos[3] = _("Ainda que um exército se acampe contra mim, o meu coração não temerá; ainda que a guerra se levante contra mim, conservarei a minha confiança.");
    b->dados[SALMOS].capitulos[27].versos[4] = _("Uma coisa pedi ao Senhor, e a buscarei: que possa morar na casa do Senhor todos os dias da minha vida, para contemplar a formosura do Senhor, e inquirir no seu templo.");
    b->dados[SALMOS].capitulos[27].versos[5] = _("Pois no dia da adversidade me esconderá no seu pavilhão; no recôndito do seu tabernáculo me esconderá; sobre uma rocha me elevará.");
    b->dados[SALMOS].capitulos[27].versos[6] = _("E agora será exaltada a minha cabeça acima dos meus inimigos que estão ao redor de mim; e no seu tabernáculo oferecerei sacrifícios de júbilo; cantarei, sim, cantarei louvores ao Senhor.");
    b->dados[SALMOS].capitulos[27].versos[7] = _("Ouve, ó Senhor, a minha voz quando clamo; compadece-te de mim e responde-me.");
    b->dados[SALMOS].capitulos[27].versos[8] = _("Quando disseste: Buscai o meu rosto; o meu coração te disse a ti: O teu rosto, Senhor, buscarei.");
    b->dados[SALMOS].capitulos[27].versos[9] = _("Não escondas de mim o teu rosto, não rejeites com ira o teu servo, tu que tens sido a minha ajuda. Não me enjeites nem me desampares, ó Deus da minha salvação.");
    b->dados[SALMOS].capitulos[27].versos[10] = _("Se meu pai e minha mãe me abandonarem, então o Senhor me acolherá.");
    b->dados[SALMOS].capitulos[27].versos[11] = _("Ensina-me, ó Senhor, o teu caminho, e guia-me por uma vereda plana, por causa dos que me espreitam.");
    b->dados[SALMOS].capitulos[27].versos[12] = _("Não me entregues à vontade dos meus adversários; pois contra mim se levantaram falsas testemunhas e os que respiram violência.");
    b->dados[SALMOS].capitulos[27].versos[13] = _("Creio que hei de ver a bondade do Senhor na terra dos viventes.");
    b->dados[SALMOS].capitulos[27].versos[14] = _("Espera tu pelo Senhor; anima-te, e fortalece o teu coração; espera, pois, pelo Senhor.");

    b->dados[SALMOS].capitulos[28].versos[1] = _("A ti clamo, ó Senhor; rocha minha, não emudeças para comigo; não suceda que, calando-te a meu respeito, eu me torne semelhante aos que descem à cova.");
    b->dados[SALMOS].capitulos[28].versos[2] = _("Ouve a voz das minhas súplicas, quando a ti clamo, quando levanto as minhas mãos para o teu santo templo.");
    b->dados[SALMOS].capitulos[28].versos[3] = _("Não me arrastes juntamente com os ímpios e com os que praticam a iniqüidade, que falam de paz ao seu próximo, mas têm o mal no seu coração.");
    b->dados[SALMOS].capitulos[28].versos[4] = _("Retribui-lhes segundo as suas obras e segundo a malícia dos seus feitos; dá-lhes conforme o que fizeram as suas mãos; retribui-lhes o que eles merecem.");
    b->dados[SALMOS].capitulos[28].versos[5] = _("Porquanto eles não atentam para as obras do Senhor, nem para o que as suas mãos têm feito, ele os derrubará e não os reedificará");
    b->dados[SALMOS].capitulos[28].versos[6] = _("Bendito seja o Senhor, porque ouviu a voz das minhas súplicas.");
    b->dados[SALMOS].capitulos[28].versos[7] = _("O Senhor é a minha força e o meu escudo; nele confiou o meu coração, e fui socorrido; pelo que o meu coração salta de prazer, e com o meu cântico o louvarei.");
    b->dados[SALMOS].capitulos[28].versos[8] = _("O Senhor é a força do seu povo; ele é a fortaleza salvadora para o seu ungido.");
    b->dados[SALMOS].capitulos[28].versos[9] = _("Salva o teu povo, e abençoa a tua herança; apascenta-os e exalta-os para sempre.");

    b->dados[SALMOS].capitulos[29].versos[1] = _("Tributai ao Senhor, ó filhos dos poderosos, tributai ao Senhor glória e força.");
    b->dados[SALMOS].capitulos[29].versos[2] = _("Tributai ao Senhor a glória devida ao seu nome; adorai o Senhor vestidos de trajes santos.");
    b->dados[SALMOS].capitulos[29].versos[3] = _("A voz do Senhor ouve-se sobre as águas; o Deus da glória troveja; o Senhor está sobre as muitas águas.");
    b->dados[SALMOS].capitulos[29].versos[4] = _("A voz do Senhor é poderosa; a voz do Senhor é cheia de majestade.");
    b->dados[SALMOS].capitulos[29].versos[5] = _("A voz do Senhor quebra os cedros; sim, o Senhor quebra os cedros do Líbano.");
    b->dados[SALMOS].capitulos[29].versos[6] = _("Ele faz o Líbano saltar como um bezerro; e Siriom, como um filhote de boi selvagem.");
    b->dados[SALMOS].capitulos[29].versos[7] = _("A voz do Senhor lança labaredas de fogo.");
    b->dados[SALMOS].capitulos[29].versos[8] = _("A voz do Senhor faz tremer o deserto; o Senhor faz tremer o deserto de Cades.");
    b->dados[SALMOS].capitulos[29].versos[9] = _("A voz do Senhor faz as corças dar à luz, e desnuda as florestas; e no seu templo todos dizem: Glória!");
    b->dados[SALMOS].capitulos[29].versos[10] = _("O Senhor está entronizado sobre o dilúvio; o Senhor se assenta como rei, perpetuamente.");
    b->dados[SALMOS].capitulos[29].versos[11] = _("O Senhor dará força ao seu povo; o Senhor abençoará o seu povo com paz.");

    b->dados[SALMOS].capitulos[30].versos[1] = _("Exaltar-te-ei, ó Senhor, porque tu me levantaste, e não permitiste que meus inimigos se alegrassem sobre mim.");
    b->dados[SALMOS].capitulos[30].versos[2] = _("Ó Senhor, Deus meu, a ti clamei, e tu me curaste.");
    b->dados[SALMOS].capitulos[30].versos[3] = _("Senhor, fizeste subir a minha alma do Seol, conservaste-me a vida, dentre os que descem à cova.");
    b->dados[SALMOS].capitulos[30].versos[4] = _("Cantai louvores ao Senhor, vós que sois seus santos, e louvai o seu santo nome.");
    b->dados[SALMOS].capitulos[30].versos[5] = _("Porque a sua ira dura só um momento; no seu favor está a vida. O choro pode durar uma noite; pela manhã, porém, vem o cântico de júbilo.");
    b->dados[SALMOS].capitulos[30].versos[6] = _("Quanto a mim, dizia eu na minha prosperidade: Jamais serei abalado.");
    b->dados[SALMOS].capitulos[30].versos[7] = _("Tu, Senhor, pelo teu favor fizeste que a minha montanha permanecesse forte; ocultaste o teu rosto, e fiquei conturbado.");
    b->dados[SALMOS].capitulos[30].versos[8] = _("A ti, Senhor, clamei, e ao Senhor supliquei:");
    b->dados[SALMOS].capitulos[30].versos[9] = _("Que proveito haverá no meu sangue, se eu descer à cova? Porventura te louvará o pó? Anunciará ele a tua verdade?");
    b->dados[SALMOS].capitulos[30].versos[10] = _("Ouve, Senhor, e tem compaixão de mim! O Senhor, sê o meu ajudador!");
    b->dados[SALMOS].capitulos[30].versos[11] = _("Tornaste o meu pranto em regozijo, tiraste o meu cilício, e me cingiste de alegria;");
    b->dados[SALMOS].capitulos[30].versos[12] = _("para que a minha alma te cante louvores, e não se cale. Senhor, Deus meu, eu te louvarei para sempre.");

    b->dados[SALMOS].capitulos[31].versos[1] = _("Em ti, Senhor, me refugio; nunca seja eu envergonhado; livra-me pela tua justiça!");
    b->dados[SALMOS].capitulos[31].versos[2] = _("Inclina para mim os teus ouvidos, livra-me depressa! Sê para mim uma rocha de refúgio, uma casa de defesa que me salve!");
    b->dados[SALMOS].capitulos[31].versos[3] = _("Porque tu és a minha rocha e a minha fortaleza; pelo que, por amor do teu nome, guia-me e encaminha-me.");
    b->dados[SALMOS].capitulos[31].versos[4] = _("Tira-me do laço que me armaram, pois tu és o meu refúgio.");
    b->dados[SALMOS].capitulos[31].versos[5] = _("Nas tuas mãos entrego o meu espírito; tu me remiste, ó Senhor, Deus da verdade.");
    b->dados[SALMOS].capitulos[31].versos[6] = _("Odeias aqueles que atentam para ídolos vãos; eu, porém, confio no Senhor.");
    b->dados[SALMOS].capitulos[31].versos[7] = _("Eu me alegrarei e regozijarei na tua benignidade, pois tens visto a minha aflição. Tens conhecido as minhas angústias,");
    b->dados[SALMOS].capitulos[31].versos[8] = _("e não me entregaste nas mãos do inimigo; puseste os meus pés num lugar espaçoso.");
    b->dados[SALMOS].capitulos[31].versos[9] = _("Tem compaixão de mim, ó Senhor, porque estou angustiado; consumidos estão de tristeza os meus olhos, a minha alma e o meu corpo.");
    b->dados[SALMOS].capitulos[31].versos[10] = _("Pois a minha vida está gasta de tristeza, e os meus anos de suspiros; a minha força desfalece por causa da minha iniqüidade, e os meus ossos se consomem.");
    b->dados[SALMOS].capitulos[31].versos[11] = _("Por causa de todos os meus adversários tornei-me em opróbrio, sim, sobremodo o sou para os meus vizinhos, e horror para os meus conhecidos; os que me vêem na rua fogem de mim.");
    b->dados[SALMOS].capitulos[31].versos[12] = _("Sou esquecido como um morto de quem não há memória; sou como um vaso quebrado.");
    b->dados[SALMOS].capitulos[31].versos[13] = _("Pois tenho ouvido a difamação de muitos, terror por todos os lados; enquanto juntamente conspiravam contra mim, maquinaram tirar-me a vida.");
    b->dados[SALMOS].capitulos[31].versos[14] = _("Mas eu confio em ti, ó Senhor; e digo: Tu és o meu Deus.");
    b->dados[SALMOS].capitulos[31].versos[15] = _("Os meus dias estão nas tuas mãos; livra-me das mãos dos meus inimigos e dos que me perseguem.");
    b->dados[SALMOS].capitulos[31].versos[16] = _("Faze resplandecer o teu rosto sobre o teu servo; salva-me por tua bondade.");
    b->dados[SALMOS].capitulos[31].versos[17] = _("Não seja eu envergonhado, ó Senhor, porque te invoco; envergonhados sejam os ímpios, emudeçam no Seol.");
    b->dados[SALMOS].capitulos[31].versos[18] = _("Emudeçam os lábios mentirosos, que falam insolentemente contra o justo, com arrogância e com desprezo.");
    b->dados[SALMOS].capitulos[31].versos[19] = _("Oh! quão grande é a tua bondade, que guardaste para os que te temem, a qual na presença dos filhos dos homens preparaste para aqueles que em ti se refugiam!");
    b->dados[SALMOS].capitulos[31].versos[20] = _("No abrigo da tua presença tu os escondes das intrigas dos homens; em um pavilhão os ocultas da contenda das línguas.");
    b->dados[SALMOS].capitulos[31].versos[21] = _("Bendito seja o Senhor, pois fez maravilhosa a sua bondade para comigo numa cidade sitiada.");
    b->dados[SALMOS].capitulos[31].versos[22] = _("Eu dizia no meu espanto: Estou cortado de diante dos teus olhos; não obstante, tu ouviste as minhas súplicas quando eu a ti clamei.");
    b->dados[SALMOS].capitulos[31].versos[23] = _("Amai ao Senhor, vós todos os que sois seus santos; o Senhor guarda os fiéis, e retribui abundantemente ao que usa de soberba.");
    b->dados[SALMOS].capitulos[31].versos[24] = _("Esforçai-vos, e fortaleça-se o vosso coração, vós todos os que esperais no Senhor.");

    b->dados[SALMOS].capitulos[32].versos[1] = _("Bem-aventurado aquele cuja transgressão é perdoada, e cujo pecado é coberto.");
    b->dados[SALMOS].capitulos[32].versos[2] = _("Bem-aventurado o homem a quem o Senhor não atribui a iniqüidade, e em cujo espírito não há dolo.");
    b->dados[SALMOS].capitulos[32].versos[3] = _("Enquanto guardei silêncio, consumiram-se os meus ossos pelo meu bramido durante o dia todo.");
    b->dados[SALMOS].capitulos[32].versos[4] = _("Porque de dia e de noite a tua mão pesava sobre mim; o meu humor se tornou em sequidão de estio.");
    b->dados[SALMOS].capitulos[32].versos[5] = _("Confessei-te o meu pecado, e a minha iniqüidade não encobri. Disse eu: Confessarei ao Senhor as minhas transgressões; e tu perdoaste a culpa do meu pecado.");
    b->dados[SALMOS].capitulos[32].versos[6] = _("Pelo que todo aquele é piedoso ore a ti, a tempo de te poder achar; no trasbordar de muitas águas, estas e ele não chegarão.");
    b->dados[SALMOS].capitulos[32].versos[7] = _("Tu és o meu esconderijo; preservas-me da angústia; de alegres cânticos de livramento me cercas.");
    b->dados[SALMOS].capitulos[32].versos[8] = _("Instruir-te-ei, e ensinar-te-ei o caminho que deves seguir; aconselhar-te-ei, tendo-te sob a minha vista.");
    b->dados[SALMOS].capitulos[32].versos[9] = _("Não sejais como o cavalo, nem como a mula, que não têm entendimento, cuja boca precisa de cabresto e freio; de outra forma não se sujeitarão.");
    b->dados[SALMOS].capitulos[32].versos[10] = _("O ímpio tem muitas dores, mas aquele que confia no Senhor, a misericórdia o cerca.");
    b->dados[SALMOS].capitulos[32].versos[11] = _("Alegrai-vos no Senhor, e regozijai-vos, vós justos; e cantai de júbilo, todos vós que sois retos de coração.");

    b->dados[SALMOS].capitulos[33].versos[1] = _("Regozijai-vos no Senhor, vós justos, pois aos retos fica bem o louvor.");
    b->dados[SALMOS].capitulos[33].versos[2] = _("Louvai ao Senhor com harpa, cantai-lhe louvores com saltério de dez cordas.");
    b->dados[SALMOS].capitulos[33].versos[3] = _("Cantai-lhe um cântico novo; tocai bem e com júbilo.");
    b->dados[SALMOS].capitulos[33].versos[4] = _("Porque a palavra do Senhor é reta; e todas as suas obras são feitas com fidelidade.");
    b->dados[SALMOS].capitulos[33].versos[5] = _("Ele ama a retidão e a justiça; a terra está cheia da benignidade do Senhor.");
    b->dados[SALMOS].capitulos[33].versos[6] = _("Pela palavra do Senhor foram feitos os céus, e todo o exército deles pelo sopro da sua boca.");
    b->dados[SALMOS].capitulos[33].versos[7] = _("Ele ajunta as águas do mar como num montão; põe em tesouros os abismos.");
    b->dados[SALMOS].capitulos[33].versos[8] = _("Tema ao Senhor a terra toda; temam-no todos os moradores do mundo.");
    b->dados[SALMOS].capitulos[33].versos[9] = _("Pois ele falou, e tudo se fez; ele mandou, e logo tudo apareceu.");
    b->dados[SALMOS].capitulos[33].versos[10] = _("O Senhor desfaz o conselho das nações, anula os intentos dos povos.");
    b->dados[SALMOS].capitulos[33].versos[11] = _("O conselho do Senhor permanece para sempre, e os intentos do seu coração por todas as gerações.");
    b->dados[SALMOS].capitulos[33].versos[12] = _("Bem-aventurada é a nação cujo Deus é o Senhor, o povo que ele escolheu para sua herança.");
    b->dados[SALMOS].capitulos[33].versos[13] = _("O Senhor olha lá do céu; vê todos os filhos dos homens;");
    b->dados[SALMOS].capitulos[33].versos[14] = _("da sua morada observa todos os moradores da terra,");
    b->dados[SALMOS].capitulos[33].versos[15] = _("aquele que forma o coração de todos eles, que contempla todas as suas obras.");
    b->dados[SALMOS].capitulos[33].versos[16] = _("Um rei não se salva pela multidão do seu exército; nem o homem valente se livra pela muita força.");
    b->dados[SALMOS].capitulos[33].versos[17] = _("O cavalo é vã esperança para a vitória; não pode livrar ninguém pela sua grande força.");
    b->dados[SALMOS].capitulos[33].versos[18] = _("Eis que os olhos do Senhor estão sobre os que o temem, sobre os que esperam na sua benignidade,");
    b->dados[SALMOS].capitulos[33].versos[19] = _("para os livrar da morte, e para os conservar vivos na fome.");
    b->dados[SALMOS].capitulos[33].versos[20] = _("A nossa alma espera no Senhor; ele é o nosso auxílio e o nosso escudo.");
    b->dados[SALMOS].capitulos[33].versos[21] = _("Pois nele se alegra o nosso coração, porquanto temos confiado no seu santo nome.");
    b->dados[SALMOS].capitulos[33].versos[22] = _("Seja a tua benignidade, Senhor, sobre nós, assim como em ti esperamos.");

    b->dados[SALMOS].capitulos[34].versos[1] = _("Bendirei ao Senhor em todo o tempo; o seu louvor estará continuamente na minha boca.");
    b->dados[SALMOS].capitulos[34].versos[2] = _("No Senhor se gloria a minha alma; ouçam-no os mansos e se alegrem.");
    b->dados[SALMOS].capitulos[34].versos[3] = _("Engrandeci ao Senhor comigo, e juntos exaltemos o seu nome.");
    b->dados[SALMOS].capitulos[34].versos[4] = _("Busquei ao Senhor, e ele me respondeu, e de todos os meus temores me livrou.");
    b->dados[SALMOS].capitulos[34].versos[5] = _("Olhai para ele, e sede iluminados; e os vossos rostos jamais serão confundidos.");
    b->dados[SALMOS].capitulos[34].versos[6] = _("Clamou este pobre, e o Senhor o ouviu, e o livrou de todas as suas angústias.");
    b->dados[SALMOS].capitulos[34].versos[7] = _("O anjo do Senhor acampa-se ao redor dos que o temem, e os livra.");
    b->dados[SALMOS].capitulos[34].versos[8] = _("Provai, e vede que o Senhor é bom; bem-aventurado o homem que nele se refugia.");
    b->dados[SALMOS].capitulos[34].versos[9] = _("Temei ao Senhor, vós, seus santos, porque nada falta aos que o temem.");
    b->dados[SALMOS].capitulos[34].versos[10] = _("Os leõezinhos necessitam e sofrem fome, mas àqueles que buscam ao Senhor, bem algum lhes faltará.");
    b->dados[SALMOS].capitulos[34].versos[11] = _("Vinde, filhos, ouvi-me; eu vos ensinarei o temor do Senhor.");
    b->dados[SALMOS].capitulos[34].versos[12] = _("Quem é o homem que deseja a vida, e quer longos dias para ver o bem?");
    b->dados[SALMOS].capitulos[34].versos[13] = _("Guarda a tua língua do mal, e os teus lábios de falarem dolosamente.");
    b->dados[SALMOS].capitulos[34].versos[14] = _("Aparta-te do mal, e faze o bem: busca a paz, e segue-a.");
    b->dados[SALMOS].capitulos[34].versos[15] = _("Os olhos do Senhor estão sobre os justos, e os seus ouvidos atentos ao seu clamor.");
    b->dados[SALMOS].capitulos[34].versos[16] = _("A face do Senhor está contra os que fazem o mal, para desarraigar da terra a memória deles.");
    b->dados[SALMOS].capitulos[34].versos[17] = _("Os justos clama, e o Senhor os ouve, e os livra de todas as suas angústias.");
    b->dados[SALMOS].capitulos[34].versos[18] = _("Perto está o Senhor dos que têm o coração quebrantado, e salva os contritos de espírito.");
    b->dados[SALMOS].capitulos[34].versos[19] = _("Muitas são as aflições do justo, mas de todas elas o Senhor o livra.");
    b->dados[SALMOS].capitulos[34].versos[20] = _("Ele lhe preserva todos os ossos; nem sequer um deles se quebra.");
    b->dados[SALMOS].capitulos[34].versos[21] = _("A malícia matará o ímpio, e os que odeiam o justo serão condenados.");
    b->dados[SALMOS].capitulos[34].versos[22] = _("O Senhor resgata a alma dos seus servos, e nenhum dos que nele se refugiam será condenado.");

    b->dados[SALMOS].capitulos[35].versos[1] = _("Contende, Senhor, com aqueles que contendem comigo; combate contra os que me combatem.");
    b->dados[SALMOS].capitulos[35].versos[2] = _("Pega do escudo e do pavês, e levanta-te em meu socorro.");
    b->dados[SALMOS].capitulos[35].versos[3] = _("Tira da lança e do dardo contra os que me perseguem. Dize à minha alma: Eu sou a tua salvação.");
    b->dados[SALMOS].capitulos[35].versos[4] = _("Sejam envergonhados e confundidos os que buscam a minha vida; voltem atrás e se confudam os que contra mim intentam o mal.");
    b->dados[SALMOS].capitulos[35].versos[5] = _("Sejam como a moinha diante do vento, e o anjo do Senhor os faça fugir.");
    b->dados[SALMOS].capitulos[35].versos[6] = _("Seja o seu caminho tenebroso e escorregadio, e o anjo do Senhor os persiga.");
    b->dados[SALMOS].capitulos[35].versos[7] = _("Pois sem causa me armaram ocultamente um laço; sem razão cavaram uma cova para a minha vida.");
    b->dados[SALMOS].capitulos[35].versos[8] = _("Sobrevenha-lhes inesperadamente a destruição, e prenda-os o laço que ocultaram; caiam eles nessa mesma destruição.");
    b->dados[SALMOS].capitulos[35].versos[9] = _("Então minha alma se regozijará no Senhor; exultará na sua salvação.");
    b->dados[SALMOS].capitulos[35].versos[10] = _("Todos os meus ossos dirão: Ó Senhor, quem é como tu, que livras o fraco daquele que é mais forte do que ele? sim, o pobre e o necessitado, daquele que o rouba.");
    b->dados[SALMOS].capitulos[35].versos[11] = _("Levantam-se testemunhas maliciosas; interrogam-me sobre coisas que eu ignoro.");
    b->dados[SALMOS].capitulos[35].versos[12] = _("Tornam-me o mal pelo bem, causando-me luto na alma.");
    b->dados[SALMOS].capitulos[35].versos[13] = _("Mas, quanto a mim, estando eles enfermos, vestia-me de cilício, humilhava-me com o jejum, e orava de cabeça sobre o peito.");
    b->dados[SALMOS].capitulos[35].versos[14] = _("Portava-me como o faria por meu amigo ou meu irmão; eu andava encurvado e lamentando-me, como quem chora por sua mãe.");
    b->dados[SALMOS].capitulos[35].versos[15] = _("Mas, quando eu tropeçava, eles se alegravam e se congregavam; congregavam-se contra mim, homens miseráveis que eu não conhecia; difamavam-me sem cessar.");
    b->dados[SALMOS].capitulos[35].versos[16] = _("Como hipócritas zombadores nas festas, rangiam os dentes contra mim.");
    b->dados[SALMOS].capitulos[35].versos[17] = _("Ó Senhor, até quando contemplarás isto? Livra-me das suas violências; salva a minha vida dos leões!");
    b->dados[SALMOS].capitulos[35].versos[18] = _("Então te darei graças na grande assembléia; entre muitíssimo povo te louvarei.");
    b->dados[SALMOS].capitulos[35].versos[19] = _("Não se alegrem sobre mim os que são meus inimigos sem razão, nem pisquem os olhos aqueles que me odeiam sem causa.");
    b->dados[SALMOS].capitulos[35].versos[20] = _("Pois não falaram de paz, antes inventam contra os quietos da terra palavras enganosas.");
    b->dados[SALMOS].capitulos[35].versos[21] = _("Escancararam contra mim a sua boca, e dizem: Ah! Ah! os nossos olhos o viram.");
    b->dados[SALMOS].capitulos[35].versos[22] = _("Tu, Senhor, o viste, não te cales; Senhor, não te alongues de mim.");
    b->dados[SALMOS].capitulos[35].versos[23] = _("Acorda e desperta para o meu julgamento, para a minha causa, Deus meu, e Senhor meu.");
    b->dados[SALMOS].capitulos[35].versos[24] = _("Justifica-me segundo a tua justiça, Senhor Deus meu, e não se regozijem eles sobre mim.");
    b->dados[SALMOS].capitulos[35].versos[25] = _("Não digam em seu coração: Eia! cumpriu-se o nosso desejo! Não digam: Nós o havemos devorado.");
    b->dados[SALMOS].capitulos[35].versos[26] = _("Envergonhem-se e confundam-se à uma os que se alegram com o meu mal; vistam-se de vergonha e de confusão os que se engrandecem contra mim.");
    b->dados[SALMOS].capitulos[35].versos[27] = _("Bradem de júbilo e se alegrem os que desejam a minha justificação, e digam a minha justificação, e digam continuamente: Seja engrandecido o Senhor, que se deleita na prosperidade do seu servo.");
    b->dados[SALMOS].capitulos[35].versos[28] = _("Então a minha língua falará da tua justiça e do teu louvor o dia todo.");

    b->dados[SALMOS].capitulos[36].versos[1] = _("A transgressão fala ao ímpio no íntimo do seu coração; não há temor de Deus perante os seus olhos.");
    b->dados[SALMOS].capitulos[36].versos[2] = _("Porque em seus próprios olhos se lisonjeia, cuidando que a sua iniqüidade não será descoberta e detestada.");
    b->dados[SALMOS].capitulos[36].versos[3] = _("As palavras da sua boca são malícia e engano; deixou de ser prudente e de fazer o bem.");
    b->dados[SALMOS].capitulos[36].versos[4] = _("Maquina o mal na sua cama; põe-se em caminho que não é bom; não odeia o mal.");
    b->dados[SALMOS].capitulos[36].versos[5] = _("A tua benignidade, Senhor, chega até os céus, e a tua fidelidade até as nuvens.");
    b->dados[SALMOS].capitulos[36].versos[6] = _("A tua justiça é como os montes de Deus, os teus juízos são como o abismo profundo. Tu, Senhor, preservas os homens e os animais.");
    b->dados[SALMOS].capitulos[36].versos[7] = _("Quão preciosa é, ó Deus, a tua benignidade! Os filhos dos homens se refugiam à sombra das tuas asas.");
    b->dados[SALMOS].capitulos[36].versos[8] = _("Eles se fartarão da gordura da tua casa, e os farás beber da corrente das tuas delícias;");
    b->dados[SALMOS].capitulos[36].versos[9] = _("pois em ti está o manancial da vida; na tua luz vemos a luz.");
    b->dados[SALMOS].capitulos[36].versos[10] = _("Continua a tua benignidade aos que te conhecem, e a tua justiça aos retos de coração.");
    b->dados[SALMOS].capitulos[36].versos[11] = _("Não venha sobre mim o pé da soberba, e não me mova a mão dos ímpios.");
    b->dados[SALMOS].capitulos[36].versos[12] = _("Ali caídos estão os que praticavam a iniqüidade; estão derrubados, e não se podem levantar.");

    b->dados[SALMOS].capitulos[37].versos[1] = _("Não te enfades por causa dos malfeitores, nem tenhas inveja dos que praticam a iniqüidade.");
    b->dados[SALMOS].capitulos[37].versos[2] = _("Pois em breve murcharão como a relva, e secarão como a erva verde.");
    b->dados[SALMOS].capitulos[37].versos[3] = _("Confia no Senhor e faze o bem; assim habitarás na terra, e te alimentarás em segurança.");
    b->dados[SALMOS].capitulos[37].versos[4] = _("Deleita-te também no Senhor, e ele te concederá o que deseja o teu coração.");
    b->dados[SALMOS].capitulos[37].versos[5] = _("Entrega o teu caminho ao Senhor; confia nele, e ele tudo fará.");
    b->dados[SALMOS].capitulos[37].versos[6] = _("E ele fará sobressair a tua justiça como a luz, e o teu direito como o meio-dia.");
    b->dados[SALMOS].capitulos[37].versos[7] = _("Descansa no Senhor, e espera nele; não te enfades por causa daquele que prospera em seu caminho, por causa do homem que executa maus desígnios.");
    b->dados[SALMOS].capitulos[37].versos[8] = _("Deixa a ira, e abandona o furor; não te enfades, pois isso só leva à prática do mal.");
    b->dados[SALMOS].capitulos[37].versos[9] = _("Porque os malfeitores serão exterminados, mas aqueles que esperam no Senhor herdarão a terra.");
    b->dados[SALMOS].capitulos[37].versos[10] = _("Pois ainda um pouco, e o ímpio não existirá; atentarás para o seu lugar, e ele ali não estará.");
    b->dados[SALMOS].capitulos[37].versos[11] = _("Mas os mansos herdarão a terra, e se deleitarão na abundância de paz.");
    b->dados[SALMOS].capitulos[37].versos[12] = _("O ímpio maquina contra o justo, e contra ele range os dentes,");
    b->dados[SALMOS].capitulos[37].versos[13] = _("mas o Senhor se ri do ímpio, pois vê que vem chegando o seu dia.");
    b->dados[SALMOS].capitulos[37].versos[14] = _("Os ímpios têm puxado da espada e têm entesado o arco, para derrubarem o poder e necessitado, e para matarem os que são retos no seu caminho.");
    b->dados[SALMOS].capitulos[37].versos[15] = _("Mas a sua espada lhes entrará no coração, e os seus arcos quebrados.");
    b->dados[SALMOS].capitulos[37].versos[16] = _("Mais vale o pouco que o justo tem, do que as riquezas de muitos ímpios.");
    b->dados[SALMOS].capitulos[37].versos[17] = _("Pois os braços dos ímpios serão quebrados, mas o Senhor sustém os justos.");
    b->dados[SALMOS].capitulos[37].versos[18] = _("O Senhor conhece os dias dos íntegros, e a herança deles permanecerá para sempre.");
    b->dados[SALMOS].capitulos[37].versos[19] = _("Não serão envergonhados no dia do mal, e nos dias da fome se fartarão.");
    b->dados[SALMOS].capitulos[37].versos[20] = _("Mas os ímpios perecerão, e os inimigos do Senhor serão como a beleza das pastagens; desaparecerão, em fumaça se desfarão.");
    b->dados[SALMOS].capitulos[37].versos[21] = _("O ímpio toma emprestado, e não paga; mas o justo se compadece e dá.");
    b->dados[SALMOS].capitulos[37].versos[22] = _("Pois aqueles que são abençoados pelo Senhor herdarão a terra, mas aqueles que são por ele amaldiçoados serão exterminados.");
    b->dados[SALMOS].capitulos[37].versos[23] = _("Confirmados pelo Senhor são os passos do homem em cujo caminho ele se deleita;");
    b->dados[SALMOS].capitulos[37].versos[24] = _("ainda que caia, não ficará prostrado, pois o Senhor lhe segura a mão.");
    b->dados[SALMOS].capitulos[37].versos[25] = _("Fui moço, e agora sou velho; mas nunca vi desamparado o justo, nem a sua descendência a mendigar o pão.");
    b->dados[SALMOS].capitulos[37].versos[26] = _("Ele é sempre generoso, e empresta, e a sua descendência é abençoada.");
    b->dados[SALMOS].capitulos[37].versos[27] = _("Aparta-te do mal e faze o bem; e terás morada permanente.");
    b->dados[SALMOS].capitulos[37].versos[28] = _("Pois o Senhor ama a justiça e não desampara os seus santos. Eles serão preservados para sempre, mas a descendência dos ímpios será exterminada.");
    b->dados[SALMOS].capitulos[37].versos[29] = _("Os justos herdarão a terra e nela habitarão para sempre.");
    b->dados[SALMOS].capitulos[37].versos[30] = _("A boca do justo profere sabedoria; a sua língua fala o que é reto.");
    b->dados[SALMOS].capitulos[37].versos[31] = _("A lei do seu Deus está em seu coração; não resvalarão os seus passos.");
    b->dados[SALMOS].capitulos[37].versos[32] = _("O ímpio espreita o justo, e procura matá-lo.");
    b->dados[SALMOS].capitulos[37].versos[33] = _("O Senhor não o deixará nas mãos dele, nem o condenará quando for julgado.");
    b->dados[SALMOS].capitulos[37].versos[34] = _("Espera no Senhor, e segue o seu caminho, e ele te exaltará para herdares a terra; tu o verás quando os ímpios forem exterminados.");
    b->dados[SALMOS].capitulos[37].versos[35] = _("Vi um ímpio cheio de prepotência, e a espalhar-se como a árvore verde na terra natal.");
    b->dados[SALMOS].capitulos[37].versos[36] = _("Mas eu passei, e ele já não era; procurei-o, mas não pôde ser encontrado.");
    b->dados[SALMOS].capitulos[37].versos[37] = _("Nota o homem íntegro, e considera o reto, porque há para o homem de paz um porvir feliz.");
    b->dados[SALMOS].capitulos[37].versos[38] = _("Quanto aos transgressores, serão à uma destruídos, e a posteridade dos ímpios será exterminada.");
    b->dados[SALMOS].capitulos[37].versos[39] = _("Mas a salvação dos justos vem do Senhor; ele é a sua fortaleza no tempo da angústia.");
    b->dados[SALMOS].capitulos[37].versos[40] = _("E o Senhor os ajuda e os livra; ele os livra dos ímpios e os salva, porquanto nele se refugiam.");

    b->dados[SALMOS].capitulos[38].versos[1] = _("Ó Senhor, não me repreendas na tua ira, nem me castigues no teu furor.");
    b->dados[SALMOS].capitulos[38].versos[2] = _("Porque as tuas flechas se cravaram em mim, e sobre mim a tua mão pesou.");
    b->dados[SALMOS].capitulos[38].versos[3] = _("Não há coisa sã na minha carne, por causa da tua cólera; nem há saúde nos meus ossos, por causa do meu pecado.");
    b->dados[SALMOS].capitulos[38].versos[4] = _("Pois já as minhas iniqüidades submergem a minha cabeça; como carga pesada excedem as minhas forças.");
    b->dados[SALMOS].capitulos[38].versos[5] = _("As minhas chagas se tornam fétidas e purulentas, por causa da minha loucura.");
    b->dados[SALMOS].capitulos[38].versos[6] = _("Estou encurvado, estou muito abatido, ando lamentando o dia todo.");
    b->dados[SALMOS].capitulos[38].versos[7] = _("Pois os meus lombos estão cheios de ardor, e não há coisa sã na minha carne.");
    b->dados[SALMOS].capitulos[38].versos[8] = _("Estou gasto e muito esmagado; dou rugidos por causa do desassossego do meu coração.");
    b->dados[SALMOS].capitulos[38].versos[9] = _("Senhor, diante de ti está todo o meu desejo, e o meu suspirar não te é oculto.");
    b->dados[SALMOS].capitulos[38].versos[10] = _("O meu coração está agitado; a minha força me falta; quanto à luz dos meus olhos, até essa me deixou.");
    b->dados[SALMOS].capitulos[38].versos[11] = _("Os meus amigos e os meus companheiros afastaram-se da minha chaga; e os meus parentes se põem à distância.");
    b->dados[SALMOS].capitulos[38].versos[12] = _("Também os que buscam a minha vida me armam laços, e os que procuram o meu mal dizem coisas perniciosas,");
    b->dados[SALMOS].capitulos[38].versos[13] = _("Mas eu, como um surdo, não ouço; e sou qual um mudo que não abre a boca.");
    b->dados[SALMOS].capitulos[38].versos[14] = _("Assim eu sou como homem que não ouve, e em cuja boca há com que replicar.");
    b->dados[SALMOS].capitulos[38].versos[15] = _("Mas por ti, Senhor, espero; tu, Senhor meu Deus, responderás.");
    b->dados[SALMOS].capitulos[38].versos[16] = _("Rogo, pois: Ouve-me, para que eles não se regozijem sobre mim e não se engrandeçam contra mim quando resvala o meu pé.");
    b->dados[SALMOS].capitulos[38].versos[17] = _("Pois estou prestes a tropeçar; a minha dor está sempre comigo.");
    b->dados[SALMOS].capitulos[38].versos[18] = _("Confesso a minha iniqüidade; entristeço-me por causa do meu pecado.");
    b->dados[SALMOS].capitulos[38].versos[19] = _("Mas os meus inimigos são cheios de vida e são fortes, e muitos são os que sem causa me odeiam.");
    b->dados[SALMOS].capitulos[38].versos[20] = _("Os que tornam o mal pelo bem são meus adversários, porque eu sigo o que é bom.");
    b->dados[SALMOS].capitulos[38].versos[21] = _("Não me desampares, ó Senhor; Deus meu, não te alongues de mim.");
    b->dados[SALMOS].capitulos[38].versos[22] = _("Apressa-te em meu auxílio, Senhor, minha salvação.");

    b->dados[SALMOS].capitulos[39].versos[1] = _("Disse eu: Guardarei os meus caminhos para não pecar com a minha língua; guardarei a minha boca com uma mordaça, enquanto o ímpio estiver diante de mim.");
    b->dados[SALMOS].capitulos[39].versos[2] = _("Com silêncio fiquei qual um mundo; calava-me mesmo acerca do bem; mas a minha dor se agravou.");
    b->dados[SALMOS].capitulos[39].versos[3] = _("Acendeu-se dentro de mim o meu coração; enquanto eu meditava acendeu-se o fogo; então com a minha língua, dizendo;");
    b->dados[SALMOS].capitulos[39].versos[4] = _("Faze-me conhecer, ó Senhor, o meu fim, e qual a medida dos meus dias, para que eu saiba quão frágil sou.");
    b->dados[SALMOS].capitulos[39].versos[5] = _("Eis que mediste os meus dias a palmos; o tempo da minha vida é como que nada diante de ti. Na verdade, todo homem, por mais firme que esteja, é totalmente vaidade.");
    b->dados[SALMOS].capitulos[39].versos[6] = _("Na verdade, todo homem anda qual uma sombra; na verdade, em vão se inquieta, amontoa riquezas, e não sabe quem as levará.");
    b->dados[SALMOS].capitulos[39].versos[7] = _("Agora, pois, Senhor, que espero eu? a minha esperança está em ti.");
    b->dados[SALMOS].capitulos[39].versos[8] = _("Livra-me de todas as minhas transgressões; não me faças o opróbrio do insensato.");
    b->dados[SALMOS].capitulos[39].versos[9] = _("Emudecido estou, não abro a minha boca; pois tu és que agiste,");
    b->dados[SALMOS].capitulos[39].versos[10] = _("Tira de sobre mim o teu flagelo; estou desfalecido pelo golpe da tua mão.");
    b->dados[SALMOS].capitulos[39].versos[11] = _("Quando com repreensões castigas o homem por causa da iniquidade, destróis, como traça, o que ele tem de precioso; na verdade todo homem é vaidade.");
    b->dados[SALMOS].capitulos[39].versos[12] = _("Ouve, Senhor, a minha oração, e inclina os teus ouvidos ao meu clamor; não te cales perante as minhas lágrimas, porque sou para contigo como um estranho, um peregrino como todos os meus pais.");
    b->dados[SALMOS].capitulos[39].versos[13] = _("Desvia de mim o teu olhar, para que eu tome alento, antes que me vá e não exista mais.");

    b->dados[SALMOS].capitulos[40].versos[1] = _("Esperei com paciência pelo Senhor, e ele se inclinou para mim e ouviu o meu clamor.");
    b->dados[SALMOS].capitulos[40].versos[2] = _("Também me tirou duma cova de destruição, dum charco de lodo; pôs os meus pés sobre uma rocha, firmou os meus passos.");
    b->dados[SALMOS].capitulos[40].versos[3] = _("Pôs na minha boca um cântico novo, um hino ao nosso Deus; muitos verão isso e temerão, e confiarão no Senhor.");
    b->dados[SALMOS].capitulos[40].versos[4] = _("Bem-aventurado o homem que faz do Senhor a sua confiança, e que não atenta para os soberbos nem para os apóstatas mentirosos.");
    b->dados[SALMOS].capitulos[40].versos[5] = _("Muitas são, Senhor, Deus meu, as maravilhas que tens operado e os teus pensamentos para conosco; ninguém há que se possa comparar a ti; eu quisera anunciá-los, e manifestá-los, mas são mais do que se podem contar.");
    b->dados[SALMOS].capitulos[40].versos[6] = _("Sacrifício e oferta não desejas; abriste-me os ouvidos; holocausto e oferta de expiação pelo pecado não reclamaste.");
    b->dados[SALMOS].capitulos[40].versos[7] = _("Então disse eu: Eis aqui venho; no rolo do livro está escrito a meu respeito:");
    b->dados[SALMOS].capitulos[40].versos[8] = _("Deleito-me em fazer a tua vontade, ó Deus meu; sim, a tua lei está dentro do meu coração.");
    b->dados[SALMOS].capitulos[40].versos[9] = _("Tenho proclamado boas-novas de justiça na grande congregação; eis que não retive os meus lábios;");
    b->dados[SALMOS].capitulos[40].versos[10] = _("Não ocultei dentro do meu coração a tua justiça; apregoei a tua fidelidade e a tua salvação; não escondi da grande congregação a tua benignidade e a tua verdade.");
    b->dados[SALMOS].capitulos[40].versos[11] = _("Não detenhas para comigo, Senhor a tua compaixão; a tua benignidade e a tua fidelidade sempre me guardem.");
    b->dados[SALMOS].capitulos[40].versos[12] = _("Pois males sem número me têm rodeado; as minhas iniqüidades me têm alcançado, de modo que não posso ver; são mais numerosas do que os cabelos da minha cabeça, pelo que desfalece o meu coração.");
    b->dados[SALMOS].capitulos[40].versos[13] = _("Digna-te, Senhor, livra-me; Senhor, apressa-te em meu auxílio.");
    b->dados[SALMOS].capitulos[40].versos[14] = _("Sejam à uma envergonhados e confundidos os que buscam a minha vida para destruí-la; tornem atrás e confundam-se os que me desejam o mal.");
    b->dados[SALMOS].capitulos[40].versos[15] = _("Desolados sejam em razão da sua afronta os que me dizem: Ah! Ah!");
    b->dados[SALMOS].capitulos[40].versos[16] = _("Regozijem-se e alegrem-se em ti todos os que te buscam. Digam continuamente os que amam a tua salvação: Engrandecido seja o Senhor.");
    b->dados[SALMOS].capitulos[40].versos[17] = _("Eu, na verdade, sou pobre e necessitado, mas o Senhor cuida de mim. Tu és o meu auxílio e o meu libertador; não te detenhas, ó Deus meu.");

    b->dados[SALMOS].capitulos[41].versos[1] = _("Bem-aventurado é aquele que considera o pobre; o Senhor o livrará no dia do mal.");
    b->dados[SALMOS].capitulos[41].versos[2] = _("O Senhor o guardará, e o conservará em vida; será abençoado na terra; tu, Senhor não o entregarás à vontade dos seus inimigos.");
    b->dados[SALMOS].capitulos[41].versos[3] = _("O Senhor o sustentará no leito da enfermidade; tu lhe amaciarás a cama na sua doença.");
    b->dados[SALMOS].capitulos[41].versos[4] = _("Disse eu da minha parte: Senhor, compadece-te de mim, sara a minha alma, pois pequei contra ti.");
    b->dados[SALMOS].capitulos[41].versos[5] = _("Os meus inimigos falam mal de mim, dizendo: Quando morrerá ele, e perecerá o seu nome?");
    b->dados[SALMOS].capitulos[41].versos[6] = _("E, se algum deles vem ver-me, diz falsidades; no seu coração amontoa a maldade; e quando ele sai, é disso que fala.");
    b->dados[SALMOS].capitulos[41].versos[7] = _("Todos os que me odeiam cochicham entre si contra mim; contra mim maquinam o mal, dizendo:");
    b->dados[SALMOS].capitulos[41].versos[8] = _("Alguma coisa ruim se lhe apega; e agora que está deitado, não se levantará mais.");
    b->dados[SALMOS].capitulos[41].versos[9] = _("Até o meu próprio amigo íntimo em quem eu tanto confiava, e que comia do meu pão, levantou contra mim o seu calcanhar.");
    b->dados[SALMOS].capitulos[41].versos[10] = _("Mas tu, Senhor, compadece-te de mim e levanta-me, para que eu lhes retribua.");
    b->dados[SALMOS].capitulos[41].versos[11] = _("Por isso conheço eu que te deleitas em mim, por não triunfar de mim o meu inimigo");
    b->dados[SALMOS].capitulos[41].versos[12] = _("Quanto a mim, tu me sustentas na minha integridade, e me colocas diante da tua face para sempre.");
    b->dados[SALMOS].capitulos[41].versos[13] = _("Bendito seja o Senhor Deus de Israel de eternidade a eternidade. Amém e amém.");

    b->dados[SALMOS].capitulos[42].versos[1] = _("Como o cervo anseia pelas correntes das águas, assim a minha alma anseia por ti, ó Deus!");
    b->dados[SALMOS].capitulos[42].versos[2] = _("A minha alma tem sede de Deus, do Deus vivo; quando entrarei e verei a face de Deus?");
    b->dados[SALMOS].capitulos[42].versos[3] = _("As minhas lágrimas têm sido o meu alimento de dia e de noite, porquanto se me diz constantemente: Onde está o teu Deus?");
    b->dados[SALMOS].capitulos[42].versos[4] = _("Dentro de mim derramo a minha alma ao lembrar-me de como eu ia com a multidão, guiando-a em procissão à casa de Deus, com brados de júbilo e louvor, uma multidão que festejava.");
    b->dados[SALMOS].capitulos[42].versos[5] = _("Por que estás abatida, ó minha alma, e por que te perturbas dentro de mim? Espera em Deus, pois ainda o louvarei pela salvação que há na sua presença.");
    b->dados[SALMOS].capitulos[42].versos[6] = _("Ó Deus meu, dentro de mim a minha alma está abatida; porquanto me lembrarei de ti desde a terra do Jordão, e desde o Hermom, desde o monte Mizar.");
    b->dados[SALMOS].capitulos[42].versos[7] = _("Um abismo chama outro abismo ao ruído das tuas catadupas; todas as tuas ondas e vagas têm passado sobre mim.");
    b->dados[SALMOS].capitulos[42].versos[8] = _("Contudo, de dia o Senhor ordena a sua bondade, e de noite a sua canção está comigo, uma oração ao Deus da minha vida.");
    b->dados[SALMOS].capitulos[42].versos[9] = _("A Deus, a minha rocha, digo: Por que te esqueceste de mim? por que ando em pranto por causa da opressão do inimigo?");
    b->dados[SALMOS].capitulos[42].versos[10] = _("Como com ferida mortal nos meus ossos me afrontam os meus adversários, dizendo-me continuamente: Onde está o teu Deus?");
    b->dados[SALMOS].capitulos[42].versos[11] = _("Por que estás abatida, ó minha alma, e por que te perturbas dentro de mim? Espera em Deus, pois ainda o louvarei, a ele que é o meu socorro, e o meu Deus.");

    b->dados[SALMOS].capitulos[43].versos[1] = _("Faze-me justiça, ó Deus, e pleiteia a minha causa contra uma nação ímpia; livra-me do homem fraudulento e iníquo.");
    b->dados[SALMOS].capitulos[43].versos[2] = _("Pois tu és o Deus da minha fortaleza; por que me rejeitaste? por que ando em pranto por causa da opressão do inimigo?");
    b->dados[SALMOS].capitulos[43].versos[3] = _("Envia a tua luz e a tua verdade, para que me guiem; levem-me elas ao teu santo monte, e à tua habitação.");
    b->dados[SALMOS].capitulos[43].versos[4] = _("Então irei ao altar de Deus, a Deus, que é a minha grande alegria; e ao som da harpa te louvarei, ó Deus, Deus meu.");
    b->dados[SALMOS].capitulos[43].versos[5] = _("Por que estás abatida, ó minha alma? e por que te perturbas dentro de mim? Espera em Deus, pois ainda o louvarei, a ele que é o meu socorro, e o meu Deus.");

    b->dados[SALMOS].capitulos[44].versos[1] = _("Ó Deus, nós ouvimos com os nossos ouvidos, nossos pais nos têm contado os feitos que realizaste em seus dias, nos tempos da antigüidade.");
    b->dados[SALMOS].capitulos[44].versos[2] = _("Tu expeliste as nações com a tua mão, mas a eles plantaste; afligiste os povos, mas a eles estendes-te largamente.");
    b->dados[SALMOS].capitulos[44].versos[3] = _("Pois não foi pela sua espada que conquistaram a terra, nem foi o seu braço que os salvou, mas a tua destra e o teu braço, e a luz do teu rosto, porquanto te agradaste deles.");
    b->dados[SALMOS].capitulos[44].versos[4] = _("Tu és o meu Rei, ó Deus; ordena livramento para Jacó.");
    b->dados[SALMOS].capitulos[44].versos[5] = _("Por ti derrubamos os nossos adversários; pelo teu nome pisamos os que se levantam contra nós.");
    b->dados[SALMOS].capitulos[44].versos[6] = _("Pois não confio no meu arco, nem a minha espada me pode salvar.");
    b->dados[SALMOS].capitulos[44].versos[7] = _("Mas tu nos salvaste dos nossos adversários, e confundiste os que nos odeiam.");
    b->dados[SALMOS].capitulos[44].versos[8] = _("Em Deus é que nos temos gloriado o dia todo, e sempre louvaremos o teu nome.");
    b->dados[SALMOS].capitulos[44].versos[9] = _("Mas agora nos rejeitaste e nos humilhaste, e não sais com os nossos exércitos.");
    b->dados[SALMOS].capitulos[44].versos[10] = _("Fizeste-nos voltar as costas ao inimigo e aqueles que nos odeiam nos despojam à vontade.");
    b->dados[SALMOS].capitulos[44].versos[11] = _("Entregaste-nos como ovelhas para alimento, e nos espalhaste entre as nações.");
    b->dados[SALMOS].capitulos[44].versos[12] = _("Vendeste por nada o teu povo, e não lucraste com o seu preço.");
    b->dados[SALMOS].capitulos[44].versos[13] = _("Puseste-nos por opróbrio aos nossos vizinhos, por escárnio e zombaria àqueles que estão à roda de nós.");
    b->dados[SALMOS].capitulos[44].versos[14] = _("Puseste-nos por provérbio entre as nações, por ludíbrio entre os povos.");
    b->dados[SALMOS].capitulos[44].versos[15] = _("A minha ignomínia está sempre diante de mim, e a vergonha do meu rosto me cobre,");
    b->dados[SALMOS].capitulos[44].versos[16] = _("à voz daquele que afronta e blasfema, à vista do inimigo e do vingador.");
    b->dados[SALMOS].capitulos[44].versos[17] = _("Tudo isto nos sobreveio; todavia não nos esquecemos de ti, nem nos houvemos falsamente contra o teu pacto.");
    b->dados[SALMOS].capitulos[44].versos[18] = _("O nosso coração não voltou atrás, nem os nossos passos se desviaram das tuas veredas,");
    b->dados[SALMOS].capitulos[44].versos[19] = _("para nos teres esmagado onde habitam os chacais, e nos teres coberto de trevas profundas.");
    b->dados[SALMOS].capitulos[44].versos[20] = _("Se nos tivéssemos esquecido do nome do nosso Deus, e estendido as nossas mãos para um deus estranho,");
    b->dados[SALMOS].capitulos[44].versos[21] = _("porventura Deus não haveria de esquadrinhar isso? pois ele conhece os segredos do coração.");
    b->dados[SALMOS].capitulos[44].versos[22] = _("Mas por amor de ti somos entregues à morte o dia todo; somos considerados como ovelhas para o matadouro.");
    b->dados[SALMOS].capitulos[44].versos[23] = _("Desperta! por que dormes, Senhor? Acorda! não nos rejeites para sempre.");
    b->dados[SALMOS].capitulos[44].versos[24] = _("Por que escondes o teu rosto, e te esqueces da nossa tribulação e da nossa angústia?");
    b->dados[SALMOS].capitulos[44].versos[25] = _("Pois a nossa alma está abatida até o pó; o nosso corpo pegado ao chão.");
    b->dados[SALMOS].capitulos[44].versos[26] = _("Levanta-te em nosso auxílio, e resgata-nos por tua benignidade.");

    b->dados[SALMOS].capitulos[45].versos[1] = _("O meu coração trasborda de boas palavras; dirijo os meus versos ao rei; a minha língua é qual pena de um hábil escriba.");
    b->dados[SALMOS].capitulos[45].versos[2] = _("Tu és o mais formoso dos filhos dos homens; a graça se derramou nos teus lábios; por isso Deus te abençoou para sempre.");
    b->dados[SALMOS].capitulos[45].versos[3] = _("Cinge a tua espada à coxa, ó valente, na tua glória e majestade.");
    b->dados[SALMOS].capitulos[45].versos[4] = _("E em tua majestade cavalga vitoriosamente pela causa da verdade, da mansidão e da justiça, e a tua destra te ensina coisas terríveis.");
    b->dados[SALMOS].capitulos[45].versos[5] = _("As tuas flechas são agudas no coração dos inimigos do rei; os povos caem debaixo de ti.");
    b->dados[SALMOS].capitulos[45].versos[6] = _("O teu trono, ó Deus, subsiste pelos séculos dos séculos; cetro de eqüidade é o cetro do teu reino.");
    b->dados[SALMOS].capitulos[45].versos[7] = _("Amaste a justiça e odiaste a iniqüidade; por isso Deus, o teu Deus, te ungiu com óleo de alegria, mais do que a teus companheiros.");
    b->dados[SALMOS].capitulos[45].versos[8] = _("Todas as tuas vestes cheiram a mirra a aloés e a cássia; dos palácios de marfim os instrumentos de cordas e te alegram.");
    b->dados[SALMOS].capitulos[45].versos[9] = _("Filhas de reis estão entre as tuas ilustres donzelas; à tua mão direita está a rainha, ornada de ouro de Ofir.");
    b->dados[SALMOS].capitulos[45].versos[10] = _("Ouve, filha, e olha, e inclina teus ouvidos; esquece-te do teu povo e da casa de teu pai.");
    b->dados[SALMOS].capitulos[45].versos[11] = _("Então o rei se afeiçoará à tua formosura. Ele é teu senhor, presta-lhe, pois, homenagem.");
    b->dados[SALMOS].capitulos[45].versos[12] = _("A filha de Tiro estará ali com presentes; os ricos do povo suplicarão o teu favor.");
    b->dados[SALMOS].capitulos[45].versos[13] = _("A filha do rei está esplendente lá dentro do palácio; as suas vestes são entretecidas de ouro.");
    b->dados[SALMOS].capitulos[45].versos[14] = _("Em vestidos de cores brilhantes será conduzida ao rei; as virgens, suas companheiras que a seguem, serão trazidas à tua presença.");
    b->dados[SALMOS].capitulos[45].versos[15] = _("Com alegria e regozijo serão trazidas; elas entrarão no palácio do rei.");
    b->dados[SALMOS].capitulos[45].versos[16] = _("Em lugar de teus pais estarão teus filhos; tu os farás príncipes sobre toda a terra.");
    b->dados[SALMOS].capitulos[45].versos[17] = _("Farei lembrado o teu nome de geração em geração; pelo que os povos te louvarão eternamente.");

    b->dados[SALMOS].capitulos[46].versos[1] = _("Deus é o nosso refúgio e fortaleza, socorro bem presente na angústia.");
    b->dados[SALMOS].capitulos[46].versos[2] = _("Pelo que não temeremos, ainda que a terra se mude, e ainda que os montes se projetem para o meio dos mares;");
    b->dados[SALMOS].capitulos[46].versos[3] = _("ainda que as águas rujam e espumem, ainda que os montes se abalem pela sua braveza.");
    b->dados[SALMOS].capitulos[46].versos[4] = _("Há um rio cujas correntes alegram a cidade de Deus, o lugar santo das moradas do Altíssimo.");
    b->dados[SALMOS].capitulos[46].versos[5] = _("Deus está no meio dela; não será abalada; Deus a ajudará desde o raiar da alva.");
    b->dados[SALMOS].capitulos[46].versos[6] = _("Bramam nações, reinos se abalam; ele levanta a sua voz, e a terra se derrete.");
    b->dados[SALMOS].capitulos[46].versos[7] = _("O Senhor dos exércitos está conosco; o Deus de Jacó é o nosso refúgio.");
    b->dados[SALMOS].capitulos[46].versos[8] = _("Vinde contemplai as obras do Senhor, as desolações que tem feito na terra.");
    b->dados[SALMOS].capitulos[46].versos[9] = _("Ele faz cessar as guerras até os confins da terra; quebra o arco e corta a lança; queima os carros no fogo.");
    b->dados[SALMOS].capitulos[46].versos[10] = _("Aquietai-vos, e sabei que eu sou Deus; sou exaltado entre as nações, sou exaltado na terra.");
    b->dados[SALMOS].capitulos[46].versos[11] = _("O Senhor dos exércitos está conosco; o Deus de Jacó é o nosso refúgio.");

    b->dados[SALMOS].capitulos[47].versos[1] = _("Batei palmas, todos os povos; aclamai a Deus com voz de júbilo.");
    b->dados[SALMOS].capitulos[47].versos[2] = _("Porque o Senhor Altíssimo é tremendo; é grande Rei sobre toda a terra.");
    b->dados[SALMOS].capitulos[47].versos[3] = _("Ele nos sujeitou povos e nações sob os nossos pés.");
    b->dados[SALMOS].capitulos[47].versos[4] = _("Escolheu para nós a nossa herança, a glória de Jacó, a quem amou.");
    b->dados[SALMOS].capitulos[47].versos[5] = _("Deus subiu entre aplausos, o Senhor subiu ao som de trombeta.");
    b->dados[SALMOS].capitulos[47].versos[6] = _("Cantai louvores a Deus, cantai louvores; cantai louvores ao nosso Rei, cantai louvores.");
    b->dados[SALMOS].capitulos[47].versos[7] = _("Pois Deus é o Rei de toda a terra; cantai louvores com salmo.");
    b->dados[SALMOS].capitulos[47].versos[8] = _("Deus reina sobre as nações; Deus está sentado sobre o seu santo trono.");
    b->dados[SALMOS].capitulos[47].versos[9] = _("Os príncipes dos povos se reúnem como povo do Deus de Abraão, porque a Deus pertencem os escudos da terra; ele é sumamente exaltado.");

    b->dados[SALMOS].capitulos[48].versos[1] = _("Grande é o Senhor e mui digno de ser louvado, na cidade do nosso Deus, no seu monte santo.");
    b->dados[SALMOS].capitulos[48].versos[2] = _("De bela e alta situação, alegria de toda terra é o monte Sião aos lados do norte, a cidade do grande Rei.");
    b->dados[SALMOS].capitulos[48].versos[3] = _("Nos palácios dela Deus se fez conhecer como alto refúgio.");
    b->dados[SALMOS].capitulos[48].versos[4] = _("Pois eis que os reis conspiraram; juntos vieram chegando.");
    b->dados[SALMOS].capitulos[48].versos[5] = _("Viram-na, e então ficaram maravilhados; ficaram assombrados e se apressaram em fugir.");
    b->dados[SALMOS].capitulos[48].versos[6] = _("Aí se apoderou deles o tremor, sentiram dores como as de uma parturiente.");
    b->dados[SALMOS].capitulos[48].versos[7] = _("Com um vento oriental quebraste as naus de Társis.");
    b->dados[SALMOS].capitulos[48].versos[8] = _("Como temos ouvido, assim vimos na cidade do Senhor dos exércitos, na cidade do nosso Deus; Deus a estabelece para sempre.");
    b->dados[SALMOS].capitulos[48].versos[9] = _("Temos meditado, ó Deus, na tua benignidade no meio do teu templo.");
    b->dados[SALMOS].capitulos[48].versos[10] = _("Como é o teu nome, ó Deus, assim é o teu louvor até os confins da terra; de retidão está cheia a tua destra.");
    b->dados[SALMOS].capitulos[48].versos[11] = _("Alegre-se o monte Sião, regozijem-se as filhas de Judá, por causa dos teus juízos.");
    b->dados[SALMOS].capitulos[48].versos[12] = _("Dai voltas a Sião, ide ao redor dela; contai as suas torres.");
    b->dados[SALMOS].capitulos[48].versos[13] = _("Notai bem os seus antemuros, percorrei os seus palácios, para que tudo narreis à geração seguinte.");
    b->dados[SALMOS].capitulos[48].versos[14] = _("Porque este Deus é o nosso Deus para todo o sempre; ele será nosso guia até a morte.");

    b->dados[SALMOS].capitulos[49].versos[1] = _("Ouvi isto, vós todos os povos; inclinai os ouvidos, todos os habitantes do mundo,");
    b->dados[SALMOS].capitulos[49].versos[2] = _("quer humildes quer grandes, tanto ricos como pobres.");
    b->dados[SALMOS].capitulos[49].versos[3] = _("A minha boca falará a sabedoria, e a meditação do meu coração será de entendimento.");
    b->dados[SALMOS].capitulos[49].versos[4] = _("Inclinarei os meus ouvidos a uma parábola; decifrarei o meu enigma ao som da harpa.");
    b->dados[SALMOS].capitulos[49].versos[5] = _("Por que temeria eu nos dias da adversidade, ao cercar-me a iniqüidade dos meus perseguidores,");
    b->dados[SALMOS].capitulos[49].versos[6] = _("dos que confiam nos seus bens e se gloriam na multidão das suas riquezas?");
    b->dados[SALMOS].capitulos[49].versos[7] = _("Nenhum deles de modo algum pode remir a seu irmão, nem por ele dar um resgate a Deus,");
    b->dados[SALMOS].capitulos[49].versos[8] = _("{pois a redenção da sua vida é caríssima, de sorte que os seus recursos não dariam;}");
    b->dados[SALMOS].capitulos[49].versos[9] = _("para que continuasse a viver para sempre, e não visse a cova.");
    b->dados[SALMOS].capitulos[49].versos[10] = _("Sim, ele verá que até os sábios morrem, que perecem igualmente o néscio e o estúpido, e deixam a outros os seus bens.");
    b->dados[SALMOS].capitulos[49].versos[11] = _("O pensamento íntimo deles é que as suas casas são perpétuas e as suas habitações de geração em geração; dão às suas terras os seus próprios nomes.");
    b->dados[SALMOS].capitulos[49].versos[12] = _("Mas o homem, embora esteja em honra, não permanece; antes é como os animais que perecem.");
    b->dados[SALMOS].capitulos[49].versos[13] = _("Este é o destino dos que confiam em si mesmos; o fim dos que se satisfazem com as suas próprias palavras.");
    b->dados[SALMOS].capitulos[49].versos[14] = _("Como ovelhas são arrebanhados ao Seol; a morte os pastoreia; ao romper do dia os retos terão domínio sobre eles; e a sua formosura se consumirá no Seol, que lhes será por habitação.");
    b->dados[SALMOS].capitulos[49].versos[15] = _("Mas Deus remirá a minha alma do poder do Seol, pois me receberá.");
    b->dados[SALMOS].capitulos[49].versos[16] = _("Não temas quando alguém se enriquece, quando a glória da sua casa aumenta.");
    b->dados[SALMOS].capitulos[49].versos[17] = _("Pois, quando morrer, nada levará consigo; a sua glória não descerá após ele.");
    b->dados[SALMOS].capitulos[49].versos[18] = _("Ainda que ele, enquanto vivo, se considera feliz e os homens o louvam quando faz o bem a si mesmo,");
    b->dados[SALMOS].capitulos[49].versos[19] = _("ele irá ter com a geração de seus pais; eles nunca mais verão a luz");
    b->dados[SALMOS].capitulos[49].versos[20] = _("Mas o homem, embora esteja em honra, não permanece; antes é como os animais que perecem.");

    b->dados[SALMOS].capitulos[50].versos[1] = _("O Poderoso, o Senhor Deus, fala e convoca a terra desde o nascer do sol até o seu ocaso.");
    b->dados[SALMOS].capitulos[50].versos[2] = _("Desde Sião, a perfeição da formosura. Deus resplandece.");
    b->dados[SALMOS].capitulos[50].versos[3] = _("O nosso Deus vem, e não guarda silêncio; diante dele há um fogo devorador, e grande tormenta ao seu redor.");
    b->dados[SALMOS].capitulos[50].versos[4] = _("Ele intima os altos céus e a terra, para o julgamento do seu povo:");
    b->dados[SALMOS].capitulos[50].versos[5] = _("Congregai os meus santos, aqueles que fizeram comigo um pacto por meio de sacrifícios.");
    b->dados[SALMOS].capitulos[50].versos[6] = _("Os céus proclamam a justiça dele, pois Deus mesmo é Juiz.");
    b->dados[SALMOS].capitulos[50].versos[7] = _("Ouve, povo meu, e eu falarei; ouve, ó Israel, e eu te protestarei: Eu sou Deus, o teu Deus.");
    b->dados[SALMOS].capitulos[50].versos[8] = _("Não te repreendo pelos teus sacrifícios, pois os teus holocaustos estão de contínuo perante mim.");
    b->dados[SALMOS].capitulos[50].versos[9] = _("Da tua casa não aceitarei novilho, nem bodes dos teus currais.");
    b->dados[SALMOS].capitulos[50].versos[10] = _("Porque meu é todo animal da selva, e o gado sobre milhares de outeiros.");
    b->dados[SALMOS].capitulos[50].versos[11] = _("Conheço todas as aves dos montes, e tudo o que se move no campo é meu.");
    b->dados[SALMOS].capitulos[50].versos[12] = _("Se eu tivesse fome, não to diria pois meu é o mundo e a sua plenitude.");
    b->dados[SALMOS].capitulos[50].versos[13] = _("Comerei eu carne de touros? ou beberei sangue de bodes?");
    b->dados[SALMOS].capitulos[50].versos[14] = _("Oferece a Deus por sacrifício ações de graças, e paga ao Altíssimo os teus votos;");
    b->dados[SALMOS].capitulos[50].versos[15] = _("e invoca-me no dia da angústia; eu te livrarei, e tu me glorificarás.");
    b->dados[SALMOS].capitulos[50].versos[16] = _("Mas ao ímpio diz Deus: Que fazes tu em recitares os meus estatutos, e em tomares o meu pacto na tua boca,");
    b->dados[SALMOS].capitulos[50].versos[17] = _("visto que aborreces a correção, e lanças as minhas palavras para trás de ti?");
    b->dados[SALMOS].capitulos[50].versos[18] = _("Quando vês um ladrão, tu te comprazes nele; e tens parte com os adúlteros.");
    b->dados[SALMOS].capitulos[50].versos[19] = _("Soltas a tua boca para o mal, e a tua língua trama enganos.");
    b->dados[SALMOS].capitulos[50].versos[20] = _("Tu te sentas a falar contra teu irmão; difamas o filho de tua mãe.");
    b->dados[SALMOS].capitulos[50].versos[21] = _("Estas coisas tens feito, e eu me calei; pensavas que na verdade eu era como tu; mas eu te argüirei, e tudo te porei à vista.");
    b->dados[SALMOS].capitulos[50].versos[22] = _("Considerai pois isto, vós que vos esqueceis de Deus, para que eu não vos despedace, sem que haja quem vos livre.");
    b->dados[SALMOS].capitulos[50].versos[23] = _("Aquele que oferece por sacrifício ações de graças me glorifica; e àquele que bem ordena o seu caminho eu mostrarei a salvação de Deus.");

    b->dados[SALMOS].capitulos[51].versos[1] = _("Compadece-te de mim, ó Deus, segundo a tua benignidade; apaga as minhas tansgressões, segundo a multidão das tuas misericórdias.");
    b->dados[SALMOS].capitulos[51].versos[2] = _("Lava-me completamente da minha iniqüidade, e purifica-me do meu pecado.");
    b->dados[SALMOS].capitulos[51].versos[3] = _("Pois eu conheço as minhas transgressões, e o meu pecado está sempre diante de mim.");
    b->dados[SALMOS].capitulos[51].versos[4] = _("Contra ti, contra ti somente, pequei, e fiz o que é mau diante dos teus olhos; de sorte que és justificado em falares, e inculpável em julgares.");
    b->dados[SALMOS].capitulos[51].versos[5] = _("Eis que eu nasci em iniqüidade, e em pecado me concedeu minha mãe.");
    b->dados[SALMOS].capitulos[51].versos[6] = _("Eis que desejas que a verdade esteja no íntimo; faze-me, pois, conhecer a sabedoria no secreto da minha alma.");
    b->dados[SALMOS].capitulos[51].versos[7] = _("Purifica-me com hissopo, e ficarei limpo; lava-me, e ficarei mais alvo do que a neve.");
    b->dados[SALMOS].capitulos[51].versos[8] = _("Faze-me ouvir júbilo e alegria, para que se regozijem os ossos que esmagaste.");
    b->dados[SALMOS].capitulos[51].versos[9] = _("Esconde o teu rosto dos meus pecados, e apaga todas as minhas iniqüidades.");
    b->dados[SALMOS].capitulos[51].versos[10] = _("Cria em mim, ó Deus, um coração puro, e renova em mim um espírito estável.");
    b->dados[SALMOS].capitulos[51].versos[11] = _("Não me lances fora da tua presença, e não retire de mim o teu santo Espírito.");
    b->dados[SALMOS].capitulos[51].versos[12] = _("Restitui-me a alegria da tua salvação, e sustém-me com um espírito voluntário.");
    b->dados[SALMOS].capitulos[51].versos[13] = _("Então ensinarei aos transgressores os teus caminhos, e pecadores se converterão a ti.");
    b->dados[SALMOS].capitulos[51].versos[14] = _("Livra-me dos crimes de sangue, ó Deus, Deus da minha salvação, e a minha língua cantará alegremente a tua justiça.");
    b->dados[SALMOS].capitulos[51].versos[15] = _("Abre, Senhor, os meus lábios, e a minha boca proclamará o teu louvor.");
    b->dados[SALMOS].capitulos[51].versos[16] = _("Pois tu não te comprazes em sacrifícios; se eu te oferecesse holocaustos, tu não te deleitarias.");
    b->dados[SALMOS].capitulos[51].versos[17] = _("O sacrifício aceitável a Deus é o espírito quebrantado; ao coração quebrantado e contrito não desprezarás, ó Deus.");
    b->dados[SALMOS].capitulos[51].versos[18] = _("Faze o bem a Sião, segundo a tua boa vontade; edifica os muros de Jerusalém.");
    b->dados[SALMOS].capitulos[51].versos[19] = _("Então te agradarás de sacrifícios de justiça dos holocaustos e das ofertas queimadas; então serão oferecidos novilhos sobre o teu altar.");

    b->dados[SALMOS].capitulos[52].versos[1] = _("Por que te glorias na malícia, ó homem poderoso? pois a bondade de Deus subsiste em todo o tempo.");
    b->dados[SALMOS].capitulos[52].versos[2] = _("A tua língua maquina planos de destruição, como uma navalha afiada, ó tu que usas de dolo.");
    b->dados[SALMOS].capitulos[52].versos[3] = _("Tu amas antes o mal do que o bem, e o mentir do que o falar a verdade.");
    b->dados[SALMOS].capitulos[52].versos[4] = _("Amas todas as palavras devoradoras, ó língua fraudulenta.");
    b->dados[SALMOS].capitulos[52].versos[5] = _("Também Deus te esmagará para sempre; arrebatar-te-á e arrancar-te-á da tua habitação, e desarraigar-te-á da terra dos viventes.");
    b->dados[SALMOS].capitulos[52].versos[6] = _("Os justos o verão e temerão; e se rirão dele, dizendo:");
    b->dados[SALMOS].capitulos[52].versos[7] = _("Eis aqui o homem que não tomou a Deus por sua fortaleza; antes confiava na abundância das suas riquezas, e se fortalecia na sua perversidade.");
    b->dados[SALMOS].capitulos[52].versos[8] = _("Mas eu sou qual oliveira verde na casa de Deus; confio na bondade de Deus para sempre e eternamente.");
    b->dados[SALMOS].capitulos[52].versos[9] = _("Para sempre te louvarei, porque tu isso fizeste, e proclamarei o teu nome, porque é bom diante de teus santos.");

    b->dados[SALMOS].capitulos[53].versos[1] = _("Diz o néscio no seu coração: Não há Deus. Corromperam-se e cometeram abominável iniqüidade; não há quem faça o bem.");
    b->dados[SALMOS].capitulos[53].versos[2] = _("Deus olha lá dos céus para os filhos dos homens, para ver se há algum que tenha entendimento, que busque a Deus.");
    b->dados[SALMOS].capitulos[53].versos[3] = _("Desviaram-se todos, e juntamente se fizeram imundos; não há quem faça o bem, não há sequer um.");
    b->dados[SALMOS].capitulos[53].versos[4] = _("Acaso não têm conhecimento os que praticam a iniqüidade, os quais comem o meu povo como se comessem pão, e não invocam a Deus?");
    b->dados[SALMOS].capitulos[53].versos[5] = _("Eis que eles se acham em grande pavor onde não há motivo de pavor, porque Deus espalhará os ossos daqueles que se acampam contra ti; tu os confundirás, porque Deus os rejeitou.");
    b->dados[SALMOS].capitulos[53].versos[6] = _("Oxalá que de Sião viesse a salvação de Israel! Quando Deus fizer voltar os cativos do seu povo, então se regozijará Jacó e se alegrará Israel.");

    b->dados[SALMOS].capitulos[54].versos[1] = _("Salva-me, ó Deus, pelo teu nome, e faze-me justiça pelo teu poder.");
    b->dados[SALMOS].capitulos[54].versos[2] = _("Ó Deus, ouve a minha oração, dá ouvidos às palavras da minha boca.");
    b->dados[SALMOS].capitulos[54].versos[3] = _("Porque homens insolentes se levantam contra mim, e violentos procuram a minha vida; eles não põem a Deus diante de si.");
    b->dados[SALMOS].capitulos[54].versos[4] = _("Eis que Deus é o meu ajudador; o Senhor é quem sustenta a minha vida.");
    b->dados[SALMOS].capitulos[54].versos[5] = _("Faze recair o mal sobre os meus inimigos; destrói-os por tua verdade.");
    b->dados[SALMOS].capitulos[54].versos[6] = _("De livre vontade te oferecerei sacrifícios; louvarei o teu nome, ó Senhor, porque é bom.");
    b->dados[SALMOS].capitulos[54].versos[7] = _("Porque tu me livraste de toda a angústia; e os meus olhos viram a ruína dos meus inimigos.");

    b->dados[SALMOS].capitulos[55].versos[1] = _("Dá ouvidos, ó Deus, à minha oração, e não te escondas da minha súplica.");
    b->dados[SALMOS].capitulos[55].versos[2] = _("Atende-me, e ouve-me; agitado estou, e ando perplexo,");
    b->dados[SALMOS].capitulos[55].versos[3] = _("por causa do clamor do inimigo e da opressão do ímpio; pois lançam sobre mim iniqüidade, e com furor me perseguem.");
    b->dados[SALMOS].capitulos[55].versos[4] = _("O meu coração confrange-se dentro de mim, e terrores de morte sobre mim caíram.");
    b->dados[SALMOS].capitulos[55].versos[5] = _("Temor e tremor me sobrevêm, e o horror me envolveu.");
    b->dados[SALMOS].capitulos[55].versos[6] = _("Pelo que eu disse: Ah! quem me dera asas como de pomba! então voaria, e encontraria descanso.");
    b->dados[SALMOS].capitulos[55].versos[7] = _("Eis que eu fugiria para longe, e pernoitaria no deserto.");
    b->dados[SALMOS].capitulos[55].versos[8] = _("Apressar-me-ia a abrigar-me da fúria do vento e da tempestade.");
    b->dados[SALMOS].capitulos[55].versos[9] = _("Destrói, Senhor, confunde as suas línguas, pois vejo violência e contenda na cidade.");
    b->dados[SALMOS].capitulos[55].versos[10] = _("Dia e noite andam ao redor dela, sobre os seus muros; também iniqüidade e malícia estão no meio dela.");
    b->dados[SALMOS].capitulos[55].versos[11] = _("Há destruição lá dentro; opressão e fraude não se apartam das suas ruas.");
    b->dados[SALMOS].capitulos[55].versos[12] = _("Pois não é um inimigo que me afronta, então eu poderia suportá-lo; nem é um adversário que se exalta contra mim, porque dele poderia esconder-me;");
    b->dados[SALMOS].capitulos[55].versos[13] = _("mas és tu, homem meu igual, meu companheiro e meu amigo íntimo.");
    b->dados[SALMOS].capitulos[55].versos[14] = _("Conservávamos juntos tranqüilamente, e em companhia andávamos na casa de Deus.");
    b->dados[SALMOS].capitulos[55].versos[15] = _("A morte os assalte, e vivos desçam ao Seol; porque há maldade na sua morada, no seu próprio íntimo.");
    b->dados[SALMOS].capitulos[55].versos[16] = _("Mas eu invocarei a Deus, e o Senhor me salvará.");
    b->dados[SALMOS].capitulos[55].versos[17] = _("De tarde, de manhã e ao meio-dia me queixarei e me lamentarei; e ele ouvirá a minha voz.");
    b->dados[SALMOS].capitulos[55].versos[18] = _("Livrará em paz a minha vida, de modo que ninguém se aproxime de mim; pois há muitos que contendem contra mim.");
    b->dados[SALMOS].capitulos[55].versos[19] = _("Deus ouvirá; e lhes responderá aquele que está entronizado desde a antigüidade; porque não há neles nenhuma mudança, e tampouco temem a Deus.");
    b->dados[SALMOS].capitulos[55].versos[20] = _("Aquele meu companheiro estendeu a sua mão contra os que tinham paz com ele; violou o seu pacto.");
    b->dados[SALMOS].capitulos[55].versos[21] = _("A sua fala era macia como manteiga, mas no seu coração havia guerra; as suas palavras eram mais brandas do que o azeite, todavia eram espadas desembainhadas.");
    b->dados[SALMOS].capitulos[55].versos[22] = _("Lança o teu fardo sobre o Senhor, e ele te susterá; nunca permitirá que o justo seja abalado.");
    b->dados[SALMOS].capitulos[55].versos[23] = _("Mas tu, ó Deus, os farás descer ao poço da perdição; homens de sangue e de traição não viverão metade dos seus dias; mas eu em ti confiarei.");

    b->dados[SALMOS].capitulos[56].versos[1] = _("Compadece-te de mim, ó Deus, pois homens me calcam aos pés e, pelejando, me aflingem o dia todo.");
    b->dados[SALMOS].capitulos[56].versos[2] = _("Os meus inimigos me calcam aos pés o dia todo, pois são muitos os que insolentemente pelejam contra mim.");
    b->dados[SALMOS].capitulos[56].versos[3] = _("No dia em que eu temer, hei de confiar em ti.");
    b->dados[SALMOS].capitulos[56].versos[4] = _("Em Deus, cuja palavra eu louvo, em Deus ponho a minha confiança e não terei medo;");
    b->dados[SALMOS].capitulos[56].versos[5] = _("Todos os dias torcem as minhas palavras; todos os seus pensamentos são contra mim para o mal.");
    b->dados[SALMOS].capitulos[56].versos[6] = _("Ajuntam-se, escondem-se, espiam os meus passos, como que aguardando a minha morte.");
    b->dados[SALMOS].capitulos[56].versos[7] = _("Escaparão eles por meio da sua iniqüidade? Ó Deus, derruba os povos na tua ira!");
    b->dados[SALMOS].capitulos[56].versos[8] = _("Tu contaste as minhas aflições; põe as minhas lágrimas no teu odre; não estão elas no teu livro?");
    b->dados[SALMOS].capitulos[56].versos[9] = _("No dia em que eu te invocar retrocederão os meus inimigos; isto eu sei, que Deus está comigo.");
    b->dados[SALMOS].capitulos[56].versos[10] = _("Em Deus, cuja palavra eu louvo, no Senhor, cuja palavra eu louvo,");
    b->dados[SALMOS].capitulos[56].versos[11] = _("em Deus ponho a minha confiança, e não terei medo; que me pode fazer o homem?");
    b->dados[SALMOS].capitulos[56].versos[12] = _("Sobre mim estão os votos que te fiz, ó Deus; eu te oferecerei ações de graças;");
    b->dados[SALMOS].capitulos[56].versos[13] = _("pois tu livraste a minha alma da morte. Não livraste também os meus pés de tropeçarem, para que eu ande diante de Deus na luz da vida?");

    b->dados[SALMOS].capitulos[57].versos[1] = _("Compadece-te de mim, ó Deus, compadece-te de mim, pois em ti se refugia a minha alma; à sombra das tuas asas me refugiarei, até que passem as calamidades.");
    b->dados[SALMOS].capitulos[57].versos[2] = _("Clamarei ao Deus altíssimo, ao Deus que por mim tudo executa.");
    b->dados[SALMOS].capitulos[57].versos[3] = _("Ele do céu enviará seu auxílio , e me salvará, quando me ultrajar aquele que quer calçar-me aos pés. Deus enviará a sua misericórdia e a sua verdade.");
    b->dados[SALMOS].capitulos[57].versos[4] = _("Estou deitado no meio de leões; tenho que deitar-me no meio daqueles que respiram chamas, filhos dos homens, cujos dentes são lanças e flechas, e cuja língua é espada afiada.");
    b->dados[SALMOS].capitulos[57].versos[5] = _("Sê exaltado, ó Deus, acima dos céus; seja a tua glória sobre toda a terra.");
    b->dados[SALMOS].capitulos[57].versos[6] = _("Armaram um laço para os meus passos, a minha alma ficou abatida; cavaram uma cova diante de mim, mas foram eles que nela caíram.");
    b->dados[SALMOS].capitulos[57].versos[7] = _("Resoluto está o meu coração, ó Deus, resoluto está o meu coração; cantarei, sim, cantarei louvores.");
    b->dados[SALMOS].capitulos[57].versos[8] = _("Desperta, minha alma; despertai, alaúde e harpa; eu mesmo despertarei a aurora.");
    b->dados[SALMOS].capitulos[57].versos[9] = _("Louvar-te-ei, Senhor, entre os povos; cantar-te-ei louvores entre as nações.");
    b->dados[SALMOS].capitulos[57].versos[10] = _("Pois a tua benignidade é grande até os céus, e a tua verdade até as nuvens.");
    b->dados[SALMOS].capitulos[57].versos[11] = _("Sê exaltado, ó Deus, acima dos céus; e seja a tua glória sobre a terra.");

    b->dados[SALMOS].capitulos[58].versos[1] = _("Falais deveras o que é reto, vós os poderosos? Julgais retamente, ó filhos dos homens?");
    b->dados[SALMOS].capitulos[58].versos[2] = _("Não, antes no coração forjais iniqüidade; sobre a terra fazeis pesar a violência das vossas mãos.");
    b->dados[SALMOS].capitulos[58].versos[3] = _("Alienam-se os ímpios desde a madre; andam errados desde que nasceram, proferindo mentiras.");
    b->dados[SALMOS].capitulos[58].versos[4] = _("Têm veneno semelhante ao veneno da serpente; são como a víbora surda, que tapa os seus ouvidos,");
    b->dados[SALMOS].capitulos[58].versos[5] = _("de sorte que não ouve a voz dos encantadores, nem mesmo do encantador perito em encantamento.");
    b->dados[SALMOS].capitulos[58].versos[6] = _("Ó Deus, quebra-lhes os dentes na sua boca; arranca, Senhor, os caninos aos filhos dos leões.");
    b->dados[SALMOS].capitulos[58].versos[7] = _("Sumam-se como águas que se escoam; sejam pisados e murcham como a relva macia.");
    b->dados[SALMOS].capitulos[58].versos[8] = _("Sejam como a lesma que se derrete e se vai; como o aborto de mulher, que nunca viu o sol.");
    b->dados[SALMOS].capitulos[58].versos[9] = _("Que ele arrebate os espinheiros antes que cheguem a aquecer as vossas panelas, assim os verdes, como os que estão ardendo.");
    b->dados[SALMOS].capitulos[58].versos[10] = _("O justo se alegrará quando vir a vingança; lavará os seus pés no sangue do ímpio.");
    b->dados[SALMOS].capitulos[58].versos[11] = _("Então dirão os homens: Deveras há uma recompensa para o justo; deveras há um Deus que julga na terra.");

    b->dados[SALMOS].capitulos[59].versos[1] = _("Livra-me, Deus meu, dos meus inimigos; protege-me daqueles que se levantam contra mim.");
    b->dados[SALMOS].capitulos[59].versos[2] = _("Livra-me do que praticam a iniqüidade, e salva-me dos homens sanguinários.");
    b->dados[SALMOS].capitulos[59].versos[3] = _("Pois eis que armam ciladas à minha alma; os fortes se ajuntam contra mim, não por transgressão minha nem por pecado meu, ó Senhor.");
    b->dados[SALMOS].capitulos[59].versos[4] = _("Eles correm, e se preparam, sem culpa minha; desperta para me ajudares, e olha.");
    b->dados[SALMOS].capitulos[59].versos[5] = _("Tu, ó Senhor, Deus dos exércitos, Deus de Israel, desperta para punir todas as nações; não tenhas misericórdia de nenhum dos pérfidos que praticam a iniqüidade.");
    b->dados[SALMOS].capitulos[59].versos[6] = _("Eles voltam à tarde, uivam como cães, e andam rodeando a cidade.");
    b->dados[SALMOS].capitulos[59].versos[7] = _("Eis que eles soltam gritos; espadas estão nos seus lábios; porque {pensam eles}, quem ouve?");
    b->dados[SALMOS].capitulos[59].versos[8] = _("Mas tu, Senhor, te rirás deles; zombarás de todas as nações.");
    b->dados[SALMOS].capitulos[59].versos[9] = _("Em ti, força minha, esperarei; pois Deus é o meu alto refúgio.");
    b->dados[SALMOS].capitulos[59].versos[10] = _("O meu Deus com a sua benignidade virá ao meu encontro; Deus me fará ver o meu desejo sobre os meus inimigos.");
    b->dados[SALMOS].capitulos[59].versos[11] = _("Não os mates, para que meu povo não se esqueça; espalha-os pelo teu poder, e abate-os ó Senhor, escudo nosso.");
    b->dados[SALMOS].capitulos[59].versos[12] = _("Pelo pecado da sua boca e pelas palavras dos seus lábios fiquem presos na sua soberba. Pelas maldições e pelas mentiras que proferem,");
    b->dados[SALMOS].capitulos[59].versos[13] = _("consome-os na tua indignação; consome-os, de modo que não existem mais; para que saibam que Deus reina sobre Jacó, até os confins da terra.");
    b->dados[SALMOS].capitulos[59].versos[14] = _("Eles tornam a vir à tarde, uivam como cães, e andam rodeando a cidade;");
    b->dados[SALMOS].capitulos[59].versos[15] = _("vagueiam buscando o que comer, e resmungam se não se fartarem.");
    b->dados[SALMOS].capitulos[59].versos[16] = _("Eu, porém, cantarei a tua força; pela manhã louvarei com alegria a tua benignidade, porquanto tens sido para mim uma fortaleza, e refúgio no dia da minha angústia.");
    b->dados[SALMOS].capitulos[59].versos[17] = _("A ti, ó força minha, cantarei louvores; porque Deus é a minha fortaleza, é o Deus que me mostra benignidade.");

    b->dados[SALMOS].capitulos[60].versos[1] = _("Ó Deus, tu nos rejeitaste, tu nos esmagaste, tu tens estado indignado; oh, restabelece-nos.");
    b->dados[SALMOS].capitulos[60].versos[2] = _("Abalaste a terra, e a fendeste; sara as suas fendas, pois ela treme.");
    b->dados[SALMOS].capitulos[60].versos[3] = _("Ao teu povo fizeste ver duras coisas; fizeste-nos beber o vinho de aturdimento.");
    b->dados[SALMOS].capitulos[60].versos[4] = _("Deste um estandarte aos que te temem, para o qual possam fugir de diante do arco.");
    b->dados[SALMOS].capitulos[60].versos[5] = _("Para que os teus amados sejam livres, salva-nos com a tua destra, e responde-nos.");
    b->dados[SALMOS].capitulos[60].versos[6] = _("Deus falou na sua santidade: Eu exultarei; repartirei Siquém e medirei o vale de Sucote.");
    b->dados[SALMOS].capitulos[60].versos[7] = _("Meu é Gileade, e meu é Manassés; Efraim é o meu capacete; Judá é o meu cetro.");
    b->dados[SALMOS].capitulos[60].versos[8] = _("Moabe é a minha bacia de lavar; sobre Edom lançarei o meu sapato; sobre a Filístia darei o brado de vitória.");
    b->dados[SALMOS].capitulos[60].versos[9] = _("Quem me conduzirá à cidade forte? Quem me guiará até Edom?");
    b->dados[SALMOS].capitulos[60].versos[10] = _("Não nos rejeitaste, ó Deus? e tu, ó Deus, não deixaste de sair com os nossos exércitos?");
    b->dados[SALMOS].capitulos[60].versos[11] = _("Dá-nos auxílio contra o adversário, pois vão é o socorro da parte do homem.");
    b->dados[SALMOS].capitulos[60].versos[12] = _("Em Deus faremos proezas; porque é ele quem calcará aos pés os nossos inimigos.");

    b->dados[SALMOS].capitulos[61].versos[1] = _("Ouve, ó Deus, o meu clamor; atende à minha oração.");
    b->dados[SALMOS].capitulos[61].versos[2] = _("Desde a extremidade da terra clamo a ti, estando abatido o meu coração; leva-me para a rocha que é mais alta do que eu.");
    b->dados[SALMOS].capitulos[61].versos[3] = _("Pois tu és o meu refúgio, uma torre forte contra o inimigo.");
    b->dados[SALMOS].capitulos[61].versos[4] = _("Deixa-me habitar no teu tabernáculo para sempre; dá que me abrigue no esconderijo das tuas asas.");
    b->dados[SALMOS].capitulos[61].versos[5] = _("Pois tu, ó Deus, ouviste os meus votos; deste-me a herança dos que temem o teu nome.");
    b->dados[SALMOS].capitulos[61].versos[6] = _("Prolongarás os dias do rei; e os seus anos serão como muitas gerações.");
    b->dados[SALMOS].capitulos[61].versos[7] = _("Ele permanecerá no trono diante de Deus para sempre; faze que a benignidade e a fidelidade o preservem.");
    b->dados[SALMOS].capitulos[61].versos[8] = _("Assim cantarei louvores ao teu nome perpetuamente, para pagar os meus votos de dia em dia.");

    b->dados[SALMOS].capitulos[62].versos[1] = _("Somente em Deus espera silenciosa a minha alma; dele vem a minha salvação.");
    b->dados[SALMOS].capitulos[62].versos[2] = _("Só ele é a minha rocha e a minha salvação; é ele a minha fortaleza; não serei grandemente abalado.");
    b->dados[SALMOS].capitulos[62].versos[3] = _("Até quando acometereis um homem, todos vós, para o derrubardes, como a um muro pendido, uma cerca prestes a cair?");
    b->dados[SALMOS].capitulos[62].versos[4] = _("Eles somente consultam como derrubá-lo da sua alta posição; deleitam-se em mentiras; com a boca bendizem, mas no íntimo maldizem.");
    b->dados[SALMOS].capitulos[62].versos[5] = _("Ó minha alma, espera silenciosa somente em Deus, porque dele vem a minha esperança.");
    b->dados[SALMOS].capitulos[62].versos[6] = _("Só ele é a minha rocha e a minha salvação; é a minha fortaleza; não serei abalado.");
    b->dados[SALMOS].capitulos[62].versos[7] = _("Em Deus está a minha salvação e a minha glória; Deus é o meu forte rochedo e o meu refúgio.");
    b->dados[SALMOS].capitulos[62].versos[8] = _("Confiai nele, ó povo, em todo o tempo; derramai perante ele o vosso coração; Deus é o nosso refúgio.");
    b->dados[SALMOS].capitulos[62].versos[9] = _("Certamente que os filhos de Adão são vaidade, e os filhos dos homens são desilusão; postos na balança, subiriam; todos juntos são mais leves do que um sopro.");
    b->dados[SALMOS].capitulos[62].versos[10] = _("Não confieis na opressão, nem vos vanglorieis na rapina; se as vossas riquezas aumentarem, não ponhais nelas o coração.");
    b->dados[SALMOS].capitulos[62].versos[11] = _("Uma vez falou Deus, duas vezes tenho ouvido isto: que o poder pertence a Deus.");
    b->dados[SALMOS].capitulos[62].versos[12] = _("A ti também, Senhor, pertence a benignidade; pois retribuis a cada um segundo a sua obra.");

    b->dados[SALMOS].capitulos[63].versos[1] = _("Ó Deus, tu és o meu Deus; ansiosamente te busco. A minha alma tem sede de ti; a minha carne te deseja muito em uma terra seca e cansada, onde não há água.");
    b->dados[SALMOS].capitulos[63].versos[2] = _("Assim no santuário te contemplo, para ver o teu poder e a tua glória.");
    b->dados[SALMOS].capitulos[63].versos[3] = _("Porquanto a tua benignidade é melhor do que a vida, os meus lábios te louvarão.");
    b->dados[SALMOS].capitulos[63].versos[4] = _("Assim eu te bendirei enquanto viver; em teu nome levantarei as minhas mãos.");
    b->dados[SALMOS].capitulos[63].versos[5] = _("A minha alma se farta, como de tutano e de gordura; e a minha boca te louva com alegres lábios.");
    b->dados[SALMOS].capitulos[63].versos[6] = _("quando me lembro de ti no meu leito, e medito em ti nas vigílias da noite,");
    b->dados[SALMOS].capitulos[63].versos[7] = _("pois tu tens sido o meu auxílio; de júbilo canto à sombra das tuas asas.");
    b->dados[SALMOS].capitulos[63].versos[8] = _("A minha alma se apega a ti; a tua destra me sustenta.");
    b->dados[SALMOS].capitulos[63].versos[9] = _("Mas aqueles que procuram a minha vida para a destruírem, irão para as profundezas da terra.");
    b->dados[SALMOS].capitulos[63].versos[10] = _("Serão entregues ao poder da espada, servidão de pasto aos chacais.");
    b->dados[SALMOS].capitulos[63].versos[11] = _("Mas o rei se regozijará em Deus; todo o que por ele jura se gloriará, porque será tapada a boca aos que falam a mentira.");

    b->dados[SALMOS].capitulos[64].versos[1] = _("Ouve, ó Deus, a minha voz na minha queixa; preserva a minha voz na minha queixa; preserva a minha vida do horror do inimigo.");
    b->dados[SALMOS].capitulos[64].versos[2] = _("Esconde-me do secreto conselho dos maus, e do ajuntamento dos que praticam a iniqüidade,");
    b->dados[SALMOS].capitulos[64].versos[3] = _("os quais afiaram a sua língua como espada, e armaram por suas flechas palavras amargas.");
    b->dados[SALMOS].capitulos[64].versos[4] = _("Para em lugares ocultos atirarem sobre o íntegro; disparam sobre ele repentinamente, e não temem.");
    b->dados[SALMOS].capitulos[64].versos[5] = _("Firmam-se em mau intento; falam de armar laços secretamente, e dizem: Quem nos verá?");
    b->dados[SALMOS].capitulos[64].versos[6] = _("Planejam iniqüidades; ocultam planos bem traçados; pois o íntimo e o coração do homem são inescrutáveis.");
    b->dados[SALMOS].capitulos[64].versos[7] = _("Mas Deus disparará sobre eles uma seta, e de repente ficarão feridos.");
    b->dados[SALMOS].capitulos[64].versos[8] = _("Assim serão levados a tropeçar, por causa das suas próprias línguas; todos aqueles que os virem fugirão.");
    b->dados[SALMOS].capitulos[64].versos[9] = _("E todos os homens temerão, e anunciarão a obra de Deus, e considerarão a obra de Deus, e considerarão prudentemente os seus feitos.");
    b->dados[SALMOS].capitulos[64].versos[10] = _("O justo se alegrará no Senhor e confiará nele, e todos os de coração reto cantarão louvores.");

    b->dados[SALMOS].capitulos[65].versos[1] = _("A ti, ó Deus, é devido o louvor em Sião; e a ti se pagará o voto.");
    b->dados[SALMOS].capitulos[65].versos[2] = _("Ó tu que ouves a oração! a ti virá toda a carne.");
    b->dados[SALMOS].capitulos[65].versos[3] = _("Prevalecem as iniqüidades contra mim; mas as nossas transgressões, tu as perdoarás.");
    b->dados[SALMOS].capitulos[65].versos[4] = _("Bem-aventurado aquele a quem tu escolhes, e fazes chegar a ti, para habitar em teus átrios! Nós seremos satisfeitos com a bondade da tua casa, do teu santo templo.");
    b->dados[SALMOS].capitulos[65].versos[5] = _("Com prodígios nos respondes em justiça, ó Deus da nossa salvação, a esperança de todas as extremidades da terra, e do mais remoto mar;");
    b->dados[SALMOS].capitulos[65].versos[6] = _("tu que pela tua força consolidas os montes, cingido de poder;");
    b->dados[SALMOS].capitulos[65].versos[7] = _("que aplacas o ruído dos mares, o ruído das suas ondas, e o tumulto dos povos.");
    b->dados[SALMOS].capitulos[65].versos[8] = _("Os que habitam os confins da terra são tomados de medo à vista dos teus sinais; tu fazes exultar de júbilo as saídas da manhã e da tarde.");
    b->dados[SALMOS].capitulos[65].versos[9] = _("Tu visitas a terra, e a regas; grandemente e enriqueces; o rio de Deus está cheio d'água; tu lhe dás o trigo quando assim a tens preparado;");
    b->dados[SALMOS].capitulos[65].versos[10] = _("enches d'água os seus sulcos, aplanando-lhes as leivas, amolecendo-a com a chuva, e abençoando as suas novidades.");
    b->dados[SALMOS].capitulos[65].versos[11] = _("Coroas o ano com a tua bondade, e as tuas veredas destilam gordura;");
    b->dados[SALMOS].capitulos[65].versos[12] = _("destilam sobre as pastagens do deserto, e os outeiros se cingem de alegria.");
    b->dados[SALMOS].capitulos[65].versos[13] = _("As pastagens revestem-se de rebanhos, e os vales se cobrem de trigo; por isso eles se regozijam, por isso eles cantam.");

    b->dados[SALMOS].capitulos[66].versos[1] = _("Louvai a Deus com brados de júbilo, todas as terras.");
    b->dados[SALMOS].capitulos[66].versos[2] = _("Cantai a glória do seu nome, dai glória em seu louvor.");
    b->dados[SALMOS].capitulos[66].versos[3] = _("Dizei a Deus: Quão tremendas são as tuas obras! pela grandeza do teu poder te lisonjeiam os teus inimigos.");
    b->dados[SALMOS].capitulos[66].versos[4] = _("Toda a terra te adorará e te cantará louvores; eles cantarão o teu nome.");
    b->dados[SALMOS].capitulos[66].versos[5] = _("Vinde, e vede as obras de Deus; ele é tremendo nos seus feitos para com os filhos dos homens.");
    b->dados[SALMOS].capitulos[66].versos[6] = _("Converteu o mar em terra seca; passaram o rio a pé; ali nos alegramos nele.");
    b->dados[SALMOS].capitulos[66].versos[7] = _("Ele governa eternamente pelo seu poder; os seus olhos estão sobre as nações; não se exaltem os rebeldes.");
    b->dados[SALMOS].capitulos[66].versos[8] = _("Bendizei, povos, ao nosso Deus, e fazei ouvir a voz do seu louvor;");
    b->dados[SALMOS].capitulos[66].versos[9] = _("ao que nos conserva em vida, e não consente que resvalem os nossos pés.");
    b->dados[SALMOS].capitulos[66].versos[10] = _("Pois tu, ó Deus, nos tens provado; tens nos refinado como se refina a prata.");
    b->dados[SALMOS].capitulos[66].versos[11] = _("Fizeste-nos entrar no laço; pesada carga puseste sobre os nossos lombos.");
    b->dados[SALMOS].capitulos[66].versos[12] = _("Fizeste com que os homens cavalgassem sobre as nossas cabeças; passamos pelo fogo e pela água, mas nos trouxeste a um lugar de abundância.");
    b->dados[SALMOS].capitulos[66].versos[13] = _("Entregarei em tua casa com holocaustos; pagar-te-ei os meus votos,");
    b->dados[SALMOS].capitulos[66].versos[14] = _("votos que os meus lábios pronunciaram e a minha boca prometeu, quando eu estava na angústia.");
    b->dados[SALMOS].capitulos[66].versos[15] = _("Oferecer-te-ei holocausto de animais nédios, com incenso de carneiros; prepararei novilhos com cabritos.");
    b->dados[SALMOS].capitulos[66].versos[16] = _("Vinde, e ouvi, todos os que temeis a Deus, e eu contarei o que ele tem feito por mim.");
    b->dados[SALMOS].capitulos[66].versos[17] = _("A ele clamei com a minha boca, e ele foi exaltado pela minha língua.");
    b->dados[SALMOS].capitulos[66].versos[18] = _("Se eu tivesse guardado iniqüidade no meu coração, o Senhor não me teria ouvido;");
    b->dados[SALMOS].capitulos[66].versos[19] = _("mas, na verdade, Deus me ouviu; tem atendido à voz da minha oração.");
    b->dados[SALMOS].capitulos[66].versos[20] = _("Bendito seja Deus, que não rejeitou a minha oração, nem retirou de mim a sua benignidade.");

    b->dados[SALMOS].capitulos[67].versos[1] = _("Deus se compadeça de nós e nos abençoe, e faça resplandecer o seu rosto sobre nós,");
    b->dados[SALMOS].capitulos[67].versos[2] = _("para que se conheça na terra o seu caminho e entre todas as nações a sua salvação.");
    b->dados[SALMOS].capitulos[67].versos[3] = _("Louvem-te, ó Deus, os povos; louvem-te os povos todos.");
    b->dados[SALMOS].capitulos[67].versos[4] = _("Alegrem-se e regozijem-se as nações, pois julgas os povos com eqüidade, e guias as nações sobre a terra.");
    b->dados[SALMOS].capitulos[67].versos[5] = _("Louvem-te, ó Deus, os povos; louvem os povos todos.");
    b->dados[SALMOS].capitulos[67].versos[6] = _("A terra tem produzido o seu fruto; e Deus, o nosso Deus, tem nos abençoado.");
    b->dados[SALMOS].capitulos[67].versos[7] = _("Deus nos tem abençoado; temam-no todas as extremidades da terra!");

    b->dados[SALMOS].capitulos[68].versos[1] = _("Levanta-se Deus! Sejam dispersos os seus inimigos; fujam de diante dele os que o odeiam!");
    b->dados[SALMOS].capitulos[68].versos[2] = _("Como é impelida a fumaça, assim tu os impeles; como a cera se derrete diante do fogo, assim pereçam os ímpios diante de Deus.");
    b->dados[SALMOS].capitulos[68].versos[3] = _("Mas alegrem-se os justos, e se regozijem na presença de Deus, e se encham de júbilo.");
    b->dados[SALMOS].capitulos[68].versos[4] = _("Cantai a Deus, cantai louvores ao seu nome; louvai aquele que cavalga sobre as nuvens, pois o seu nome é Já; exultai diante dele.");
    b->dados[SALMOS].capitulos[68].versos[5] = _("Pai de órfãos e juiz de viúvas é Deus na sua santa morada.");
    b->dados[SALMOS].capitulos[68].versos[6] = _("Deus faz que o solitário viva em família; liberta os presos e os faz prosperar; mas os rebeldes habitam em terra árida.");
    b->dados[SALMOS].capitulos[68].versos[7] = _("Ó Deus! quando saías à frente do teu povo, quando caminhavas pelo deserto,");
    b->dados[SALMOS].capitulos[68].versos[8] = _("a terra se abalava e os céus gotejavam perante a face de Deus; o próprio Sinai tremeu na presença de Deus, do Deus de Israel.");
    b->dados[SALMOS].capitulos[68].versos[9] = _("Tu, ó Deus, mandaste copiosa chuva; restauraste a tua herança, quando estava cansada.");
    b->dados[SALMOS].capitulos[68].versos[10] = _("Nela habitava o teu rebanho; da tua bondade, ó Deus, proveste o pobre.");
    b->dados[SALMOS].capitulos[68].versos[11] = _("O Senhor proclama a palavra; grande é a companhia dos que anunciam as boas-novas.");
    b->dados[SALMOS].capitulos[68].versos[12] = _("Reis de exércitos fogem, sim, fogem; as mulheres em casa repartem os despojos.");
    b->dados[SALMOS].capitulos[68].versos[13] = _("Deitados entre redis, sois como as asas da pomba cobertas de prata, com as suas penas de ouro amarelo.");
    b->dados[SALMOS].capitulos[68].versos[14] = _("Quando o Todo-Poderoso ali dispersou os reis, caiu neve em Zalmom.");
    b->dados[SALMOS].capitulos[68].versos[15] = _("Monte grandíssimo é o monte de Basã; monte de cimos numerosos é o monte de Basã!");
    b->dados[SALMOS].capitulos[68].versos[16] = _("Por que estás, ó monte de cimos numerosos, olhando com inveja o monte que Deus desejou para sua habitação? Na verdade o Senhor habitará nele eternamente.");
    b->dados[SALMOS].capitulos[68].versos[17] = _("Os carros de Deus são miríades, milhares de milhares. O Senhor está no meio deles, como em Sinai no santuário.");
    b->dados[SALMOS].capitulos[68].versos[18] = _("Tu subiste ao alto, levando os teus cativos; recebeste dons dentre os homens, e até dentre os rebeldes, para que o Senhor Deus habitasse entre eles.");
    b->dados[SALMOS].capitulos[68].versos[19] = _("Bendito seja o Senhor, que diariamente leva a nossa carga, o Deus que é a nossa salvação.");
    b->dados[SALMOS].capitulos[68].versos[20] = _("Deus é para nós um Deus de libertação; a Jeová, o Senhor, pertence o livramento da morte.");
    b->dados[SALMOS].capitulos[68].versos[21] = _("Mas Deus esmagará a cabeça de seus inimigos, o crânio cabeludo daquele que prossegue em suas culpas.");
    b->dados[SALMOS].capitulos[68].versos[22] = _("Disse o Senhor: Eu os farei voltar de Basã; fá-los-ei voltar das profundezas do mar;");
    b->dados[SALMOS].capitulos[68].versos[23] = _("para que mergulhes o teu pé em sangue, e para que a língua dos teus cães tenha dos inimigos o seu quinhão.");
    b->dados[SALMOS].capitulos[68].versos[24] = _("Viu-se, ó Deus, a tua entrada, a entrada do meu Deus, meu Rei, no santuário.");
    b->dados[SALMOS].capitulos[68].versos[25] = _("Iam na frente os cantores, atrás os tocadores de instrumentos, no meio as donzelas que tocavam adufes.");
    b->dados[SALMOS].capitulos[68].versos[26] = _("Bendizei a Deus nas congregações, ao Senhor, vós que sois da fonte de Israel.");
    b->dados[SALMOS].capitulos[68].versos[27] = _("Ali está Benjamim, o menor deles, na frente; os chefes de Judá com o seu ajuntamento; os chefes de Judá com o seu ajuntamento; os chefes de Zebulom e os chefes de Naftali.");
    b->dados[SALMOS].capitulos[68].versos[28] = _("Ordena, ó Deus, a tua força; confirma, ó Deus, o que já fizeste por nós.");
    b->dados[SALMOS].capitulos[68].versos[29] = _("Por amor do teu templo em Jerusalém, os reis te trarão presentes.");
    b->dados[SALMOS].capitulos[68].versos[30] = _("Repreende as feras dos caniçais, a multidão dos touros, com os bezerros dos povos. Calca aos pés as suas peças de prata; dissipa os povos que se deleitam na guerra.");
    b->dados[SALMOS].capitulos[68].versos[31] = _("Venham embaixadores do Egito; estenda a Etiópia ansiosamente as mãos para Deus.");
    b->dados[SALMOS].capitulos[68].versos[32] = _("Reinos da terra, cantai a Deus, cantai louvores ao Senhor,");
    b->dados[SALMOS].capitulos[68].versos[33] = _("àquele que vai montado sobre os céus dos céus, que são desde a antigüidade; eis que faz ouvir a sua voz, voz veemente.");
    b->dados[SALMOS].capitulos[68].versos[34] = _("Atribuí a Deus força; sobre Israel está a sua excelência, e a sua força nos firmamento.");
    b->dados[SALMOS].capitulos[68].versos[35] = _("Ó Deus, tu és tremendo desde o teu santuário; o Deus de Israel, ele dá força e poder ao seu povo. Bendito seja Deus!");

    b->dados[SALMOS].capitulos[69].versos[1] = _("Salva-me, ó Deus, pois as águas me sobem até o pescoço.");
    b->dados[SALMOS].capitulos[69].versos[2] = _("Atolei-me em profundo lamaçal, onde não se pode firmar o pé; entrei na profundeza das águas, onde a corrente me submerge.");
    b->dados[SALMOS].capitulos[69].versos[3] = _("Estou cansado de clamar; secou-se-me a garganta; os meus olhos desfalecem de esperar por meu Deus.");
    b->dados[SALMOS].capitulos[69].versos[4] = _("Aqueles que me odeiam sem causa são mais do que os cabelos da minha cabeça; poderosos são aqueles que procuram destruir-me, que me atacam com mentiras; por isso tenho de restituir o que não extorqui.");
    b->dados[SALMOS].capitulos[69].versos[5] = _("Tu, ó Deus, bem conheces a minha estultícia, e as minhas culpas não são ocultas.");
    b->dados[SALMOS].capitulos[69].versos[6] = _("Não sejam envergonhados por minha causa aqueles que esperam em ti, ó Senhor Deus dos exércitos; não sejam confundidos por minha causa aqueles que te buscam, ó Deus de Israel.");
    b->dados[SALMOS].capitulos[69].versos[7] = _("Porque por amor de ti tenho suportado afrontas; a confusão me cobriu o rosto.");
    b->dados[SALMOS].capitulos[69].versos[8] = _("Tornei-me como um estranho para os meus irmãos, e um desconhecido para os filhos de minha mãe.");
    b->dados[SALMOS].capitulos[69].versos[9] = _("Pois o zelo da tua casa me devorou, e as afrontas dos que te afrontam caíram sobre mim.");
    b->dados[SALMOS].capitulos[69].versos[10] = _("Quando chorei e castiguei com jejum a minha alma, isto se me tornou em afrontas.");
    b->dados[SALMOS].capitulos[69].versos[11] = _("Quando me vesti de cilício, fiz-me para eles um provérbio.");
    b->dados[SALMOS].capitulos[69].versos[12] = _("Aqueles que se sentem à porta falam de mim; e sou objeto das cantigas dos bêbedos.");
    b->dados[SALMOS].capitulos[69].versos[13] = _("Eu, porém, faço a minha oração a ti, ó Senhor, em tempo aceitável; ouve-me, ó Deus, segundo a grandeza da tua benignidade, segundo a fidelidade da tua salvação.");
    b->dados[SALMOS].capitulos[69].versos[14] = _("Tira-me do lamaçal, e não me deixes afundar; seja eu salvo dos meus inimigos, e das profundezas das águas.");
    b->dados[SALMOS].capitulos[69].versos[15] = _("Não me submerja a corrente das águas e não me trague o abismo, nem cerre a cova a sua boca sobre mim.");
    b->dados[SALMOS].capitulos[69].versos[16] = _("Ouve-me, Senhor, pois grande é a tua benignidade; volta-te para mim segundo a tua muitíssima compaixão.");
    b->dados[SALMOS].capitulos[69].versos[17] = _("Não escondas o teu rosto do teu servo; ouve-me depressa, pois estou angustiado.");
    b->dados[SALMOS].capitulos[69].versos[18] = _("Aproxima-te da minha alma, e redime-a; resgata-me por causa dos meus inimigos.");
    b->dados[SALMOS].capitulos[69].versos[19] = _("Tu conheces o meu opróbrio, a minha vergonha, e a minha ignomínia; diante de ti estão todos os meus adversários.");
    b->dados[SALMOS].capitulos[69].versos[20] = _("Afrontas quebrantaram-me o coração, e estou debilitado. Esperei por alguém que tivesse compaixão, mas não houve nenhum; e por consoladores, mas não os achei.");
    b->dados[SALMOS].capitulos[69].versos[21] = _("Deram-me fel por mantimento, e na minha sede me deram a beber vinagre.");
    b->dados[SALMOS].capitulos[69].versos[22] = _("Torne-se a sua mesa diante deles em laço, e sejam-lhes as suas ofertas pacíficas uma armadilha.");
    b->dados[SALMOS].capitulos[69].versos[23] = _("Obscureçam-se-lhes os olhos, para que não vejam, e faze com que os seus lombos tremam constantemente.");
    b->dados[SALMOS].capitulos[69].versos[24] = _("Derrama sobre eles a tua indignação, e apanhe-os o ardor da tua ira.");
    b->dados[SALMOS].capitulos[69].versos[25] = _("Fique desolada a sua habitação, e não haja quem habite nas suas tendas.");
    b->dados[SALMOS].capitulos[69].versos[26] = _("Pois perseguem a quem afligiste, e aumentam a dor daqueles a quem feriste.");
    b->dados[SALMOS].capitulos[69].versos[27] = _("Acrescenta iniqüidade à iniqüidade deles, e não encontrem eles absolvição na tua justiça.");
    b->dados[SALMOS].capitulos[69].versos[28] = _("Sejam riscados do livro da vida, e não sejam inscritos com os justos.");
    b->dados[SALMOS].capitulos[69].versos[29] = _("Eu, porém, estou aflito e triste; a tua salvação, ó Deus, me ponha num alto retiro.");
    b->dados[SALMOS].capitulos[69].versos[30] = _("Louvarei o nome de Deus com um cântico, e engrandecê-lo-ei com ação de graças.");
    b->dados[SALMOS].capitulos[69].versos[31] = _("Isto será mais agradável ao Senhor do que um boi, ou um novilho que tem pontas e unhas.");
    b->dados[SALMOS].capitulos[69].versos[32] = _("Vejam isto os mansos, e se alegrem; vós que buscais a Deus reviva o vosso coração.");
    b->dados[SALMOS].capitulos[69].versos[33] = _("Porque o Senhor ouve os necessitados, e não despreza os seus, embora sejam prisioneiros.");
    b->dados[SALMOS].capitulos[69].versos[34] = _("Louvem-no os céus e a terra, os mares e tudo quanto neles se move.");
    b->dados[SALMOS].capitulos[69].versos[35] = _("Porque Deus salvará a Sião, e edificará as cidades de Judá, e ali habitarão os seus servos e a possuirão.");
    b->dados[SALMOS].capitulos[69].versos[36] = _("E herdá-la-á a descendência de seus servos, e os que amam o seu nome habitarão nela.");

    b->dados[SALMOS].capitulos[70].versos[1] = _("Apressa-te, ó Deus, em me livrar; Senhor, apressa-te em socorrer-me.");
    b->dados[SALMOS].capitulos[70].versos[2] = _("Fiquem envergonhados e confundidos os que procuram tirar-me a vida; tornem atrás e confundam-se os que me desejam o mal.");
    b->dados[SALMOS].capitulos[70].versos[3] = _("Sejam cobertos de vergonha os que dizem: Ah! Ah!");
    b->dados[SALMOS].capitulos[70].versos[4] = _("Folguem e alegrem-se em ti todos os que te buscam; e aqueles que amam a tua salvação digam continuamente: engrandecido seja Deus.");
    b->dados[SALMOS].capitulos[70].versos[5] = _("Eu, porém, estou aflito e necessitado; apressa-te em me valer, ó Deus. Tu és o meu amparo e o meu libertador; Senhor, não te detenhas.");

    b->dados[SALMOS].capitulos[71].versos[1] = _("Em ti, Senhor, me refugio; nunca seja eu confundido.");
    b->dados[SALMOS].capitulos[71].versos[2] = _("Na tua justiça socorre-me e livra-me; inclina os teus ouvidos para mim, e salva-me.");
    b->dados[SALMOS].capitulos[71].versos[3] = _("Sê tu para mim uma rocha de refúgio a que sempre me acolha; deste ordem para que eu seja salvo, pois tu és a minha rocha e a minha fortaleza.");
    b->dados[SALMOS].capitulos[71].versos[4] = _("Livra-me, Deus meu, da mão do ímpio, do poder do homem injusto e cruel,");
    b->dados[SALMOS].capitulos[71].versos[5] = _("Pois tu és a minha esperança, Senhor Deus; tu és a minha confiança desde a minha mocidade.");
    b->dados[SALMOS].capitulos[71].versos[6] = _("Em ti me tenho apoiado desde que nasci; tu és aquele que me tiraste das entranhas de minha mãe. O meu louvor será teu constantemente.");
    b->dados[SALMOS].capitulos[71].versos[7] = _("Sou para muitos um assombro, mas tu és o meu refúgio forte.");
    b->dados[SALMOS].capitulos[71].versos[8] = _("A minha boca se enche do teu louvor e da tua glória continuamente.");
    b->dados[SALMOS].capitulos[71].versos[9] = _("Não me enjeites no tempo da velhice; não me desampares, quando se forem acabando as minhas forças.");
    b->dados[SALMOS].capitulos[71].versos[10] = _("Porque os meus inimigos falam de mim, e os que espreitam a minha vida consultam juntos,");
    b->dados[SALMOS].capitulos[71].versos[11] = _("dizendo: Deus o desamparou; persegui-o e prendei-o, pois não há quem o livre.");
    b->dados[SALMOS].capitulos[71].versos[12] = _("Ó Deus, não te alongues de mim; meu Deus, apressa-te em socorrer-me.");
    b->dados[SALMOS].capitulos[71].versos[13] = _("Sejam envergonhados e consumidos os meus adversários; cubram-se de opróbrio e de confusão aqueles que procuram o meu mal.");
    b->dados[SALMOS].capitulos[71].versos[14] = _("Mas eu esperarei continuamente, e te louvarei cada vez mais.");
    b->dados[SALMOS].capitulos[71].versos[15] = _("A minha boca falará da tua justiça e da tua salvação todo o dia, posto que não conheça a sua grandeza.");
    b->dados[SALMOS].capitulos[71].versos[16] = _("Virei na força do Senhor Deus; farei menção da tua justiça, da tua tão somente.");
    b->dados[SALMOS].capitulos[71].versos[17] = _("Ensinaste-me, ó Deus, desde a minha mocidade; e até aqui tenho anunciado as tuas maravilhas.");
    b->dados[SALMOS].capitulos[71].versos[18] = _("Agora, quando estou velho e de cabelos brancos, não me desampares, ó Deus, até que tenha anunciado a tua força a esta geração, e o teu poder a todos os vindouros.");
    b->dados[SALMOS].capitulos[71].versos[19] = _("A tua justiça, ó Deus, atinge os altos céus; tu tens feito grandes coisas; ó Deus, quem é semelhante a ti?");
    b->dados[SALMOS].capitulos[71].versos[20] = _("Tu, que me fizeste ver muitas e penosas tribulações, de novo me restituirás a vida, e de novo me tirarás dos abismos da terra.");
    b->dados[SALMOS].capitulos[71].versos[21] = _("Aumentarás a minha grandeza, e de novo me consolarás.");
    b->dados[SALMOS].capitulos[71].versos[22] = _("Também eu te louvarei ao som do saltério, pela tua fidelidade, ó meu Deus; cantar-te-ei ao som da harpa, ó Santo de Israel.");
    b->dados[SALMOS].capitulos[71].versos[23] = _("Os meus lábios exultarão quando eu cantar os teus louvores, assim como a minha alma, que tu remiste.");
    b->dados[SALMOS].capitulos[71].versos[24] = _("Também a minha língua falará da tua justiça o dia todo; pois estão envergonhados e confundidos aqueles que procuram o meu mal.");

    b->dados[SALMOS].capitulos[72].versos[1] = _("Ó Deus, dá ao rei os teus juízes, e a tua justiça ao filho do rei.");
    b->dados[SALMOS].capitulos[72].versos[2] = _("Julgue ele o teu povo com justiça, e os teus pobres com eqüidade.");
    b->dados[SALMOS].capitulos[72].versos[3] = _("Que os montes tragam paz ao povo, como também os outeiros, com justiça.");
    b->dados[SALMOS].capitulos[72].versos[4] = _("Julgue ele os aflitos do povo, salve os filhos do necessitado, e esmague o opressor.");
    b->dados[SALMOS].capitulos[72].versos[5] = _("Viva ele enquanto existir o sol, e enquanto durar a lua, por todas as gerações.");
    b->dados[SALMOS].capitulos[72].versos[6] = _("Desça como a chuva sobre o prado, como os chuveiros que regam a terra.");
    b->dados[SALMOS].capitulos[72].versos[7] = _("Nos seus dias floresça a justiça, e haja abundância de paz enquanto durar a lua.");
    b->dados[SALMOS].capitulos[72].versos[8] = _("Domine de mar a mar, e desde o Rio até as extremidades da terra.");
    b->dados[SALMOS].capitulos[72].versos[9] = _("Inclinem-se diante dele os seus adversários, e os seus inimigos lambam o pó.");
    b->dados[SALMOS].capitulos[72].versos[10] = _("Paguem-lhe tributo os reis de Társis e das ilhas; os reis de Sabá e de Seba ofereçam-lhe dons.");
    b->dados[SALMOS].capitulos[72].versos[11] = _("Todos os reis se prostrem perante ele; todas as nações o sirvam.");
    b->dados[SALMOS].capitulos[72].versos[12] = _("Porque ele livra ao necessitado quando clama, como também ao aflito e ao que não tem quem o ajude.");
    b->dados[SALMOS].capitulos[72].versos[13] = _("Compadece-se do pobre e do necessitado, e a vida dos necessitados ele salva.");
    b->dados[SALMOS].capitulos[72].versos[14] = _("Ele os liberta da opressão e da violência, e precioso aos seus olhos é o sangue deles.");
    b->dados[SALMOS].capitulos[72].versos[15] = _("Viva, pois, ele; e se lhe dê do ouro de Sabá; e continuamente se faça por ele oração, e o bendigam em todo o tempo.");
    b->dados[SALMOS].capitulos[72].versos[16] = _("Haja abundância de trigo na terra sobre os cumes dos montes; ondule o seu fruto como o Líbano, e das cidades floresçam homens como a erva da terra.");
    b->dados[SALMOS].capitulos[72].versos[17] = _("Permaneça o seu nome eternamente; continue a sua fama enquanto o sol durar, e os homens sejam abençoados nele; todas as nações o chamem bem-aventurado.");
    b->dados[SALMOS].capitulos[72].versos[18] = _("Bendito seja o Senhor Deus, o Deus de Israel, o único que faz maravilhas.");
    b->dados[SALMOS].capitulos[72].versos[19] = _("Bendito seja para sempre o seu nome glorioso, e encha-se da sua glória toda a terra. Amém e amém.");
    b->dados[SALMOS].capitulos[72].versos[20] = _("Findam aqui as orações de Davi, filho de Jessé.");

    b->dados[SALMOS].capitulos[73].versos[1] = _("Verdadeiramente bom é Deus para com Israel, para com os limpos de coração.");
    b->dados[SALMOS].capitulos[73].versos[2] = _("Quanto a mim, os meus pés quase resvalaram; pouco faltou para que os meus passos escorregassem.");
    b->dados[SALMOS].capitulos[73].versos[3] = _("Pois eu tinha inveja dos soberbos, ao ver a prosperidade dos ímpios.");
    b->dados[SALMOS].capitulos[73].versos[4] = _("Não há apertos na sua morte; o seu corpo é forte e sadio.");
    b->dados[SALMOS].capitulos[73].versos[5] = _("Não se acham em tribulações como outra gente, nem são afligidos como os demais homens.");
    b->dados[SALMOS].capitulos[73].versos[6] = _("Pelo que a soberba lhes cinge o pescoço como um colar; a violência os cobre como um vestido.");
    b->dados[SALMOS].capitulos[73].versos[7] = _("Os olhos deles estão inchados de gordura; trasbordam as fantasias do seu coração.");
    b->dados[SALMOS].capitulos[73].versos[8] = _("Motejam e falam maliciosamente; falam arrogantemente da opressão.");
    b->dados[SALMOS].capitulos[73].versos[9] = _("Põem a sua boca contra os céus, e a sua língua percorre a terra.");
    b->dados[SALMOS].capitulos[73].versos[10] = _("Pelo que o povo volta para eles e não acha neles falta alguma.");
    b->dados[SALMOS].capitulos[73].versos[11] = _("E dizem: Como o sabe Deus? e: Há conhecimento no Altíssimo?");
    b->dados[SALMOS].capitulos[73].versos[12] = _("Eis que estes são ímpios; sempre em segurança, aumentam as suas riquezas.");
    b->dados[SALMOS].capitulos[73].versos[13] = _("Na verdade que em vão tenho purificado o meu coração e lavado as minhas mãos na inocência,");
    b->dados[SALMOS].capitulos[73].versos[14] = _("pois todo o dia tenho sido afligido, e castigado cada manhã.");
    b->dados[SALMOS].capitulos[73].versos[15] = _("Se eu tivesse dito: Também falarei assim; eis que me teria havido traiçoeiramente para com a geração de teus filhos.");
    b->dados[SALMOS].capitulos[73].versos[16] = _("Quando me esforçava para compreender isto, achei que era tarefa difícil para mim,");
    b->dados[SALMOS].capitulos[73].versos[17] = _("até que entrei no santuário de Deus; então percebi o fim deles.");
    b->dados[SALMOS].capitulos[73].versos[18] = _("Certamente tu os pões em lugares escorregadios, tu os lanças para a ruína.");
    b->dados[SALMOS].capitulos[73].versos[19] = _("Como caem na desolação num momento! ficam totalmente consumidos de terrores.");
    b->dados[SALMOS].capitulos[73].versos[20] = _("Como faz com um sonho o que acorda, assim, ó Senhor, quando acordares, desprezarás as suas fantasias.");
    b->dados[SALMOS].capitulos[73].versos[21] = _("Quando o meu espírito se amargurava, e sentia picadas no meu coração,");
    b->dados[SALMOS].capitulos[73].versos[22] = _("estava embrutecido, e nada sabia; era como animal diante de ti.");
    b->dados[SALMOS].capitulos[73].versos[23] = _("Todavia estou sempre contigo; tu me seguras a mão direita.");
    b->dados[SALMOS].capitulos[73].versos[24] = _("Tu me guias com o teu conselho, e depois me receberás em glória.");
    b->dados[SALMOS].capitulos[73].versos[25] = _("A quem tenho eu no céu senão a ti? e na terra não há quem eu deseje além de ti.");
    b->dados[SALMOS].capitulos[73].versos[26] = _("A minha carne e o meu coração desfalecem; do meu coração, porém, Deus é a fortaleza, e o meu quinhão para sempre.");
    b->dados[SALMOS].capitulos[73].versos[27] = _("Pois os que estão longe de ti perecerão; tu exterminas todos aqueles que se desviam de ti.");
    b->dados[SALMOS].capitulos[73].versos[28] = _("Mas para mim, bom é aproximar-me de Deus; ponho a minha confiança no Senhor Deus, para anunciar todas as suas obras.");

    b->dados[SALMOS].capitulos[74].versos[1] = _("Ó Deus, por que nos rejeitaste para sempre? Por que se acende a tua ira contra o rebanho do teu pasto?");
    b->dados[SALMOS].capitulos[74].versos[2] = _("Lembra-te da tua congregação, que compraste desde a antigüidade, que remiste para ser a tribo da tua herança, e do monte Sião, em que tens habitado.");
    b->dados[SALMOS].capitulos[74].versos[3] = _("Dirige os teus passos para as perpétuas ruínas, para todo o mal que o inimigo tem feito no santuário.");
    b->dados[SALMOS].capitulos[74].versos[4] = _("Os teus inimigos bramam no meio da tua assembléia; põem nela as suas insígnias por sinais.");
    b->dados[SALMOS].capitulos[74].versos[5] = _("A entrada superior cortaram com machados a grade de madeira.");
    b->dados[SALMOS].capitulos[74].versos[6] = _("Eis que toda obra entalhada, eles a despedaçaram a machados e martelos.");
    b->dados[SALMOS].capitulos[74].versos[7] = _("Lançaram fogo ao teu santuário; profanaram, derrubando-a até o chão, a morada do teu nome.");
    b->dados[SALMOS].capitulos[74].versos[8] = _("Disseram no seu coração: Despojemo-la duma vez. Queimaram todas as sinagogas de Deus na terra.");
    b->dados[SALMOS].capitulos[74].versos[9] = _("Não vemos mais as nossas insígnias, não há mais profeta; nem há entre nós alguém que saiba até quando isto durará.");
    b->dados[SALMOS].capitulos[74].versos[10] = _("Até quando, ó Deus, o adversário afrontará? O inimigo ultrajará o teu nome para sempre?");
    b->dados[SALMOS].capitulos[74].versos[11] = _("Por que reténs a tua mão, sim, a tua destra? Tira-a do teu seio, e consome-os.");
    b->dados[SALMOS].capitulos[74].versos[12] = _("Todavia, Deus é o meu Rei desde a antigüidade, operando a salvação no meio da terra.");
    b->dados[SALMOS].capitulos[74].versos[13] = _("Tu dividiste o mar pela tua força; esmigalhaste a cabeça dos monstros marinhos sobre as águas.");
    b->dados[SALMOS].capitulos[74].versos[14] = _("Tu esmagaste as cabeças do leviatã, e o deste por mantimento aos habitantes do deserto.");
    b->dados[SALMOS].capitulos[74].versos[15] = _("Tu abriste fontes e ribeiros; tu secaste os rios perenes.");
    b->dados[SALMOS].capitulos[74].versos[16] = _("Teu é o dia e tua é a noite: tu preparaste a luz e o sol.");
    b->dados[SALMOS].capitulos[74].versos[17] = _("Tu estabeleceste todos os limites da terra; verão e inverno, tu os fizeste.");
    b->dados[SALMOS].capitulos[74].versos[18] = _("Lembra-te disto: que o inimigo te afrontou, ó Senhor, e que um povo insensato ultrajou o teu nome.");
    b->dados[SALMOS].capitulos[74].versos[19] = _("Não entregues às feras a alma da tua rola; não te esqueça para sempre da vida dos teus aflitos.");
    b->dados[SALMOS].capitulos[74].versos[20] = _("Atenta para o teu pacto, pois os lugares tenebrosos da terra estão cheios das moradas de violência.");
    b->dados[SALMOS].capitulos[74].versos[21] = _("Não volte envergonhado o oprimido; louvem o teu nome o aflito e o necessitado.");
    b->dados[SALMOS].capitulos[74].versos[22] = _("Levanta-te, ó Deus, pleiteia a tua própria causa; lembra-te da afronta que o insensato te faz continuamente.");
    b->dados[SALMOS].capitulos[74].versos[23] = _("Não te esqueças da gritaria dos teus adversários; o tumulto daqueles que se levantam contra ti sobe continuamente.");

    b->dados[SALMOS].capitulos[75].versos[1] = _("Damos-te graças, ó Deus, damos-te graças, pois o teu nome está perto; os que invocam o teu nome anunciam as tuas maravilhas.");
    b->dados[SALMOS].capitulos[75].versos[2] = _("Quando chegar o tempo determinado, julgarei retamente.");
    b->dados[SALMOS].capitulos[75].versos[3] = _("Dissolve-se a terra e todos os seus moradores, mas eu lhe fortaleci as colunas.");
    b->dados[SALMOS].capitulos[75].versos[4] = _("Digo eu aos arrogantes: Não sejais arrogantes; e aos ímpios: Não levanteis a fronte;");
    b->dados[SALMOS].capitulos[75].versos[5] = _("não levanteis ao alto a vossa fronte, nem faleis com arrogância.");
    b->dados[SALMOS].capitulos[75].versos[6] = _("Porque nem do oriente, nem do ocidente, nem do deserto vem a exaltação.");
    b->dados[SALMOS].capitulos[75].versos[7] = _("Mas Deus é o que julga; a um abate, e a outro exalta.");
    b->dados[SALMOS].capitulos[75].versos[8] = _("Porque na mão do Senhor há um cálice, cujo vinho espuma, cheio de mistura, do qual ele dá a beber; certamente todos os ímpios da terra sorverão e beberão as suas fezes.");
    b->dados[SALMOS].capitulos[75].versos[9] = _("Mas, quanto a mim, exultarei para sempre, cantarei louvores ao Deus de Jacó.");
    b->dados[SALMOS].capitulos[75].versos[10] = _("E quebrantarei todas as forças dos ímpios, mas as forças dos justos serão exaltadas.");

    b->dados[SALMOS].capitulos[76].versos[1] = _("Conhecido é Deus em Judá, grande é o seu nome em Israel.");
    b->dados[SALMOS].capitulos[76].versos[2] = _("Em Salém está a sua tenda, e a sua morada em Sião.");
    b->dados[SALMOS].capitulos[76].versos[3] = _("Ali quebrou ele as flechas do arco, o escudo, a espada, e a guerra.");
    b->dados[SALMOS].capitulos[76].versos[4] = _("Glorioso és tu, mais majestoso do que os montes eternos.");
    b->dados[SALMOS].capitulos[76].versos[5] = _("Os ousados de coração foram despojados; dormiram o seu último sono; nenhum dos homens de força pôde usar as mãos.");
    b->dados[SALMOS].capitulos[76].versos[6] = _("À tua repreensão, ó Deus de Jacó, cavaleiros e cavalos ficaram estirados sem sentidos.");
    b->dados[SALMOS].capitulos[76].versos[7] = _("Tu, sim, tu és tremendo; e quem subsistirá à tua vista, quando te irares?");
    b->dados[SALMOS].capitulos[76].versos[8] = _("Desde o céu fizeste ouvir o teu juízo; a terra tremeu e se aquietou,");
    b->dados[SALMOS].capitulos[76].versos[9] = _("quando Deus se levantou para julgar, para salvar a todos os mansos da terra.");
    b->dados[SALMOS].capitulos[76].versos[10] = _("Na verdade a cólera do homem redundará em teu louvor, e do restante da cólera tu te cingirás.");
    b->dados[SALMOS].capitulos[76].versos[11] = _("Fazei votos, e pagai-os ao Senhor, vosso Deus; tragam presentes, os que estão em redor dele, àquele que deve ser temido.");
    b->dados[SALMOS].capitulos[76].versos[12] = _("Ele ceifará o espírito dos príncipes; é tremendo para com os reis da terra.");

    b->dados[SALMOS].capitulos[77].versos[1] = _("Levanto a Deus a minha voz; a Deus levanto a minha voz, para que ele me ouça.");
    b->dados[SALMOS].capitulos[77].versos[2] = _("No dia da minha angústia busco ao Senhor; de noite a minha mão fica estendida e não se cansa; a minha alma recusa ser consolada.");
    b->dados[SALMOS].capitulos[77].versos[3] = _("Lembro-me de Deus, e me lamento; queixo-me, e o meu espírito desfalece.");
    b->dados[SALMOS].capitulos[77].versos[4] = _("Conservas vigilantes os meus olhos; estou tão perturbado que não posso falar.");
    b->dados[SALMOS].capitulos[77].versos[5] = _("Considero os dias da antigüidade, os anos dos tempos passados.");
    b->dados[SALMOS].capitulos[77].versos[6] = _("De noite lembro-me do meu cântico; consulto com o meu coração, e examino o meu espírito.");
    b->dados[SALMOS].capitulos[77].versos[7] = _("Rejeitará o Senhor para sempre e não tornará a ser favorável?");
    b->dados[SALMOS].capitulos[77].versos[8] = _("Cessou para sempre a sua benignidade? Acabou-se a sua promessa para todas as gerações");
    b->dados[SALMOS].capitulos[77].versos[9] = _("Esqueceu-se Deus de ser compassivo? Ou na sua ira encerrou ele as suas ternas misericórdias?");
    b->dados[SALMOS].capitulos[77].versos[10] = _("E eu digo: Isto é minha enfermidade; acaso se mudou a destra do Altíssimo?");
    b->dados[SALMOS].capitulos[77].versos[11] = _("Recordarei os feitos do Senhor; sim, me lembrarei das tuas maravilhas da antigüidade.");
    b->dados[SALMOS].capitulos[77].versos[12] = _("Meditarei também em todas as tuas obras, e ponderarei os teus feitos poderosos");
    b->dados[SALMOS].capitulos[77].versos[13] = _("O teu caminho, ó Deus, é em santidade; que deus é grande como o nosso Deus?");
    b->dados[SALMOS].capitulos[77].versos[14] = _("Tu és o Deus que fazes maravilhas; tu tens feito notória a tua força entre os povos.");
    b->dados[SALMOS].capitulos[77].versos[15] = _("Com o teu braço remiste o teu povo, os filhos de Jacó e de José.");
    b->dados[SALMOS].capitulos[77].versos[16] = _("As águas te viram, ó Deus, as águas te viram, e tremeram; os abismos também se abalaram.");
    b->dados[SALMOS].capitulos[77].versos[17] = _("As nuvens desfizeram-se em água; os céus retumbaram; as tuas flechas também correram de uma para outra parte.");
    b->dados[SALMOS].capitulos[77].versos[18] = _("A voz do teu trovão estava no redemoinho; os relâmpagos alumiaram o mundo; a terra se abalou e tremeu.");
    b->dados[SALMOS].capitulos[77].versos[19] = _("Pelo mar foi teu caminho, e tuas veredas pelas grandes águas; e as tuas pegadas não foram conhecidas.");
    b->dados[SALMOS].capitulos[77].versos[20] = _("Guiaste o teu povo, como a um rebanho, pela mão de Moisés e de Arão.");

    b->dados[SALMOS].capitulos[78].versos[1] = _("Escutai o meu ensino, povo meu; inclinai os vossos ouvidos às palavras da minha boca.");
    b->dados[SALMOS].capitulos[78].versos[2] = _("Abrirei a minha boca numa parábola; proporei enigmas da antigüidade,");
    b->dados[SALMOS].capitulos[78].versos[3] = _("coisas que temos ouvido e sabido, e que nossos pais nos têm contado.");
    b->dados[SALMOS].capitulos[78].versos[4] = _("Não os encobriremos aos seus filhos, cantaremos às gerações vindouras os louvores do Senhor, assim como a sua força e as maravilhas que tem feito.");
    b->dados[SALMOS].capitulos[78].versos[5] = _("Porque ele estabeleceu um testemunho em Jacó, e instituiu uma lei em Israel, as quais coisas ordenou aos nossos pais que as ensinassem a seus filhos;");
    b->dados[SALMOS].capitulos[78].versos[6] = _("para que as soubesse a geração vindoura, os filhos que houvesse de nascer, os quais se levantassem e as contassem a seus filhos,");
    b->dados[SALMOS].capitulos[78].versos[7] = _("a fim de que pusessem em Deus a sua esperança, e não se esquecessem das obras de Deus, mas guardassem os seus mandamentos;");
    b->dados[SALMOS].capitulos[78].versos[8] = _("e que não fossem como seus pais, geração contumaz e rebelde, geração de coração instável, cujo espírito não foi fiel para com Deus.");
    b->dados[SALMOS].capitulos[78].versos[9] = _("Os filhos de Efraim, armados de arcos, retrocederam no dia da peleja.");
    b->dados[SALMOS].capitulos[78].versos[10] = _("Não guardaram o pacto de Deus, e recusaram andar na sua lei;");
    b->dados[SALMOS].capitulos[78].versos[11] = _("esqueceram-se das suas obras e das maravilhas que lhes fizera ver.");
    b->dados[SALMOS].capitulos[78].versos[12] = _("Maravilhas fez ele à vista de seus pais na terra do Egito, no campo de Zoã.");
    b->dados[SALMOS].capitulos[78].versos[13] = _("Dividiu o mar, e os fez passar por ele; fez com que as águas parassem como um montão.");
    b->dados[SALMOS].capitulos[78].versos[14] = _("Também os guiou de dia por uma nuvem, e a noite toda por um clarão de fogo.");
    b->dados[SALMOS].capitulos[78].versos[15] = _("Fendeu rochas no deserto, e deu-lhes de beber abundantemente como de grandes abismos.");
    b->dados[SALMOS].capitulos[78].versos[16] = _("Da penha fez sair fontes, e fez correr águas como rios.");
    b->dados[SALMOS].capitulos[78].versos[17] = _("Todavia ainda prosseguiram em pecar contra ele, rebelando-se contra o Altíssimo no deserto.");
    b->dados[SALMOS].capitulos[78].versos[18] = _("E tentaram a Deus nos seus corações, pedindo comida segundo o seu apetite.");
    b->dados[SALMOS].capitulos[78].versos[19] = _("Também falaram contra Deus, dizendo: Poderá Deus porventura preparar uma mesa no deserto? Acaso fornecerá carne para o seu povo?");
    b->dados[SALMOS].capitulos[78].versos[20] = _("Pelo que o Senhor, quando os ouviu, se indignou; e acendeu um fogo contra Jacó, e a sua ira subiu contra Israel;");
    b->dados[SALMOS].capitulos[78].versos[21] = _("Pelo que o Senhor, quando os ouviu, se indignou; e acendeu um fogo contra Jacó, e a sua ira subiu contra Israel;");
    b->dados[SALMOS].capitulos[78].versos[22] = _("porque não creram em Deus nem confiaram na sua salvação.");
    b->dados[SALMOS].capitulos[78].versos[23] = _("Contudo ele ordenou às nuvens lá em cima, e abriu as portas dos céus;");
    b->dados[SALMOS].capitulos[78].versos[24] = _("fez chover sobre eles maná para comerem, e deu-lhes do trigo dos céus.");
    b->dados[SALMOS].capitulos[78].versos[25] = _("Cada um comeu o pão dos poderosos; ele lhes mandou comida em abundância.");
    b->dados[SALMOS].capitulos[78].versos[26] = _("Fez soprar nos céus o vento do oriente, e pelo seu poder trouxe o vento sul.");
    b->dados[SALMOS].capitulos[78].versos[27] = _("Sobre eles fez também chover carne como poeira, e aves de asas como a areia do mar;");
    b->dados[SALMOS].capitulos[78].versos[28] = _("e as fez cair no meio do arraial deles, ao redor de suas habitações.");
    b->dados[SALMOS].capitulos[78].versos[29] = _("Então comeram e se fartaram bem, pois ele lhes trouxe o que cobiçavam.");
    b->dados[SALMOS].capitulos[78].versos[30] = _("Não refrearam a sua cobiça. Ainda lhes estava a comida na boca,");
    b->dados[SALMOS].capitulos[78].versos[31] = _("quando a ira de Deus se levantou contra eles, e matou os mais fortes deles, e prostrou os escolhidos de Israel.");
    b->dados[SALMOS].capitulos[78].versos[32] = _("Com tudo isso ainda pecaram, e não creram nas suas maravilhas.");
    b->dados[SALMOS].capitulos[78].versos[33] = _("Pelo que consumiu os seus dias como um sopro, e os seus anos em repentino terror.");
    b->dados[SALMOS].capitulos[78].versos[34] = _("Quando ele os fazia morrer, então o procuravam; arrependiam-se, e de madrugada buscavam a Deus.");
    b->dados[SALMOS].capitulos[78].versos[35] = _("Lembravam-se de que Deus era a sua rocha, e o Deus Altíssimo o seu Redentor.");
    b->dados[SALMOS].capitulos[78].versos[36] = _("Todavia lisonjeavam-no com a boca, e com a língua lhe mentiam.");
    b->dados[SALMOS].capitulos[78].versos[37] = _("Pois o coração deles não era constante para com ele, nem foram eles fiéis ao seu pacto.");
    b->dados[SALMOS].capitulos[78].versos[38] = _("Mas ele, sendo compassivo, perdoou a sua iniqüidade, e não os destruiu; antes muitas vezes desviou deles a sua cólera, e não acendeu todo o seu furor.");
    b->dados[SALMOS].capitulos[78].versos[39] = _("Porque se lembrou de que eram carne, um vento que passa e não volta.");
    b->dados[SALMOS].capitulos[78].versos[40] = _("Quantas vezes se rebelaram contra ele no deserto, e o ofenderam no ermo!");
    b->dados[SALMOS].capitulos[78].versos[41] = _("Voltaram atrás, e tentaram a Deus; e provocaram o Santo de Israel.");
    b->dados[SALMOS].capitulos[78].versos[42] = _("Não se lembraram do seu poder, nem do dia em que os remiu do adversário,");
    b->dados[SALMOS].capitulos[78].versos[43] = _("nem de como operou os seus sinais no Egito, e as suas maravilhas no campo de Zoã,");
    b->dados[SALMOS].capitulos[78].versos[44] = _("convertendo em sangue os seus rios, para que não pudessem beber das suas correntes.");
    b->dados[SALMOS].capitulos[78].versos[45] = _("Também lhes mandou enxames de moscas que os consumiram, e rãs que os destruíram.");
    b->dados[SALMOS].capitulos[78].versos[46] = _("Entregou às lagartas as novidades deles, e o fruto do seu trabalho aos gafanhotos.");
    b->dados[SALMOS].capitulos[78].versos[47] = _("Destruiu as suas vinhas com saraiva, e os seus sicômoros com chuva de pedra.");
    b->dados[SALMOS].capitulos[78].versos[48] = _("Também entregou à saraiva o gado deles, e aos coriscos os seus rebanhos.");
    b->dados[SALMOS].capitulos[78].versos[49] = _("E atirou sobre eles o ardor da sua ira, o furor, a indignação, e a angústia, qual companhia de anjos destruidores.");
    b->dados[SALMOS].capitulos[78].versos[50] = _("Deu livre curso à sua ira; não os poupou da morte, mas entregou a vida deles à pestilência.");
    b->dados[SALMOS].capitulos[78].versos[51] = _("Feriu todo primogênito no Egito, primícias da força deles nas tendas de Cam.");
    b->dados[SALMOS].capitulos[78].versos[52] = _("Mas fez sair o seu povo como ovelhas, e os guiou pelo deserto como a um rebanho.");
    b->dados[SALMOS].capitulos[78].versos[53] = _("Guiou-os com segurança, de sorte que eles não temeram; mas aos seus inimigos, o mar os submergiu.");
    b->dados[SALMOS].capitulos[78].versos[54] = _("Sim, conduziu-os até a sua fronteira santa, até o monte que a sua destra adquirira.");
    b->dados[SALMOS].capitulos[78].versos[55] = _("Expulsou as nações de diante deles; e dividindo suas terras por herança, fez habitar em suas tendas as tribos de Israel.");
    b->dados[SALMOS].capitulos[78].versos[56] = _("Contudo tentaram e provocaram o Deus Altíssimo, e não guardaram os seus testemunhos.");
    b->dados[SALMOS].capitulos[78].versos[57] = _("Mas tornaram atrás, e portaram-se aleivosamente como seus pais; desviaram-se como um arco traiçoeiro.");
    b->dados[SALMOS].capitulos[78].versos[58] = _("Pois o provocaram à ira com os seus altos, e o incitaram a zelos com as suas imagens esculpidas.");
    b->dados[SALMOS].capitulos[78].versos[59] = _("Ao ouvir isso, Deus se indignou, e sobremodo abominou a Israel.");
    b->dados[SALMOS].capitulos[78].versos[60] = _("Pelo que desamparou o tabernáculo em Siló, a tenda da sua morada entre os homens,");
    b->dados[SALMOS].capitulos[78].versos[61] = _("dando a sua força ao cativeiro, e a sua glória à mão do inimigo.");
    b->dados[SALMOS].capitulos[78].versos[62] = _("Entregou o seu povo à espada, e encolerizou-se contra a sua herança.");
    b->dados[SALMOS].capitulos[78].versos[63] = _("Aos seus mancebos o fogo devorou, e suas donzelas não tiveram cântico nupcial.");
    b->dados[SALMOS].capitulos[78].versos[64] = _("Os seus sacerdotes caíram à espada, e suas viúvas não fizeram pranto.");
    b->dados[SALMOS].capitulos[78].versos[65] = _("Então o Senhor despertou como dum sono, como um valente que o vinho excitasse.");
    b->dados[SALMOS].capitulos[78].versos[66] = _("E fez recuar a golpes os seus adversários; infligiu-lhes eterna ignomínia.");
    b->dados[SALMOS].capitulos[78].versos[67] = _("Além disso, rejeitou a tenda de José, e não escolheu a tribo de Efraim;");
    b->dados[SALMOS].capitulos[78].versos[68] = _("antes escolheu a tribo de Judá, o monte Sião, que ele amava.");
    b->dados[SALMOS].capitulos[78].versos[69] = _("Edificou o seu santuário como os lugares elevados, como a terra que fundou para sempre.");
    b->dados[SALMOS].capitulos[78].versos[70] = _("Também escolheu a Davi, seu servo, e o tirou dos apriscos das ovelhas;");
    b->dados[SALMOS].capitulos[78].versos[71] = _("de após as ovelhas e suas crias o trouxe, para apascentar a Jacó, seu povo, e a Israel, sua herança.");
    b->dados[SALMOS].capitulos[78].versos[72] = _("E ele os apascentou, segundo a integridade do seu coração, e os guiou com a perícia de suas mãos.");

    b->dados[SALMOS].capitulos[79].versos[1] = _("Ó Deus, as nações invadiram a tua herança; contaminaram o teu santo templo; reduziram Jerusalém a ruínas.");
    b->dados[SALMOS].capitulos[79].versos[2] = _("Deram os cadáveres dos teus servos como pastos às aves dos céus, e a carne dos teus santos aos animais da terra.");
    b->dados[SALMOS].capitulos[79].versos[3] = _("Derramaram o sangue deles como água ao redor de Jerusalém, e não houve quem os sepultasse.");
    b->dados[SALMOS].capitulos[79].versos[4] = _("Somos feitos o opróbrio dos nossos vizinhos, o escárnio e a zombaria dos que estão em redor de nós.");
    b->dados[SALMOS].capitulos[79].versos[5] = _("Até quando, Senhor? Indignar-te-ás para sempre? Arderá o teu zelo como fogo?");
    b->dados[SALMOS].capitulos[79].versos[6] = _("Derrama o teu furor sobre as nações que não te conhecem, e sobre os reinos que não invocam o teu nome;");
    b->dados[SALMOS].capitulos[79].versos[7] = _("porque eles devoraram a Jacó, e assolaram a sua morada.");
    b->dados[SALMOS].capitulos[79].versos[8] = _("Não te lembres contra nós das iniqüidades de nossos pais; venha depressa ao nosso encontro a tua compaixão, pois estamos muito abatidos.");
    b->dados[SALMOS].capitulos[79].versos[9] = _("Ajuda-nos, ó Deus da nossa salvação, pela glória do teu nome; livra-nos, e perdoa os nossos pecados, por amor do teu nome.");
    b->dados[SALMOS].capitulos[79].versos[10] = _("Por que diriam as nações: Onde está o seu Deus? Torne-se manifesta entre as nações, à nossa vista, a vingança do sangue derramado dos teus servos.");
    b->dados[SALMOS].capitulos[79].versos[11] = _("Chegue à tua presença o gemido dos presos; segundo a grandeza do teu braço, preserva aqueles que estão condenados à morte.");
    b->dados[SALMOS].capitulos[79].versos[12] = _("E aos nossos vizinhos, deita-lhes no regaço, setuplicadamente, a injúria com que te injuriaram, Senhor.");
    b->dados[SALMOS].capitulos[79].versos[13] = _("Assim nós, teu povo ovelhas de teu pasto, te louvaremos eternamente; de geração em geração publicaremos os teus louvores.");

    b->dados[SALMOS].capitulos[80].versos[1] = _("Ó pastor de Israel, dá ouvidos; tu, que guias a José como a um rebanho, que estás entronizado sobre os querubins, resplandece.");
    b->dados[SALMOS].capitulos[80].versos[2] = _("Perante Efraim, Benjamim e Manassés, desperta o teu poder, e vem salvar-nos.");
    b->dados[SALMOS].capitulos[80].versos[3] = _("Reabilita-nos, ó Deus; faze resplandecer o teu rosto, para que sejamos salvos.");
    b->dados[SALMOS].capitulos[80].versos[4] = _("Ó Senhor Deus dos exércitos, até quando te indignarás contra a oração do teu povo?");
    b->dados[SALMOS].capitulos[80].versos[5] = _("Tu os alimentaste com pão de lágrimas, e lhes deste a beber lágrimas em abundância.");
    b->dados[SALMOS].capitulos[80].versos[6] = _("Tu nos fazes objeto de escárnio entre os nossos vizinhos; e os nossos inimigos zombam de nós entre si.");
    b->dados[SALMOS].capitulos[80].versos[7] = _("Reabilita-nos, ó Deus dos exércitos; faze resplandecer o teu rosto, para que sejamos salvos.");
    b->dados[SALMOS].capitulos[80].versos[8] = _("Trouxeste do Egito uma videira; lançaste fora as nações, e a plantaste.");
    b->dados[SALMOS].capitulos[80].versos[9] = _("Preparaste-lhe lugar; e ela deitou profundas raízes, e encheu a terra.");
    b->dados[SALMOS].capitulos[80].versos[10] = _("Os montes cobriram-se com a sua sombra, e os cedros de Deus com os seus ramos.");
    b->dados[SALMOS].capitulos[80].versos[11] = _("Ela estendeu a sua ramagem até o mar, e os seus rebentos até o Rio.");
    b->dados[SALMOS].capitulos[80].versos[12] = _("Por que lhe derrubaste as cercas, de modo que a vindimam todos os que passam pelo caminho?");
    b->dados[SALMOS].capitulos[80].versos[13] = _("O javali da selva a devasta, e as feras do campo alimentam-se dela.");
    b->dados[SALMOS].capitulos[80].versos[14] = _("Ó Deus dos exércitos, volta-te, nós te rogamos; atende do céu, e vê, e visita esta videira,");
    b->dados[SALMOS].capitulos[80].versos[15] = _("a videira que a tua destra plantou, e o sarmento que fortificaste para ti.");
    b->dados[SALMOS].capitulos[80].versos[16] = _("Está queimada pelo fogo, está cortada; eles perecem pela repreensão do teu rosto.");
    b->dados[SALMOS].capitulos[80].versos[17] = _("Seja a tua mão sobre o varão da tua destra, sobre o filho do homem que fortificaste para ti.");
    b->dados[SALMOS].capitulos[80].versos[18] = _("E não nos afastaremos de ti; vivifica-nos, e nós invocaremos o teu nome.");
    b->dados[SALMOS].capitulos[80].versos[19] = _("Reabilita-nos, Senhor Deus dos exércitos; faze resplandecer o teu rosto, para que sejamos salvos.");

    b->dados[SALMOS].capitulos[81].versos[1] = _("Cantai alegremente a Deus, nossa fortaleza; erguei alegres vozes ao Deus de Jacó.");
    b->dados[SALMOS].capitulos[81].versos[2] = _("Entoai um salmo, e fazei soar o adufe, a suave harpa e o saltério.");
    b->dados[SALMOS].capitulos[81].versos[3] = _("Tocai a trombeta pela lua nova, pela lua cheia, no dia da nossa festa.");
    b->dados[SALMOS].capitulos[81].versos[4] = _("Pois isso é um estatuto para Israel, e uma ordenança do Deus de Jacó.");
    b->dados[SALMOS].capitulos[81].versos[5] = _("Ordenou-o por decreto em José, quando saiu contra a terra do Egito. Ouvi uma voz que não conhecia, dizendo:");
    b->dados[SALMOS].capitulos[81].versos[6] = _("Livrei da carga o seu ombro; as suas mãos ficaram livres dos cestos.");
    b->dados[SALMOS].capitulos[81].versos[7] = _("Na angústia clamaste e te livrei; respondi-te no lugar oculto dos trovões; provei-te junto às águas de Meribá.");
    b->dados[SALMOS].capitulos[81].versos[8] = _("Ouve-me, povo meu, e eu te admoestarei; ó Israel, se me escutasses!");
    b->dados[SALMOS].capitulos[81].versos[9] = _("não haverá em ti deus estranho, nem te prostrarás ante um deus estrangeiro.");
    b->dados[SALMOS].capitulos[81].versos[10] = _("Eu sou o Senhor teu Deus, que te tirei da terra do Egito; abre bem a tua boca, e eu a encherei.");
    b->dados[SALMOS].capitulos[81].versos[11] = _("Mas o meu povo não ouviu a minha voz, e Israel não me quis.");
    b->dados[SALMOS].capitulos[81].versos[12] = _("Pelo que eu os entreguei à obstinação dos seus corações, para que andassem segundo os seus próprios conselhos.");
    b->dados[SALMOS].capitulos[81].versos[13] = _("Oxalá me escutasse o meu povo! oxalá Israel andasse nos meus caminhos!");
    b->dados[SALMOS].capitulos[81].versos[14] = _("Em breve eu abateria os seus inimigos, e voltaria a minha mão contra os seus adversários.");
    b->dados[SALMOS].capitulos[81].versos[15] = _("Os que odeiam ao Senhor o adulariam, e a sorte deles seria eterna.");
    b->dados[SALMOS].capitulos[81].versos[16] = _("E eu te sustentaria com o trigo mais fino; e com o mel saído da rocha eu te saciaria.");

    b->dados[SALMOS].capitulos[82].versos[1] = _("Deus está na assembléia divina; julga no meio dos deuses:");
    b->dados[SALMOS].capitulos[82].versos[2] = _("Até quando julgareis injustamente, e tereis respeito às pessoas dos ímpios?");
    b->dados[SALMOS].capitulos[82].versos[3] = _("Fazei justiça ao pobre e ao órfão; procedei retamente com o aflito e o desamparado.");
    b->dados[SALMOS].capitulos[82].versos[4] = _("Livrai o pobre e o necessitado, livrai-os das mãos dos ímpios.");
    b->dados[SALMOS].capitulos[82].versos[5] = _("Eles nada sabem, nem entendem; andam vagueando às escuras; abalam-se todos os fundamentos da terra.");
    b->dados[SALMOS].capitulos[82].versos[6] = _("Eu disse: Vós sois deuses, e filhos do Altíssimo, todos vós.");
    b->dados[SALMOS].capitulos[82].versos[7] = _("Todavia, como homens, haveis de morrer e, como qualquer dos príncipes, haveis de cair.");
    b->dados[SALMOS].capitulos[82].versos[8] = _("Levanta-te, ó Deus, julga a terra; pois a ti pertencem todas as nações.");

    b->dados[SALMOS].capitulos[83].versos[1] = _("Ó Deus, não guardes silêncio; não te cales nem fiques impassível, ó Deus.");
    b->dados[SALMOS].capitulos[83].versos[2] = _("Pois eis que teus inimigos se alvoroçam, e os que te odeiam levantam a cabeça.");
    b->dados[SALMOS].capitulos[83].versos[3] = _("Astutamente formam conselho contra o teu povo, e conspiram contra os teus protegidos.");
    b->dados[SALMOS].capitulos[83].versos[4] = _("Dizem eles: Vinde, e apaguemo-los para que não sejam nação, nem seja lembrado mais o nome de Israel.");
    b->dados[SALMOS].capitulos[83].versos[5] = _("Pois à uma se conluiam; aliam-se contra ti");
    b->dados[SALMOS].capitulos[83].versos[6] = _("as tendas de Edom e os ismaelitas, Moabe e os hagarenos,");
    b->dados[SALMOS].capitulos[83].versos[7] = _("Gebal, Amom e Amaleque, e a Filístia com os habitantes de tiro.");
    b->dados[SALMOS].capitulos[83].versos[8] = _("Também a Assíria se ligou a eles; eles são o braço forte dos filhos de Ló.");
    b->dados[SALMOS].capitulos[83].versos[9] = _("Faze-lhes como fizeste a Midiã, como a Sísera, como a Jabim junto ao rio Quisom,");
    b->dados[SALMOS].capitulos[83].versos[10] = _("os quais foram destruídos em En-Dor; tornaram-se esterco para a terra.");
    b->dados[SALMOS].capitulos[83].versos[11] = _("Faze aos seus nobres como a Orebe e a Zeebe; e a todos os seus príncipes como a Zebá e a Zalmuna,");
    b->dados[SALMOS].capitulos[83].versos[12] = _("que disseram: Tomemos para nós as pastagens de Deus.");
    b->dados[SALMOS].capitulos[83].versos[13] = _("Deus meu, faze-os como um turbilhão de pó, como a palha diante do vento.");
    b->dados[SALMOS].capitulos[83].versos[14] = _("Como o fogo queima um bosque, e como a chama incedeia as montanhas,");
    b->dados[SALMOS].capitulos[83].versos[15] = _("assim persegue-os com a tua tempestade, e assombra-os com o teu furacão.");
    b->dados[SALMOS].capitulos[83].versos[16] = _("Cobre-lhes o rosto de confusão, de modo que busquem o teu nome, Senhor.");
    b->dados[SALMOS].capitulos[83].versos[17] = _("Sejam envergonhados e conturbados perpetuamente; sejam confundidos, e pereçam,");
    b->dados[SALMOS].capitulos[83].versos[18] = _("para que saibam que só tu, cujo nome é o Senhor, és o Altíssimo sobre toda a terra.");

    b->dados[SALMOS].capitulos[84].versos[1] = _("Quão amável são os teus tabernáculos, ó Senhor dos exércitos!");
    b->dados[SALMOS].capitulos[84].versos[2] = _("A minha alma suspira! sim, desfalece pelos átrios do Senhor; o meu coração e a minha carne clamam pelo Deus vivo.");
    b->dados[SALMOS].capitulos[84].versos[3] = _("Até o pardal encontrou casa, e a andorinha ninho para si, onde crie os seus filhotes, junto aos teus altares, ó Senhor dos exércitos, Rei meu e Deus meu.");
    b->dados[SALMOS].capitulos[84].versos[4] = _("Bem-aventurados os que habitam em tua casa; louvar-te-ão continuamente.");
    b->dados[SALMOS].capitulos[84].versos[5] = _("Bem-aventurados os homens cuja força está em ti, em cujo coração os caminhos altos.");
    b->dados[SALMOS].capitulos[84].versos[6] = _("Passando pelo vale de Baca, fazem dele um lugar de fontes; e a primeira chuva o cobre de bênçãos.");
    b->dados[SALMOS].capitulos[84].versos[7] = _("Vão sempre aumentando de força; cada um deles aparece perante Deus em Sião.");
    b->dados[SALMOS].capitulos[84].versos[8] = _("Senhor Deus dos exércitos, escuta a minha oração; inclina os ouvidos, ó Deus de Jacó!");
    b->dados[SALMOS].capitulos[84].versos[9] = _("Olha, ó Deus, escudo nosso, e contempla o rosto do teu ungido.");
    b->dados[SALMOS].capitulos[84].versos[10] = _("Porque vale mais um dia nos teus átrios do que em outra parte mil. Preferiria estar à porta da casa do meu Deus, a habitar nas tendas da perversidade.");
    b->dados[SALMOS].capitulos[84].versos[11] = _("Porquanto o Senhor Deus é sol e escudo; o Senhor dará graça e glória; não negará bem algum aos que andam na retidão.");
    b->dados[SALMOS].capitulos[84].versos[12] = _("Ó Senhor dos exércitos, bem-aventurado o homem que em ti põe a sua confiança.");

    b->dados[SALMOS].capitulos[85].versos[1] = _("Mostraste favor, Senhor, à tua terra; fizeste regressar os cativos de Jacó.");
    b->dados[SALMOS].capitulos[85].versos[2] = _("Perdoaste a iniqüidade do teu povo; cobriste todos os seus pecados.");
    b->dados[SALMOS].capitulos[85].versos[3] = _("Retraíste toda a tua cólera; refreaste o ardor da tua ira.");
    b->dados[SALMOS].capitulos[85].versos[4] = _("Restabelece-nos, ó Deus da nossa salvação, e faze cessar a tua indignação contra nós.");
    b->dados[SALMOS].capitulos[85].versos[5] = _("Estarás para sempre irado contra nós? estenderás a tua ira a todas as gerações?");
    b->dados[SALMOS].capitulos[85].versos[6] = _("Não tornarás a vivificar-nos, para que o teu povo se regozije em ti?");
    b->dados[SALMOS].capitulos[85].versos[7] = _("Mostra-nos, Senhor, a tua benignidade, e concede-nos a tua salvação.");
    b->dados[SALMOS].capitulos[85].versos[8] = _("Escutarei o que Deus, o Senhor, disser; porque falará de paz ao seu povo, e aos seus santos, contanto que não voltem à insensatez.");
    b->dados[SALMOS].capitulos[85].versos[9] = _("Certamente que a sua salvação está perto daqueles que o temem, para que a glória habite em nossa terra.");
    b->dados[SALMOS].capitulos[85].versos[10] = _("A benignidade e a fidelidade se encontraram; a justiça e a paz se beijaram.");
    b->dados[SALMOS].capitulos[85].versos[11] = _("A fidelidade brota da terra, e a justiça olha desde o céu.");
    b->dados[SALMOS].capitulos[85].versos[12] = _("O Senhor dará o que é bom, e a nossa terra produzirá o seu fruto.");
    b->dados[SALMOS].capitulos[85].versos[13] = _("A justiça irá adiante dele, marcando o caminho com as suas pegadas.");

    b->dados[SALMOS].capitulos[86].versos[1] = _("Inclina, Senhor, os teus ouvidos, e ouve-me, porque sou pobre e necessitado.");
    b->dados[SALMOS].capitulos[86].versos[2] = _("Preserva a minha vida, pois sou piedoso; o Deus meu, salva o teu servo, que em ti confia.");
    b->dados[SALMOS].capitulos[86].versos[3] = _("Compadece-te de mim, ó Senhor, pois a ti clamo o dia todo.");
    b->dados[SALMOS].capitulos[86].versos[4] = _("Alegra a alma do teu servo, pois a ti, Senhor, elevo a minha alma.");
    b->dados[SALMOS].capitulos[86].versos[5] = _("Porque tu, Senhor, és bom, e pronto a perdoar, e abundante em benignidade para com todos os que te invocam.");
    b->dados[SALMOS].capitulos[86].versos[6] = _("Dá ouvidos, Senhor, à minha oração, e atende à voz das minhas súplicas.");
    b->dados[SALMOS].capitulos[86].versos[7] = _("No dia da minha angústia clamo a ti, porque tu me respondes.");
    b->dados[SALMOS].capitulos[86].versos[8] = _("Entre os deuses nenhum há semelhante a ti, Senhor, nem há obras como as tuas.");
    b->dados[SALMOS].capitulos[86].versos[9] = _("Todas as nações que fizeste virão e se prostrarão diante de ti, Senhor, e glorificarão o teu nome.");
    b->dados[SALMOS].capitulos[86].versos[10] = _("Ensina-me, Senhor, o teu caminho, e andarei na tua verdade; dispõe o meu coração para temer o teu nome.");
    b->dados[SALMOS].capitulos[86].versos[11] = _("Louvar-te-ei, Senhor Deus meu, de todo o meu coração, e glorificarei o teu nome para sempre.");
    b->dados[SALMOS].capitulos[86].versos[12] = _("Pois grande é a tua benignidade para comigo, e livraste a minha alma das profundezas do Seol.");
    b->dados[SALMOS].capitulos[86].versos[13] = _("Pois grande é a tua benignidade para comigo, e livraste a minha alma das profundezas do Seol.");
    b->dados[SALMOS].capitulos[86].versos[14] = _("Ó Deus, os soberbos têm-se levantado contra mim, e um bando de homens violentos procura tirar-me a vida; eles não te puseram diante dos seus olhos.");
    b->dados[SALMOS].capitulos[86].versos[15] = _("Mas tu, Senhor, és um Deus compassivo e benigno, longânimo, e abundante em graça e em fidelidade.");
    b->dados[SALMOS].capitulos[86].versos[16] = _("Volta-te para mim, e compadece-te de mim; dá a tua força ao teu servo, e a salva o filho da tua serva.");
    b->dados[SALMOS].capitulos[86].versos[17] = _("Mostra-me um sinal do teu favor, para que o vejam aqueles que me odeiam, e sejam envergonhados, por me haveres tu, Senhor, ajuntado e confortado.");

    b->dados[SALMOS].capitulos[87].versos[1] = _("O fundamento dela está nos montes santos.");
    b->dados[SALMOS].capitulos[87].versos[2] = _("O Senhor ama as portas de Sião mais do que todas as habitações de Jacó.");
    b->dados[SALMOS].capitulos[87].versos[3] = _("Coisas gloriosas se dizem de ti, ó cidade de Deus.");
    b->dados[SALMOS].capitulos[87].versos[4] = _("Farei menção de Raabe e de Babilônia dentre os que me conhecem; eis que da Filístia, e de Tiro, e da Etiópia, se dirá: Este nasceu ali.");
    b->dados[SALMOS].capitulos[87].versos[5] = _("Sim, de Sião se dirá: Este e aquele nasceram ali; e o próprio Altíssimo a estabelecerá.");
    b->dados[SALMOS].capitulos[87].versos[6] = _("O Senhor, ao registrar os povos, dirá: Este nasceu ali.");
    b->dados[SALMOS].capitulos[87].versos[7] = _("Tanto os cantores como os que tocam instrumentos dirão: Todas as minhas fontes estão em ti.");

    b->dados[SALMOS].capitulos[88].versos[1] = _("Ó Senhor, Deus da minha salvação, dia e noite clamo diante de ti.");
    b->dados[SALMOS].capitulos[88].versos[2] = _("Chegue à tua presença a minha oração, inclina os teus ouvidos ao meu clamor;");
    b->dados[SALMOS].capitulos[88].versos[3] = _("porque a minha alma está cheia de angústias, e a minha vida se aproxima do Seol.");
    b->dados[SALMOS].capitulos[88].versos[4] = _("Já estou contado com os que descem à cova; estou como homem sem forças,");
    b->dados[SALMOS].capitulos[88].versos[5] = _("atirado entre os finados; como os mortos que jazem na sepultura, dos quais já não te lembras, e que são desamparados da tua mão.");
    b->dados[SALMOS].capitulos[88].versos[6] = _("Puseste-me na cova mais profunda, em lugares escuros, nas profundezas.");
    b->dados[SALMOS].capitulos[88].versos[7] = _("Sobre mim pesa a tua cólera; tu me esmagaste com todas as tuas ondas.");
    b->dados[SALMOS].capitulos[88].versos[8] = _("Apartaste de mim os meus conhecidos, fizeste-me abominável para eles; estou encerrado e não posso sair.");
    b->dados[SALMOS].capitulos[88].versos[9] = _("Os meus olhos desfalecem por causa da aflição. Clamo a ti todo dia, Senhor, estendendo-te as minhas mãos.");
    b->dados[SALMOS].capitulos[88].versos[10] = _("Mostrarás tu maravilhas aos mortos? ou levantam-se os mortos para te louvar?");
    b->dados[SALMOS].capitulos[88].versos[11] = _("Será anunciada a tua benignidade na sepultura, ou a tua fidelidade no Abadom?");
    b->dados[SALMOS].capitulos[88].versos[12] = _("Serão conhecidas nas trevas as tuas maravilhas, e a tua justiça na terra do esquecimento?");
    b->dados[SALMOS].capitulos[88].versos[13] = _("Eu, porém, Senhor, clamo a ti; de madrugada a minha oração chega à tua presença.");
    b->dados[SALMOS].capitulos[88].versos[14] = _("Senhor, por que me rejeitas? por que escondes de mim a tua face?");
    b->dados[SALMOS].capitulos[88].versos[15] = _("Estou aflito, e prestes a morrer desde a minha mocidade; sofro os teus terrores, estou desamparado.");
    b->dados[SALMOS].capitulos[88].versos[16] = _("Sobre mim tem passado a tua ardente indignação; os teus terrores deram cabo de mim.");
    b->dados[SALMOS].capitulos[88].versos[17] = _("Como águas me rodeiam todo o dia; cercam-me todos juntos.");
    b->dados[SALMOS].capitulos[88].versos[18] = _("Aparte de mim amigos e companheiros; os meus conhecidos se acham nas trevas.");

    b->dados[SALMOS].capitulos[89].versos[1] = _("Cantarei para sempre as benignidades do Senhor; com a minha boca proclamarei a todas as gerações a tua fidelidade.");
    b->dados[SALMOS].capitulos[89].versos[2] = _("Digo, pois: A tua benignidade será renovada para sempre; tu confirmarás a tua fidelidade até nos céus, dizendo:");
    b->dados[SALMOS].capitulos[89].versos[3] = _("Fiz um pacto com o meu escolhido; jurei ao meu servo Davi:");
    b->dados[SALMOS].capitulos[89].versos[4] = _("Estabelecerei para sempre a tua descendência, e firmarei o teu trono por todas as gerações.");
    b->dados[SALMOS].capitulos[89].versos[5] = _("Os céus louvarão as tuas maravilhas, ó Senhor, e a tua fidelidade na assembléia dos santos.");
    b->dados[SALMOS].capitulos[89].versos[6] = _("Pois quem no firmamento se pode igualar ao Senhor? Quem entre os filhos de Deus é semelhante ao Senhor,");
    b->dados[SALMOS].capitulos[89].versos[7] = _("um Deus sobremodo tremendo na assembléia dos santos, e temível mais do que todos os que estão ao seu redor?");
    b->dados[SALMOS].capitulos[89].versos[8] = _("Ó Senhor, Deus dos exércitos, quem é poderoso como tu, Senhor, com a tua fidelidade ao redor de ti?");
    b->dados[SALMOS].capitulos[89].versos[9] = _("Tu dominas o ímpio do mar; quando as suas ondas se levantam tu as fazes aquietar.");
    b->dados[SALMOS].capitulos[89].versos[10] = _("Tu abateste a Raabe como se fora ferida de morte; com o teu braço poderoso espalhaste os teus inimigos.");
    b->dados[SALMOS].capitulos[89].versos[11] = _("São teus os céus, e tua é a terra; o mundo e a sua plenitude, tu os fundaste.");
    b->dados[SALMOS].capitulos[89].versos[12] = _("O norte e o sul, tu os criaste; o Tabor e o Hermom regozijam-se em teu nome.");
    b->dados[SALMOS].capitulos[89].versos[13] = _("Tu tens um braço poderoso; forte é a tua mão, e elevado a tua destra.");
    b->dados[SALMOS].capitulos[89].versos[14] = _("Justiça e juízo são a base do teu trono; benignidade e verdade vão adiante de ti.");
    b->dados[SALMOS].capitulos[89].versos[15] = _("Bem-aventurado o povo que conhece o som festivo, que anda, ó Senhor, na luz da tua face,");
    b->dados[SALMOS].capitulos[89].versos[16] = _("que se regozija em teu nome todo o dia, e na tua justiça é exaltado.");
    b->dados[SALMOS].capitulos[89].versos[17] = _("Pois tu és a glória da sua força; e pelo teu favor será exaltado o nosso poder.");
    b->dados[SALMOS].capitulos[89].versos[18] = _("Porque o Senhor é o nosso escudo, e o Santo de Israel é o nosso Rei.");
    b->dados[SALMOS].capitulos[89].versos[19] = _("Naquele tempo falaste em visão ao teu santo, e disseste: Coloquei a coroa num homem poderoso; exaltei um escolhido dentre o povo.");
    b->dados[SALMOS].capitulos[89].versos[20] = _("Achei Davi, meu servo; com o meu santo óleo o ungi.");
    b->dados[SALMOS].capitulos[89].versos[21] = _("A minha mão será sempre com ele, e o meu braço o fortalecerá.");
    b->dados[SALMOS].capitulos[89].versos[22] = _("O inimigo não o surpreenderá, nem o filho da perversidade o afligirá.");
    b->dados[SALMOS].capitulos[89].versos[23] = _("Eu esmagarei diante dele os seus adversários, e aos que o odeiam abaterei.");
    b->dados[SALMOS].capitulos[89].versos[24] = _("A minha fidelidade, porém, e a minha benignidade estarão com ele, e em meu nome será exaltado o seu poder.");
    b->dados[SALMOS].capitulos[89].versos[25] = _("Porei a sua mão sobre o mar, e a sua destra sobre os rios.");
    b->dados[SALMOS].capitulos[89].versos[26] = _("Ele me invocará, dizendo: Tu és meu pai, meu Deus, e a rocha da minha salvação.");
    b->dados[SALMOS].capitulos[89].versos[27] = _("Também lhe darei o lugar de primogênito; fá-lo-ei o mais excelso dos reis da terra.");
    b->dados[SALMOS].capitulos[89].versos[28] = _("Conservar-lhe-ei para sempre a minha benignidade, e o meu pacto com ele ficará firme.");
    b->dados[SALMOS].capitulos[89].versos[29] = _("Farei que subsista para sempre a sua descendência, e o seu trono como os dias dos céus.");
    b->dados[SALMOS].capitulos[89].versos[30] = _("Se os seus filhos deixarem a minha lei, e não andarem nas minhas ordenanças,");
    b->dados[SALMOS].capitulos[89].versos[31] = _("se profanarem os meus preceitos, e não guardarem os meus mandamentos,");
    b->dados[SALMOS].capitulos[89].versos[32] = _("então visitarei com vara a sua transgressão, e com açoites a sua iniqüidade.");
    b->dados[SALMOS].capitulos[89].versos[33] = _("Mas não lhe retirarei totalmente a minha benignidade, nem faltarei com a minha fidelidade.");
    b->dados[SALMOS].capitulos[89].versos[34] = _("Não violarei o meu pacto, nem alterarei o que saiu dos meus lábios.");
    b->dados[SALMOS].capitulos[89].versos[35] = _("Uma vez para sempre jurei por minha santidade; não mentirei a Davi.");
    b->dados[SALMOS].capitulos[89].versos[36] = _("A sua descendência subsistirá para sempre, e o seu trono será como o sol diante de mim;");
    b->dados[SALMOS].capitulos[89].versos[37] = _("será estabelecido para sempre como a lua, e ficará firme enquanto o céu durar.");
    b->dados[SALMOS].capitulos[89].versos[38] = _("Mas tu o repudiaste e rejeitaste, tu estás indignado contra o teu ungido.");
    b->dados[SALMOS].capitulos[89].versos[39] = _("Desprezaste o pacto feito com teu servo; profanaste a sua coroa, arrojando-a por terra.");
    b->dados[SALMOS].capitulos[89].versos[40] = _("Derribaste todos os seus muros; arruinaste as suas fortificações.");
    b->dados[SALMOS].capitulos[89].versos[41] = _("Todos os que passam pelo caminho o despojam; tornou-se objeto de opróbrio para os seus vizinhos.");
    b->dados[SALMOS].capitulos[89].versos[42] = _("Exaltaste a destra dos seus adversários; fizeste com que todos os seus inimigos se regozijassem.");
    b->dados[SALMOS].capitulos[89].versos[43] = _("Embotaste o fio da sua espada, e não o sustentaste na peleja;");
    b->dados[SALMOS].capitulos[89].versos[44] = _("fizeste cessar o seu esplendor, e arrojaste por terra o seu trono;");
    b->dados[SALMOS].capitulos[89].versos[45] = _("abreviaste os dias da sua mocidade; cobriste-o de vergonha.");
    b->dados[SALMOS].capitulos[89].versos[46] = _("Até quando, Senhor? Esconder-te-ás para sempre? Até quando arderá a tua ira como fogo?");
    b->dados[SALMOS].capitulos[89].versos[47] = _("Lembra-te de quão breves são os meus dias; de quão efêmeros criaste todos os filhos dos homens!");
    b->dados[SALMOS].capitulos[89].versos[48] = _("Que homem há que viva e não veja a morte? ou que se livre do poder do Seol?");
    b->dados[SALMOS].capitulos[89].versos[49] = _("Senhor, onde estão as tuas antigas benignidades, que juraste a Davi na tua fidelidade?");
    b->dados[SALMOS].capitulos[89].versos[50] = _("Lembre-te, Senhor, do opróbrio dos teus servos; e de como trago no meu peito os insultos de todos os povos poderosos,");
    b->dados[SALMOS].capitulos[89].versos[51] = _("com que os teus inimigos, ó Senhor, têm difamado, com que têm difamado os passos do teu ungido.");
    b->dados[SALMOS].capitulos[89].versos[52] = _("Bendito seja o Senhor para sempre. Amém e amém.");

    b->dados[SALMOS].capitulos[90].versos[1] = _("Senhor, tu tens sido o nosso refúgio de geração em geração.");
    b->dados[SALMOS].capitulos[90].versos[2] = _("Antes que nascessem os montes, ou que tivesses formado a terra e o mundo, sim, de eternidade a eternidade tu és Deus.");
    b->dados[SALMOS].capitulos[90].versos[3] = _("Tu reduzes o homem ao pó, e dizes: Voltai, filhos dos homens!");
    b->dados[SALMOS].capitulos[90].versos[4] = _("Porque mil anos aos teus olhos são como o dia de ontem que passou, e como uma vigília da noite.");
    b->dados[SALMOS].capitulos[90].versos[5] = _("Tu os levas como por uma torrente; são como um sono; de manhã são como a erva que cresce;");
    b->dados[SALMOS].capitulos[90].versos[6] = _("de manhã cresce e floresce; à tarde corta-se e seca.");
    b->dados[SALMOS].capitulos[90].versos[7] = _("Pois somos consumidos pela tua ira, e pelo teu furor somos conturbados.");
    b->dados[SALMOS].capitulos[90].versos[8] = _("Diante de ti puseste as nossas iniqüidades, à luz do teu rosto os nossos pecados ocultos.");
    b->dados[SALMOS].capitulos[90].versos[9] = _("Pois todos os nossos dias vão passando na tua indignação; acabam-se os nossos anos como um suspiro.");
    b->dados[SALMOS].capitulos[90].versos[10] = _("A duração da nossa vida é de setenta anos; e se alguns, pela sua robustez, chegam a oitenta anos, a medida deles é canseira e enfado; pois passa rapidamente, e nós voamos.");
    b->dados[SALMOS].capitulos[90].versos[11] = _("Quem conhece o poder da tua ira? e a tua cólera, segundo o temor que te é devido?");
    b->dados[SALMOS].capitulos[90].versos[12] = _("Ensina-nos a contar os nossos dias de tal maneira que alcancemos corações sábios.");
    b->dados[SALMOS].capitulos[90].versos[13] = _("Volta-te para nós, Senhor! Até quando? Tem compaixão dos teus servos.");
    b->dados[SALMOS].capitulos[90].versos[14] = _("Sacia-nos de manhã com a tua benignidade, para que nos regozijemos e nos alegremos todos os nossos dias.");
    b->dados[SALMOS].capitulos[90].versos[15] = _("Alegra-nos pelos dias em que nos afligiste, e pelos anos em que vimos o mal.");
    b->dados[SALMOS].capitulos[90].versos[16] = _("Apareça a tua obra aos teus servos, e a tua glória sobre seus filhos.");
    b->dados[SALMOS].capitulos[90].versos[17] = _("Seja sobre nós a graça do Senhor, nosso Deus; e confirma sobre nós a obra das nossas mãos; sim, confirma a obra das nossas mãos.");

    b->dados[SALMOS].capitulos[91].versos[1] = _("Aquele que habita no esconderijo do Altíssimo, à sombra do Todo-Poderoso descansará.");
    b->dados[SALMOS].capitulos[91].versos[2] = _("Direi do Senhor: Ele é o meu refúgio e a minha fortaleza, o meu Deus, em quem confio.");
    b->dados[SALMOS].capitulos[91].versos[3] = _("Porque ele te livra do laço do passarinho, e da peste perniciosa.");
    b->dados[SALMOS].capitulos[91].versos[4] = _("Ele te cobre com as suas penas, e debaixo das suas asas encontras refúgio; a sua verdade é escudo e broquel.");
    b->dados[SALMOS].capitulos[91].versos[5] = _("Não temerás os terrores da noite, nem a seta que voe de dia,");
    b->dados[SALMOS].capitulos[91].versos[6] = _("nem peste que anda na escuridão, nem mortandade que assole ao meio-dia.");
    b->dados[SALMOS].capitulos[91].versos[7] = _("Mil poderão cair ao teu lado, e dez mil à tua direita; mas tu não serás atingido.");
    b->dados[SALMOS].capitulos[91].versos[8] = _("Somente com os teus olhos contemplarás, e verás a recompensa dos ímpios.");
    b->dados[SALMOS].capitulos[91].versos[9] = _("Porquanto fizeste do Senhor o teu refúgio, e do Altíssimo a tua habitação,");
    b->dados[SALMOS].capitulos[91].versos[10] = _("nenhum mal te sucederá, nem praga alguma chegará à tua tenda.");
    b->dados[SALMOS].capitulos[91].versos[11] = _("Porque aos seus anjos dará ordem a teu respeito, para te guardarem em todos os teus caminhos.");
    b->dados[SALMOS].capitulos[91].versos[12] = _("Eles te susterão nas suas mãos, para que não tropeces em alguma pedra.");
    b->dados[SALMOS].capitulos[91].versos[13] = _("Pisarás o leão e a áspide; calcarás aos pés o filho do leão e a serpente.");
    b->dados[SALMOS].capitulos[91].versos[14] = _("Pois que tanto me amou, eu o livrarei; pô-lo-ei num alto retiro, porque ele conhece o meu nome.");
    b->dados[SALMOS].capitulos[91].versos[15] = _("Quando ele me invocar, eu lhe responderei; estarei com ele na angústia, livrá-lo-ei, e o honrarei.");
    b->dados[SALMOS].capitulos[91].versos[16] = _("Com longura de dias fartá-lo-ei, e lhe mostrarei a minha salvação.");

    b->dados[SALMOS].capitulos[92].versos[1] = _("Bom é render graças ao Senhor, e cantar louvores ao teu nome, ó Altíssimo,");
    b->dados[SALMOS].capitulos[92].versos[2] = _("anunciar de manhã a tua benignidade, e à noite a tua fidelidade,");
    b->dados[SALMOS].capitulos[92].versos[3] = _("sobre um instrumento de dez cordas, e sobre o saltério, ao som solene da harpa.");
    b->dados[SALMOS].capitulos[92].versos[4] = _("Pois me alegraste, Senhor, pelos teus feitos; exultarei nas obras das tuas mãos.");
    b->dados[SALMOS].capitulos[92].versos[5] = _("Quão grandes são, ó Senhor, as tuas obras! quão profundos são os teus pensamentos!");
    b->dados[SALMOS].capitulos[92].versos[6] = _("O homem néscio não sabe, nem o insensato entende isto:");
    b->dados[SALMOS].capitulos[92].versos[7] = _("quando os ímpios brotam como a erva, e florescem todos os que praticam a iniqüidade, é para serem destruídos para sempre.");
    b->dados[SALMOS].capitulos[92].versos[8] = _("Mas tu, Senhor, estás nas alturas para sempre.");
    b->dados[SALMOS].capitulos[92].versos[9] = _("Pois eis que os teus inimigos, Senhor, eis que os teus inimigos perecerão; serão dispersos todos os que praticam a iniqüidade.");
    b->dados[SALMOS].capitulos[92].versos[10] = _("Mas tens exaltado o meu poder, como o do boi selvagem; fui ungido com óleo fresco.");
    b->dados[SALMOS].capitulos[92].versos[11] = _("Os meus olhos já viram o que é feito dos que me espreitam, e os meus ouvidos já ouviram o que sucedeu aos malfeitores que se levantam contra mim.");
    b->dados[SALMOS].capitulos[92].versos[12] = _("Os justos florescerão como a palmeira, crescerão como o cedro no Líbano.");
    b->dados[SALMOS].capitulos[92].versos[13] = _("Estão plantados na casa do Senhor, florescerão nos átrios do nosso Deus.");
    b->dados[SALMOS].capitulos[92].versos[14] = _("Na velhice ainda darão frutos, serão viçosos e florescentes,");
    b->dados[SALMOS].capitulos[92].versos[15] = _("para proclamarem que o Senhor é reto. Ele é a minha rocha, e nele não há injustiça.");

    b->dados[SALMOS].capitulos[93].versos[1] = _("O Senhor reina; está vestido de majestade. O Senhor se revestiu, cingiu-se de fortaleza; o mundo também está estabelecido, de modo que não pode ser abalado.");
    b->dados[SALMOS].capitulos[93].versos[2] = _("O teu trono está firme desde a antigüidade; desde a eternidade tu existes.");
    b->dados[SALMOS].capitulos[93].versos[3] = _("Os rios levantaram, ó Senhor, os rios levantaram o seu ruído, os rios levantam o seu fragor.");
    b->dados[SALMOS].capitulos[93].versos[4] = _("Mais que o ruído das grandes águas, mais que as vagas estrondosas do mar, poderoso é o Senhor nas alturas.");
    b->dados[SALMOS].capitulos[93].versos[5] = _("Mui fiéis são os teus testemunhos; a santidade convém à tua casa, Senhor, para sempre.");

    b->dados[SALMOS].capitulos[94].versos[1] = _("Ó Senhor, Deus da vingança, ó Deus da vingança, resplandece!");
    b->dados[SALMOS].capitulos[94].versos[2] = _("Exalta-te, ó juiz da terra! dá aos soberbos o que merecem.");
    b->dados[SALMOS].capitulos[94].versos[3] = _("Até quando os ímpios, Senhor, até quando os ímpios exultarão?");
    b->dados[SALMOS].capitulos[94].versos[4] = _("Até quando falarão, dizendo coisas arrogantes, e se gloriarão todos os que praticam a iniqüidade?");
    b->dados[SALMOS].capitulos[94].versos[5] = _("Esmagam o teu povo, ó Senhor, e afligem a tua herança.");
    b->dados[SALMOS].capitulos[94].versos[6] = _("Matam a viúva e o estrangeiro, e tiram a vida ao órfão.");
    b->dados[SALMOS].capitulos[94].versos[7] = _("E dizem: O Senhor não vê; o Deus de Jacó não o percebe.");
    b->dados[SALMOS].capitulos[94].versos[8] = _("Atendei, ó néscios, dentre o povo; e vós, insensatos, quando haveis de ser sábios?");
    b->dados[SALMOS].capitulos[94].versos[9] = _("Aquele que fez ouvido, não ouvirá? ou aquele que formou o olho, não verá?");
    b->dados[SALMOS].capitulos[94].versos[10] = _("Porventura aquele que disciplina as nações, não corrigirá? Aquele que instrui o homem no conhecimento,");
    b->dados[SALMOS].capitulos[94].versos[11] = _("o Senhor, conhece os pensamentos do homem, que são vaidade.");
    b->dados[SALMOS].capitulos[94].versos[12] = _("Bem-aventurado é o homem a quem tu repreendes, ó Senhor, e a quem ensinas a tua lei,");
    b->dados[SALMOS].capitulos[94].versos[13] = _("para lhe dares descanso dos dias da adversidade, até que se abra uma cova para o ímpio.");
    b->dados[SALMOS].capitulos[94].versos[14] = _("Pois o Senhor não rejeitará o seu povo, nem desamparará a sua herança.");
    b->dados[SALMOS].capitulos[94].versos[15] = _("Mas o juízo voltará a ser feito com justiça, e hão de segui-lo todos os retos de coração.");
    b->dados[SALMOS].capitulos[94].versos[16] = _("Quem se levantará por mim contra os malfeitores? quem se porá ao meu lado contra os que praticam a iniqüidade?");
    b->dados[SALMOS].capitulos[94].versos[17] = _("Se o Senhor não tivesse sido o meu auxílio, já a minha alma estaria habitando no lugar do silêncio.");
    b->dados[SALMOS].capitulos[94].versos[18] = _("Quando eu disse: O meu pé resvala; a tua benignidade, Senhor, me susteve.");
    b->dados[SALMOS].capitulos[94].versos[19] = _("Quando os cuidados do meu coração se multiplicam, as tuas consolações recreiam a minha alma.");
    b->dados[SALMOS].capitulos[94].versos[20] = _("Pode acaso associar-se contigo o trono de iniqüidade, que forja o mal tendo a lei por pretexto?");
    b->dados[SALMOS].capitulos[94].versos[21] = _("Acorrem em tropel contra a vida do justo, e condenam o sangue inocente.");
    b->dados[SALMOS].capitulos[94].versos[22] = _("Mas o Senhor tem sido o meu alto retiro, e o meu Deus a rocha do meu alto retiro, e o meu Deus a rocha do meu refúgio.");
    b->dados[SALMOS].capitulos[94].versos[23] = _("Ele fará recair sobre eles a sua própria iniqüidade, e os destruirá na sua própria malícia; o Senhor nosso Deus os destruirá.");

    b->dados[SALMOS].capitulos[95].versos[1] = _("Vinde, cantemos alegremente ao Senhor, cantemos com júbilo à rocha da nossa salvação.");
    b->dados[SALMOS].capitulos[95].versos[2] = _("Apresentemo-nos diante dele com ações de graças, e celebremo-lo com salmos de louvor.");
    b->dados[SALMOS].capitulos[95].versos[3] = _("Porque o Senhor é Deus grande, e Rei grande acima de todos os deuses.");
    b->dados[SALMOS].capitulos[95].versos[4] = _("Nas suas mãos estão as profundezas da terra, e as alturas dos montes são suas.");
    b->dados[SALMOS].capitulos[95].versos[5] = _("Seu é o mar, pois ele o fez, e as suas mãos formaram a serra terra seca.");
    b->dados[SALMOS].capitulos[95].versos[6] = _("Oh, vinde, adoremos e prostremo-nos; ajoelhemos diante do Senhor, que nos criou.");
    b->dados[SALMOS].capitulos[95].versos[7] = _("Porque ele é o nosso Deus, e nós povo do seu pasto e ovelhas que ele conduz. Oxalá que hoje ouvísseis a sua voz:");
    b->dados[SALMOS].capitulos[95].versos[8] = _("Não endureçais o vosso coração como em Meribá, como no dia de Massá no deserto,");
    b->dados[SALMOS].capitulos[95].versos[9] = _("quando vossos pais me tentaram, me provaram e viram a minha obra.");
    b->dados[SALMOS].capitulos[95].versos[10] = _("Durante quarenta anos estive irritado com aquela geração, e disse: É um povo que erra de coração, e não conhece os meus caminhos;");
    b->dados[SALMOS].capitulos[95].versos[11] = _("por isso jurei na minha ira: Eles não entrarão no meu descanso.");

    b->dados[SALMOS].capitulos[96].versos[1] = _("Cantai ao Senhor um cântico novo, cantai ao Senhor, todos os moradores da terra.");
    b->dados[SALMOS].capitulos[96].versos[2] = _("Cantai ao Senhor, bendizei o seu nome; anunciai de dia em dia a sua salvação.");
    b->dados[SALMOS].capitulos[96].versos[3] = _("Anunciai entre as nações a sua glória, entre todos os povos as suas maravilhas.");
    b->dados[SALMOS].capitulos[96].versos[4] = _("Porque grande é o Senhor, e digno de ser louvado; ele é mais temível do que todos os deuses.");
    b->dados[SALMOS].capitulos[96].versos[5] = _("Porque todos os deuses dos povos são ídolos; mas o Senhor fez os céus.");
    b->dados[SALMOS].capitulos[96].versos[6] = _("Glória e majestade estão diante dele, força e formosura no seu santuário.");
    b->dados[SALMOS].capitulos[96].versos[7] = _("Tributai ao Senhor, ó famílias dos povos, tributai ao Senhor glória e força.");
    b->dados[SALMOS].capitulos[96].versos[8] = _("Tributai ao Senhor a glória devida ao seu nome; trazei oferendas, e entrai nos seus átrios.");
    b->dados[SALMOS].capitulos[96].versos[9] = _("Adorai ao Senhor vestidos de trajes santos; tremei diante dele, todos os habitantes da terra.");
    b->dados[SALMOS].capitulos[96].versos[10] = _("Dizei entre as nações: O Senhor reina; ele firmou o mundo, de modo que não pode ser abalado. Ele julgará os povos com retidão.");
    b->dados[SALMOS].capitulos[96].versos[11] = _("Alegrem-se os céus, e regozije-se a terra; brame o mar e a sua plenitude.");
    b->dados[SALMOS].capitulos[96].versos[12] = _("Exulte o campo, e tudo o que nele há; então cantarão de júbilo todas as árvores do bosque");
    b->dados[SALMOS].capitulos[96].versos[13] = _("diante do Senhor, porque ele vem, porque vem julgar a terra: julgará o mundo com justiça e os povos com a sua fidelidade.");

    b->dados[SALMOS].capitulos[97].versos[1] = _("O Senhor reina, regozije-se a terra; alegrem-se as numerosas ilhas.");
    b->dados[SALMOS].capitulos[97].versos[2] = _("Nuvens e escuridão estão ao redor dele; justiça e eqüidade são a base do seu trono.");
    b->dados[SALMOS].capitulos[97].versos[3] = _("Adiante dele vai um fogo que abrasa os seus inimigos em redor.");
    b->dados[SALMOS].capitulos[97].versos[4] = _("Os seus relâmpagos alumiam o mundo; a terra os vê e treme.");
    b->dados[SALMOS].capitulos[97].versos[5] = _("Os montes, como cerca, se derretem na presença do Senhor, na presença do Senhor de toda a terra.");
    b->dados[SALMOS].capitulos[97].versos[6] = _("Os céus anunciam a sua justiça, e todos os povos vêem a sua glória.");
    b->dados[SALMOS].capitulos[97].versos[7] = _("Confundidos são todos os que servem imagens esculpidas, que se gloriam de ídolos; prostrai-vos diante dele, todos os deuses.");
    b->dados[SALMOS].capitulos[97].versos[8] = _("Sião ouve e se alegra, e regozijam-se as filhas de Judá por causa dos teus juízos, Senhor.");
    b->dados[SALMOS].capitulos[97].versos[9] = _("Pois tu, Senhor, és o Altíssimo sobre toda a terra; tu és sobremodo exaltado acima de todos os deuses.");
    b->dados[SALMOS].capitulos[97].versos[10] = _("O Senhor ama aos que odeiam o mal; ele preserva as almas dos seus santos, ele os livra das mãos dos ímpios.");
    b->dados[SALMOS].capitulos[97].versos[11] = _("A luz é semeada para o justo, e a alegria para os retos de coração.");
    b->dados[SALMOS].capitulos[97].versos[12] = _("Alegrai-vos, ó justos, no Senhor, e rendei graças ao seu santo nome.");

    b->dados[SALMOS].capitulos[98].versos[1] = _("Cantai ao Senhor um cântico novo, porque ele tem feito maravilhas; a sua destra e o seu braço santo lhe alcançaram a vitória.");
    b->dados[SALMOS].capitulos[98].versos[2] = _("O Senhor fez notória a sua salvação, manifestou a sua justiça perante os olhos das nações.");
    b->dados[SALMOS].capitulos[98].versos[3] = _("Lembrou-se da sua misericórdia e da sua fidelidade para com a casa de Israel; todas as extremidades da terra viram a salvação do nosso Deus.");
    b->dados[SALMOS].capitulos[98].versos[4] = _("Celebrai com júbilo ao Senhor, todos os habitantes da terra; dai brados de alegria, regozijai-vos, e cantai louvores.");
    b->dados[SALMOS].capitulos[98].versos[5] = _("Louvai ao Senhor com a harpa; com a harpa e a voz de canto.");
    b->dados[SALMOS].capitulos[98].versos[6] = _("Com trombetas, e ao som de buzinas, exultai diante do Rei, o Senhor.");
    b->dados[SALMOS].capitulos[98].versos[7] = _("Brame o mar e a sua plenitude, o mundo e os que nele habitam;");
    b->dados[SALMOS].capitulos[98].versos[8] = _("batam palmas os rios; à uma regozijem-se os montes");
    b->dados[SALMOS].capitulos[98].versos[9] = _("diante do Senhor, porque vem julgar a terra; com justiça julgará o mundo, e os povos com eqüidade.");

    b->dados[SALMOS].capitulos[99].versos[1] = _("O Senhor reina, tremam os povos; ele está entronizado sobre os querubins, estremeça a terra.");
    b->dados[SALMOS].capitulos[99].versos[2] = _("O Senhor é grande em Sião, e exaltado acima de todos os povos.");
    b->dados[SALMOS].capitulos[99].versos[3] = _("Louvem o teu nome, grande e tremendo; pois é santo.");
    b->dados[SALMOS].capitulos[99].versos[4] = _("És Rei poderoso que amas a justiça; estabeleces a eqüidade, executas juízo e justiça em Jacó.");
    b->dados[SALMOS].capitulos[99].versos[5] = _("Exaltai o Senhor nosso Deus, e prostrai-vos diante do escabelo de seus pés; porque ele é santo.");
    b->dados[SALMOS].capitulos[99].versos[6] = _("Moisés e Arão entre os seus sacerdotes, e Samuel entre os que invocavam o seu nome, clamavam ao Senhor, e ele os ouvia.");
    b->dados[SALMOS].capitulos[99].versos[7] = _("Na coluna de nuvem lhes falava; eles guardavam os seus testemunhos, e os estatutos que lhes dera.");
    b->dados[SALMOS].capitulos[99].versos[8] = _("Tu os ouviste, Senhor nosso Deus; tu foste para eles um Deus perdoador, embora vingador dos seus atos.");
    b->dados[SALMOS].capitulos[99].versos[9] = _("Exaltai o Senhor nosso Deus e adorai-o no seu santo monte, porque o Senhor nosso Deus é santo.");

    b->dados[SALMOS].capitulos[100].versos[1] = _("Celebrai com júbilo ao Senhor, todos os habitantes da terra.");
    b->dados[SALMOS].capitulos[100].versos[2] = _("Servi ao Senhor com alegria, e apresentai-vos a ele com cântico.");
    b->dados[SALMOS].capitulos[100].versos[3] = _("Sabei que o Senhor é Deus! Foi ele quem nos fez, e somos dele; somos o seu povo e ovelhas do seu pasto.");
    b->dados[SALMOS].capitulos[100].versos[4] = _("Entrai pelas suas portas com ação de graças, e em seus átrios com louvor; dai-lhe graças e bendizei o seu nome.");
    b->dados[SALMOS].capitulos[100].versos[5] = _("Porque o Senhor é bom; a sua benignidade dura para sempre, e a sua fidelidade de geração em geração.");

    b->dados[SALMOS].capitulos[101].versos[1] = _("Cantarei a benignidade e o juízo; a ti, Senhor, cantarei.");
    b->dados[SALMOS].capitulos[101].versos[2] = _("Portar-me-ei sabiamente no caminho reto. Oh, quando virás ter comigo? Andarei em minha casa com integridade de coração.");
    b->dados[SALMOS].capitulos[101].versos[3] = _("Não porei coisa torpe diante dos meus olhos; aborreço as ações daqueles que se desviam; isso não se apagará a mim.");
    b->dados[SALMOS].capitulos[101].versos[4] = _("Longe de mim estará o coração perverso; não conhecerei o mal.");
    b->dados[SALMOS].capitulos[101].versos[5] = _("Aquele que difama o seu próximo às escondidas, eu o destruirei; aquele que tem olhar altivo e coração soberbo, não o tolerarei.");
    b->dados[SALMOS].capitulos[101].versos[6] = _("Os meus olhos estão sobre os fiéis da terra, para que habitem comigo; o que anda no caminho perfeito, esse me servirá.");
    b->dados[SALMOS].capitulos[101].versos[7] = _("O que usa de fraude não habitará em minha casa; o que profere mentiras não estará firme perante os meus olhos.");
    b->dados[SALMOS].capitulos[101].versos[8] = _("De manhã em manhã destruirei todos os ímpios da terra, para desarraigar da cidade do Senhor todos os que praticam a iniqüidade.");

    b->dados[SALMOS].capitulos[102].versos[1] = _("Ó Senhor, ouve a minha oração, e chegue a ti o meu clamor.");
    b->dados[SALMOS].capitulos[102].versos[2] = _("Não escondas de mim o teu rosto no dia da minha angústia; inclina para mim os teus ouvidos; no dia em que eu clamar, ouve-me depressa.");
    b->dados[SALMOS].capitulos[102].versos[3] = _("Pois os meus dias se desvanecem como fumaça, e os meus ossos ardem como um tição.");
    b->dados[SALMOS].capitulos[102].versos[4] = _("O meu coração está ferido e seco como a erva, pelo que até me esqueço de comer o meu pão.");
    b->dados[SALMOS].capitulos[102].versos[5] = _("Por causa do meu doloroso gemer, os meus ossos se apegam à minha carne.");
    b->dados[SALMOS].capitulos[102].versos[6] = _("Sou semelhante ao pelicano no deserto; cheguei a ser como a coruja das ruínas.");
    b->dados[SALMOS].capitulos[102].versos[7] = _("Vigio, e tornei-me como um passarinho solitário no telhado.");
    b->dados[SALMOS].capitulos[102].versos[8] = _("Os meus inimigos me afrontam todo o dia; os que contra mim se enfurecem, me amaldiçoam.");
    b->dados[SALMOS].capitulos[102].versos[9] = _("Pois tenho comido cinza como pão, e misturado com lágrimas a minha bebida,");
    b->dados[SALMOS].capitulos[102].versos[10] = _("por causa da tua indignação e da tua ira; pois tu me levantaste e me arrojaste de ti.");
    b->dados[SALMOS].capitulos[102].versos[11] = _("Os meus dias são como a sombra que declina, e eu, como a erva, me vou secando.");
    b->dados[SALMOS].capitulos[102].versos[12] = _("Mas tu, Senhor, estás entronizado para sempre, e o teu nome será lembrado por todas as gerações.");
    b->dados[SALMOS].capitulos[102].versos[13] = _("Tu te levantarás e terás piedade de Sião; pois é o tempo de te compadeceres dela, sim, o tempo determinado já chegou.");
    b->dados[SALMOS].capitulos[102].versos[14] = _("Porque os teus servos têm prazer nas pedras dela, e se compadecem do seu pó.");
    b->dados[SALMOS].capitulos[102].versos[15] = _("As nações, pois, temerão o nome do Senhor, e todos os reis da terra a tua glória,");
    b->dados[SALMOS].capitulos[102].versos[16] = _("quando o Senhor edificar a Sião, e na sua glória se manifestar,");
    b->dados[SALMOS].capitulos[102].versos[17] = _("atendendo à oração do desamparado, e não desprezando a sua súplica.");
    b->dados[SALMOS].capitulos[102].versos[18] = _("Escreva-se isto para a geração futura, para que um povo que está por vir louve ao Senhor.");
    b->dados[SALMOS].capitulos[102].versos[19] = _("Pois olhou do alto do seu santuário; dos céus olhou o Senhor para a terra,");
    b->dados[SALMOS].capitulos[102].versos[20] = _("para ouvir o gemido dos presos, para libertar os sentenciados à morte;");
    b->dados[SALMOS].capitulos[102].versos[21] = _("a fim de que seja anunciado em Sião o nome do Senhor, e o seu louvor em Jerusalém,");
    b->dados[SALMOS].capitulos[102].versos[22] = _("quando se congregarem os povos, e os reinos, para servirem ao Senhor.");
    b->dados[SALMOS].capitulos[102].versos[23] = _("Ele abateu a minha força no caminho; abreviou os meus dias.");
    b->dados[SALMOS].capitulos[102].versos[24] = _("Eu clamo: Deus meu, não me leves no meio dos meus dias, tu, cujos anos alcançam todas as gerações.");
    b->dados[SALMOS].capitulos[102].versos[25] = _("Desde a antigüidade fundaste a terra; e os céus são obra das tuas mãos.");
    b->dados[SALMOS].capitulos[102].versos[26] = _("Eles perecerão, mas tu permanecerás; todos eles, como um vestido, envelhecerão; como roupa os mudarás, e ficarão mudados.");
    b->dados[SALMOS].capitulos[102].versos[27] = _("Mas tu és o mesmo, e os teus anos não acabarão.");
    b->dados[SALMOS].capitulos[102].versos[28] = _("Os filhos dos teus servos habitarão seguros, e a sua descendência ficará firmada diante de ti.");

    b->dados[SALMOS].capitulos[103].versos[1] = _("Bendize, ó minha alma, ao Senhor, e tudo o que há em mim bendiga o seu santo nome.");
    b->dados[SALMOS].capitulos[103].versos[2] = _("Bendize, ó minha alma, ao Senhor, e não te esqueças de nenhum dos seus benefícios.");
    b->dados[SALMOS].capitulos[103].versos[3] = _("É ele quem perdoa todas as tuas iniqüidades, quem sara todas as tuas enfermidades,");
    b->dados[SALMOS].capitulos[103].versos[4] = _("quem redime a tua vida da cova, quem te coroa de benignidade e de misericórdia,");
    b->dados[SALMOS].capitulos[103].versos[5] = _("quem te supre de todo o bem, de sorte que a tua mocidade se renova como a da águia.");
    b->dados[SALMOS].capitulos[103].versos[6] = _("O Senhor executa atos de justiça, e juízo a favor de todos os oprimidos.");
    b->dados[SALMOS].capitulos[103].versos[7] = _("Fez notórios os seus caminhos a Moisés, e os seus feitos aos filhos de Israel.");
    b->dados[SALMOS].capitulos[103].versos[8] = _("Compassivo e misericordioso é o Senhor; tardio em irar-se e grande em benignidade.");
    b->dados[SALMOS].capitulos[103].versos[9] = _("Não repreenderá perpetuamente, nem para sempre conservará a sua ira.");
    b->dados[SALMOS].capitulos[103].versos[10] = _("Não nos trata segundo os nossos pecados, nem nos retribui segundo as nossas iniqüidades.");
    b->dados[SALMOS].capitulos[103].versos[11] = _("Pois quanto o céu está elevado acima da terra, assim é grande a sua benignidade para com os que o temem.");
    b->dados[SALMOS].capitulos[103].versos[12] = _("Quanto o oriente está longe do ocidente, tanto tem ele afastado de nós as nossas transgressões.");
    b->dados[SALMOS].capitulos[103].versos[13] = _("Como um pai se compadece de seus filhos, assim o Senhor se compadece daqueles que o temem.");
    b->dados[SALMOS].capitulos[103].versos[14] = _("Pois ele conhece a nossa estrutura; lembra-se de que somos pó.");
    b->dados[SALMOS].capitulos[103].versos[15] = _("Quanto ao homem, os seus dias são como a erva; como a flor do campo, assim ele floresce.");
    b->dados[SALMOS].capitulos[103].versos[16] = _("Pois, passando por ela o vento, logo se vai, e o seu lugar não a conhece mais.");
    b->dados[SALMOS].capitulos[103].versos[17] = _("Mas é de eternidade a eternidade a benignidade do Senhor sobre aqueles que o temem, e a sua justiça sobre os filhos dos filhos,");
    b->dados[SALMOS].capitulos[103].versos[18] = _("sobre aqueles que guardam o seu pacto, e sobre os que se lembram dos seus preceitos para os cumprirem.");
    b->dados[SALMOS].capitulos[103].versos[19] = _("O Senhor estabeleceu o seu trono nos céus, e o seu reino domina sobre tudo.");
    b->dados[SALMOS].capitulos[103].versos[20] = _("Bendizei ao Senhor, vós anjos seus, poderosos em força, que cumpris as suas ordens, obedecendo à voz da sua palavra!");
    b->dados[SALMOS].capitulos[103].versos[21] = _("Bendizei ao Senhor, vós todos os seus exércitos, vós ministros seus, que executais a sua vontade!");
    b->dados[SALMOS].capitulos[103].versos[22] = _("Bendizei ao Senhor, vós todas as suas obras, em todos os lugares do seu domínio! Bendizei, ó minha alma ao Senhor!");

    b->dados[SALMOS].capitulos[104].versos[1] = _("Bendize, ó minha alma, ao Senhor! Senhor, Deus meu, tu és magnificentíssimo! Estás vestido de honra e de majestade,");
    b->dados[SALMOS].capitulos[104].versos[2] = _("tu que te cobres de luz como de um manto, que estendes os céus como uma cortina.");
    b->dados[SALMOS].capitulos[104].versos[3] = _("És tu que pões nas águas os vigamentos da tua morada, que fazes das nuvens o teu carro, que andas sobre as asas do vento;");
    b->dados[SALMOS].capitulos[104].versos[4] = _("que fazes dos ventos teus mensageiros, dum fogo abrasador os teus ministros.");
    b->dados[SALMOS].capitulos[104].versos[5] = _("Lançaste os fundamentos da terra, para que ela não fosse abalada em tempo algum.");
    b->dados[SALMOS].capitulos[104].versos[6] = _("Tu a cobriste do abismo, como dum vestido; as águas estavam sobre as montanhas.");
    b->dados[SALMOS].capitulos[104].versos[7] = _("À tua repreensão fugiram; à voz do teu trovão puseram-se em fuga.");
    b->dados[SALMOS].capitulos[104].versos[8] = _("Elevaram-se as montanhas, desceram os vales, até o lugar que lhes determinaste.");
    b->dados[SALMOS].capitulos[104].versos[9] = _("Limite lhes traçaste, que não haviam de ultrapassar, para que não tornassem a cobrir a terra.");
    b->dados[SALMOS].capitulos[104].versos[10] = _("És tu que nos vales fazes rebentar nascentes, que correm entre as colinas.");
    b->dados[SALMOS].capitulos[104].versos[11] = _("Dão de beber a todos os animais do campo; ali os asnos monteses matam a sua sede.");
    b->dados[SALMOS].capitulos[104].versos[12] = _("Junto delas habitam as aves dos céus; dentre a ramagem fazem ouvir o seu canto.");
    b->dados[SALMOS].capitulos[104].versos[13] = _("Da tua alta morada regas os montes; a terra se farta do fruto das tuas obras.");
    b->dados[SALMOS].capitulos[104].versos[14] = _("Fazes crescer erva para os animais, e a verdura para uso do homem, de sorte que da terra tire o alimento,");
    b->dados[SALMOS].capitulos[104].versos[15] = _("o vinho que alegra o seu coração, o azeite que faz reluzir o seu rosto, e o pão que lhe fortalece o coração.");
    b->dados[SALMOS].capitulos[104].versos[16] = _("Saciam-se as árvores do Senhor, os cedros do Líbano que ele plantou,");
    b->dados[SALMOS].capitulos[104].versos[17] = _("nos quais as aves se aninham, e a cegonha, cuja casa está nos ciprestes.");
    b->dados[SALMOS].capitulos[104].versos[18] = _("Os altos montes são um refúgio para as cabras montesas, e as rochas para os querogrilos.");
    b->dados[SALMOS].capitulos[104].versos[19] = _("Designou a lua para marcar as estações; o sol sabe a hora do seu ocaso.");
    b->dados[SALMOS].capitulos[104].versos[20] = _("Fazes as trevas, e vem a noite, na qual saem todos os animais da selva.");
    b->dados[SALMOS].capitulos[104].versos[21] = _("Os leões novos os animais bramam pela presa, e de Deus buscam o seu sustento.");
    b->dados[SALMOS].capitulos[104].versos[22] = _("Quando nasce o sol, logo se recolhem e se deitam nos seus covis.");
    b->dados[SALMOS].capitulos[104].versos[23] = _("Então sai o homem para a sua lida e para o seu trabalho, até a tarde.");
    b->dados[SALMOS].capitulos[104].versos[24] = _("Ó Senhor, quão multiformes são as tuas obras! Todas elas as fizeste com sabedoria; a terra está cheia das tuas riquezas.");
    b->dados[SALMOS].capitulos[104].versos[25] = _("Eis também o vasto e espaçoso mar, no qual se movem seres inumeráveis, animais pequenos e grandes.");
    b->dados[SALMOS].capitulos[104].versos[26] = _("Ali andam os navios, e o leviatã que formaste para nele folgar.");
    b->dados[SALMOS].capitulos[104].versos[27] = _("Todos esperam de ti que lhes dês o sustento a seu tempo.");
    b->dados[SALMOS].capitulos[104].versos[28] = _("Tu lho dás, e eles o recolhem; abres a tua mão, e eles se fartam de bens.");
    b->dados[SALMOS].capitulos[104].versos[29] = _("Escondes o teu rosto, e ficam perturbados; se lhes tiras a respiração, morrem, e voltam para o seu pó.");
    b->dados[SALMOS].capitulos[104].versos[30] = _("Envias o teu fôlego, e são criados; e assim renovas a face da terra.");
    b->dados[SALMOS].capitulos[104].versos[31] = _("Permaneça para sempre a glória do Senhor; regozije-se o Senhor nas suas obras;");
    b->dados[SALMOS].capitulos[104].versos[32] = _("ele olha para a terra, e ela treme; ele toca nas montanhas, e elas fumegam.");
    b->dados[SALMOS].capitulos[104].versos[33] = _("Cantarei ao Senhor enquanto eu viver; cantarei louvores ao meu Deus enquanto eu existir.");
    b->dados[SALMOS].capitulos[104].versos[34] = _("Seja-lhe agradável a minha meditação; eu me regozijarei no Senhor.");
    b->dados[SALMOS].capitulos[104].versos[35] = _("Sejam extirpados da terra os pecadores, e não subsistam mais os ímpios. Bendize, ó minha alma, ao Senhor. Louvai ao Senhor.");

    b->dados[SALMOS].capitulos[105].versos[1] = _("Dai graças ao Senhor; invocai o seu nome; fazei conhecidos os seus feitos entre os povos.");
    b->dados[SALMOS].capitulos[105].versos[2] = _("Cantai-lhe, cantai-lhe louvores; falai de todas as suas maravilhas.");
    b->dados[SALMOS].capitulos[105].versos[3] = _("Gloriai-vos no seu santo nome; regozije-se o coração daqueles que buscam ao Senhor.");
    b->dados[SALMOS].capitulos[105].versos[4] = _("Buscai ao Senhor e a sua força; buscai a sua face continuamente.");
    b->dados[SALMOS].capitulos[105].versos[5] = _("Lembrai-vos das maravilhas que ele tem feito, dos seus prodígios e dos juízos da sua boca,");
    b->dados[SALMOS].capitulos[105].versos[6] = _("vós, descendência de Abraão, seu servo, vós, filhos de Jacó, seus escolhidos.");
    b->dados[SALMOS].capitulos[105].versos[7] = _("Ele é o Senhor nosso Deus; os seus juízos estão em toda a terra.");
    b->dados[SALMOS].capitulos[105].versos[8] = _("Lembra-se perpetuamente do seu pacto, da palavra que ordenou para mil gerações;");
    b->dados[SALMOS].capitulos[105].versos[9] = _("do pacto que fez com Abraão, e do seu juramento a Isaque;");
    b->dados[SALMOS].capitulos[105].versos[10] = _("o qual ele confirmou a Jacó por estatuto, e a Israel por pacto eterno,");
    b->dados[SALMOS].capitulos[105].versos[11] = _("dizendo: A ti darei a terra de Canaã, como porção da vossa herança.");
    b->dados[SALMOS].capitulos[105].versos[12] = _("Quando eles eram ainda poucos em número, de pouca importância, e forasteiros nela,");
    b->dados[SALMOS].capitulos[105].versos[13] = _("andando de nação em nação, dum reino para outro povo,");
    b->dados[SALMOS].capitulos[105].versos[14] = _("não permitiu que ninguém os oprimisse, e por amor deles repreendeu reis, dizendo:");
    b->dados[SALMOS].capitulos[105].versos[15] = _("Não toqueis nos meus ungidos, e não maltrateis os meus profetas.");
    b->dados[SALMOS].capitulos[105].versos[16] = _("Chamou a fome sobre a terra; retirou-lhes todo o sustento do pão.");
    b->dados[SALMOS].capitulos[105].versos[17] = _("Enviou adiante deles um varão; José foi vendido como escravo;");
    b->dados[SALMOS].capitulos[105].versos[18] = _("feriram-lhe os pés com grilhões; puseram-no a ferro,");
    b->dados[SALMOS].capitulos[105].versos[19] = _("até o tempo em que a sua palavra se cumpriu; a palavra do Senhor o provou.");
    b->dados[SALMOS].capitulos[105].versos[20] = _("O rei mandou, e fez soltá-lo; o governador dos povos o libertou.");
    b->dados[SALMOS].capitulos[105].versos[21] = _("Fê-lo senhor da sua casa, e governador de toda a sua fazenda,");
    b->dados[SALMOS].capitulos[105].versos[22] = _("para, a seu gosto, dar ordens aos príncipes, e ensinar aos anciãos a sabedoria.");
    b->dados[SALMOS].capitulos[105].versos[23] = _("Então Israel entrou no Egito, e Jacó peregrinou na terra de Cam.");
    b->dados[SALMOS].capitulos[105].versos[24] = _("E o Senhor multiplicou sobremodo o seu povo, e o fez mais poderoso do que os seus inimigos.");
    b->dados[SALMOS].capitulos[105].versos[25] = _("Mudou o coração destes para que odiassem o seu povo, e tratassem astutamente aos seus servos.");
    b->dados[SALMOS].capitulos[105].versos[26] = _("Enviou Moisés, seu servo, e Arão, a quem escolhera,");
    b->dados[SALMOS].capitulos[105].versos[27] = _("os quais executaram entre eles os seus sinais e prodígios na terra de Cam.");
    b->dados[SALMOS].capitulos[105].versos[28] = _("Mandou à escuridão que a escurecesse; e foram rebeldes à sua palavra.");
    b->dados[SALMOS].capitulos[105].versos[29] = _("Converteu-lhes as águas em sangue, e fez morrer os seus peixes.");
    b->dados[SALMOS].capitulos[105].versos[30] = _("A terra deles produziu rãs em abundância, até nas câmaras dos seus reis.");
    b->dados[SALMOS].capitulos[105].versos[31] = _("Ele falou, e vieram enxames de moscas em todo o seu termo.");
    b->dados[SALMOS].capitulos[105].versos[32] = _("Deu-lhes saraiva por chuva, e fogo abrasador na sua terra.");
    b->dados[SALMOS].capitulos[105].versos[33] = _("Feriu-lhes também as vinhas e os figueirais, e quebrou as árvores da sua terra.");
    b->dados[SALMOS].capitulos[105].versos[34] = _("Ele falou, e vieram gafanhotos, e pulgões em quantidade inumerável,");
    b->dados[SALMOS].capitulos[105].versos[35] = _("que comeram toda a erva da sua terra, e devoraram o fruto dos seus campos.");
    b->dados[SALMOS].capitulos[105].versos[36] = _("Feriu também todos os primogênitos da terra deles, as primícias de toda a sua força.");
    b->dados[SALMOS].capitulos[105].versos[37] = _("E fez sair os israelitas com prata e ouro, e entre as suas tribos não havia quem tropeçasse.");
    b->dados[SALMOS].capitulos[105].versos[38] = _("O Egito alegrou-se quando eles saíram, porque o temor deles o dominara.");
    b->dados[SALMOS].capitulos[105].versos[39] = _("Estendeu uma nuvem para os cobrir, e um fogo para os alumiar de noite.");
    b->dados[SALMOS].capitulos[105].versos[40] = _("Eles pediram, e ele fez vir codornizes, e os saciou com pão do céu.");
    b->dados[SALMOS].capitulos[105].versos[41] = _("Fendeu a rocha, e dela brotaram águas, que correram pelos lugares áridos como um rio.");
    b->dados[SALMOS].capitulos[105].versos[42] = _("Porque se lembrou da sua santa palavra, e de Abraão, seu servo.");
    b->dados[SALMOS].capitulos[105].versos[43] = _("Fez sair com alegria o seu povo, e com cânticos de júbilo os seus escolhidos.");
    b->dados[SALMOS].capitulos[105].versos[44] = _("Deu-lhes as terras das nações, e eles herdaram o fruto do trabalho dos povos,");
    b->dados[SALMOS].capitulos[105].versos[45] = _("para que guardassem os seus preceitos, e observassem as suas leis. Louvai ao Senhor");

    b->dados[SALMOS].capitulos[106].versos[1] = _("Louvai ao Senhor. Louvai ao Senhor, porque ele é bom; porque a sua benignidade dura para sempre.");
    b->dados[SALMOS].capitulos[106].versos[2] = _("Quem pode referir os poderosos feitos do Senhor, ou anunciar todo o seu louvor?");
    b->dados[SALMOS].capitulos[106].versos[3] = _("Bem-aventurados os que observam o direito, que praticam a justiça em todos os tempos.");
    b->dados[SALMOS].capitulos[106].versos[4] = _("Lembra-te de mim, Senhor, quando mostrares favor ao teu povo; visita-me com a tua salvação,");
    b->dados[SALMOS].capitulos[106].versos[5] = _("para que eu veja a prosperidade dos teus escolhidos, para que me alegre com a alegria da tua nação, e me glorie juntamente com a tua herança.");
    b->dados[SALMOS].capitulos[106].versos[6] = _("Nós pecamos, como nossos pais; cometemos a iniqüidade, andamos perversamente.");
    b->dados[SALMOS].capitulos[106].versos[7] = _("Nossos pais não atentaram para as tuas maravilhas no Egito, não se lembraram da multidão das tuas benignidades; antes foram rebeldes contra o Altíssimo junto ao Mar Vermelho.");
    b->dados[SALMOS].capitulos[106].versos[8] = _("Não obstante, ele os salvou por amor do seu nome, para fazer conhecido o seu poder.");
    b->dados[SALMOS].capitulos[106].versos[9] = _("Pois repreendeu o Mar Vermelho e este se secou; e os fez caminhar pelos abismos como pelo deserto.");
    b->dados[SALMOS].capitulos[106].versos[10] = _("Salvou-os da mão do adversário, livrou-os do poder do inimigo.");
    b->dados[SALMOS].capitulos[106].versos[11] = _("As águas, porém, cobriram os seus adversários; nem um só deles ficou.");
    b->dados[SALMOS].capitulos[106].versos[12] = _("Então creram nas palavras dele e cantaram-lhe louvor.");
    b->dados[SALMOS].capitulos[106].versos[13] = _("Cedo, porém, se esqueceram das suas obras; não esperaram pelo seu conselho;");
    b->dados[SALMOS].capitulos[106].versos[14] = _("mas deixaram-se levar pela cobiça no deserto, e tentaram a Deus no ermo.");
    b->dados[SALMOS].capitulos[106].versos[15] = _("E ele lhes deu o que pediram, mas fê-los definhar de doença.");
    b->dados[SALMOS].capitulos[106].versos[16] = _("Tiveram inveja de Moisés no acampamento, e de Arão, o santo do Senhor.");
    b->dados[SALMOS].capitulos[106].versos[17] = _("Abriu-se a terra, e engoliu a Datã, e cobriu a companhia de Abirão;");
    b->dados[SALMOS].capitulos[106].versos[18] = _("ateou-se um fogo no meio da congregação; e chama abrasou os ímpios.");
    b->dados[SALMOS].capitulos[106].versos[19] = _("Fizeram um bezerro em Horebe, e adoraram uma imagem de fundição.");
    b->dados[SALMOS].capitulos[106].versos[20] = _("Assim trocaram a sua glória pela figura de um boi que come erva.");
    b->dados[SALMOS].capitulos[106].versos[21] = _("Esqueceram-se de Deus seu Salvador, que fizera grandes coisas no Egito,");
    b->dados[SALMOS].capitulos[106].versos[22] = _("maravilhas na terra de Cam, coisas tremendas junto ao Mar Vermelho.");
    b->dados[SALMOS].capitulos[106].versos[23] = _("Pelo que os teria destruído, como dissera, se Moisés, seu escolhido, não se tivesse interposto diante dele, para desviar a sua indignação, a fim de que não os destruísse.");
    b->dados[SALMOS].capitulos[106].versos[24] = _("Também desprezaram a terra aprazível; não confiaram na sua promessa;");
    b->dados[SALMOS].capitulos[106].versos[25] = _("antes murmuraram em suas tendas e não deram ouvidos à voz do Senhor.");
    b->dados[SALMOS].capitulos[106].versos[26] = _("Pelo que levantou a sua mão contra eles, afirmando que os faria cair no deserto;");
    b->dados[SALMOS].capitulos[106].versos[27] = _("que dispersaria também a sua descendência entre as nações, e os espalharia pelas terras.");
    b->dados[SALMOS].capitulos[106].versos[28] = _("Também se apegaram a Baal-Peor, e comeram sacrifícios oferecidos aos mortos.");
    b->dados[SALMOS].capitulos[106].versos[29] = _("Assim o provocaram à ira com as suas ações; e uma praga rebentou entre eles.");
    b->dados[SALMOS].capitulos[106].versos[30] = _("Então se levantou Finéias, que executou o juízo; e cessou aquela praga.");
    b->dados[SALMOS].capitulos[106].versos[31] = _("E isto lhe foi imputado como justiça, de geração em geração, para sempre.");
    b->dados[SALMOS].capitulos[106].versos[32] = _("Indignaram-no também junto às águas de Meribá, de sorte que sucedeu mal a Moisés por causa deles;");
    b->dados[SALMOS].capitulos[106].versos[33] = _("porque amarguraram o seu espírito; e ele falou imprudentemente com seus lábios.");
    b->dados[SALMOS].capitulos[106].versos[34] = _("Não destruíram os povos, como o Senhor lhes ordenara;");
    b->dados[SALMOS].capitulos[106].versos[35] = _("antes se misturaram com as nações, e aprenderam as suas obras.");
    b->dados[SALMOS].capitulos[106].versos[36] = _("Serviram aos seus ídolos, que vieram a ser-lhes um laço;");
    b->dados[SALMOS].capitulos[106].versos[37] = _("sacrificaram seus filhos e suas filhas aos demônios;");
    b->dados[SALMOS].capitulos[106].versos[38] = _("e derramaram sangue inocente, o sangue de seus filhos e de suas filhas, que eles sacrificaram aos ídolos de Canaã; e a terra foi manchada com sangue.");
    b->dados[SALMOS].capitulos[106].versos[39] = _("Assim se contaminaram com as suas obras, e se prostituíram pelos seus feitos.");
    b->dados[SALMOS].capitulos[106].versos[40] = _("Pelo que se acendeu a ira do Senhor contra o seu povo, de modo que abominou a sua herança;");
    b->dados[SALMOS].capitulos[106].versos[41] = _("entregou-os nas mãos das nações, e aqueles que os odiavam dominavam sobre eles.");
    b->dados[SALMOS].capitulos[106].versos[42] = _("Os seus inimigos os oprimiram, e debaixo das mãos destes foram eles humilhados.");
    b->dados[SALMOS].capitulos[106].versos[43] = _("Muitas vezes os livrou; mas eles foram rebeldes nos seus desígnios, e foram abatidos pela sua iniqüidade.");
    b->dados[SALMOS].capitulos[106].versos[44] = _("Contudo, atentou para a sua aflição, quando ouviu o seu clamor;");
    b->dados[SALMOS].capitulos[106].versos[45] = _("e a favor deles lembrou-se do seu pacto, e aplacou-se, segundo a abundância da sua benignidade.");
    b->dados[SALMOS].capitulos[106].versos[46] = _("Por isso fez com que obtivessem compaixão da parte daqueles que os levaram cativos.");
    b->dados[SALMOS].capitulos[106].versos[47] = _("Salva-nos, Senhor, nosso Deus, e congrega-nos dentre as nações, para que louvemos o teu santo nome, e nos gloriemos no teu louvor.");
    b->dados[SALMOS].capitulos[106].versos[48] = _("Bendito seja o Senhor, Deus de Israel, de eternidade em eternidade! E diga todo o povo: Amém. Louvai ao Senhor.");

    b->dados[SALMOS].capitulos[107].versos[1] = _("Dai graças ao Senhor, porque ele é bom; porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[107].versos[2] = _("digam-no os remidos do Senhor, os quais ele remiu da mão do inimigo,");
    b->dados[SALMOS].capitulos[107].versos[3] = _("e os que congregou dentre as terras, do Oriente e do Ocidente, do Norte e do Sul.");
    b->dados[SALMOS].capitulos[107].versos[4] = _("Andaram desgarrados pelo deserto, por caminho ermo; não acharam cidade em que habitassem.");
    b->dados[SALMOS].capitulos[107].versos[5] = _("Andavam famintos e sedentos; desfalecia-lhes a alma.");
    b->dados[SALMOS].capitulos[107].versos[6] = _("E clamaram ao Senhor na sua tribulação, e ele os livrou das suas angústias;");
    b->dados[SALMOS].capitulos[107].versos[7] = _("conduziu-os por um caminho direito, para irem a uma cidade em que habitassem.");
    b->dados[SALMOS].capitulos[107].versos[8] = _("Dêem graças ao Senhor pela sua benignidade, e pelas suas maravilhas para com os filhos dos homens!");
    b->dados[SALMOS].capitulos[107].versos[9] = _("Pois ele satisfaz a alma sedenta, e enche de bens a alma faminta.");
    b->dados[SALMOS].capitulos[107].versos[10] = _("Quanto aos que se assentavam nas trevas e sombra da morte, presos em aflição e em ferros,");
    b->dados[SALMOS].capitulos[107].versos[11] = _("por se haverem rebelado contra as palavras de Deus, e desprezado o conselho do Altíssimo,");
    b->dados[SALMOS].capitulos[107].versos[12] = _("eis que lhes abateu o coração com trabalho; tropeçaram, e não houve quem os ajudasse.");
    b->dados[SALMOS].capitulos[107].versos[13] = _("Então clamaram ao Senhor na sua tribulação, e ele os livrou das suas angústias.");
    b->dados[SALMOS].capitulos[107].versos[14] = _("Tirou-os das trevas e da sombra da morte, e quebrou-lhes as prisões.");
    b->dados[SALMOS].capitulos[107].versos[15] = _("Dêem graças ao Senhor pela sua benignidade, e pelas suas maravilhas para com os filhos dos homens!");
    b->dados[SALMOS].capitulos[107].versos[16] = _("Pois quebrou as portas de bronze e despedaçou as trancas de ferro.");
    b->dados[SALMOS].capitulos[107].versos[17] = _("Os insensatos, por causa do seu caminho de transgressão, e por causa das suas iniqüidades, são afligidos.");
    b->dados[SALMOS].capitulos[107].versos[18] = _("A sua alma aborreceu toda sorte de comida, e eles chegaram até as portas da morte.");
    b->dados[SALMOS].capitulos[107].versos[19] = _("Então clamaram ao Senhor na sua tribulação, e ele os livrou das suas angústias.");
    b->dados[SALMOS].capitulos[107].versos[20] = _("Enviou a sua palavra, e os sarou, e os livrou da destruição.");
    b->dados[SALMOS].capitulos[107].versos[21] = _("Dêem graças ao Senhor pela sua benignidade, e pelas suas maravilhas para com os filhos dos homens!");
    b->dados[SALMOS].capitulos[107].versos[22] = _("Ofereçam sacrifícios de louvor, e relatem as suas obras com regozijo!");
    b->dados[SALMOS].capitulos[107].versos[23] = _("Os que descem ao mar em navios, os que fazem comércio nas grandes águas,");
    b->dados[SALMOS].capitulos[107].versos[24] = _("esses vêem as obras do Senhor, e as suas maravilhas no abismo.");
    b->dados[SALMOS].capitulos[107].versos[25] = _("Pois ele manda, e faz levantar o vento tempestuoso, que eleva as ondas do mar.");
    b->dados[SALMOS].capitulos[107].versos[26] = _("Eles sobem ao céu, descem ao abismo; esvaece-lhes a alma de aflição.");
    b->dados[SALMOS].capitulos[107].versos[27] = _("Balançam e cambaleiam como ébrios, e perdem todo o tino.");
    b->dados[SALMOS].capitulos[107].versos[28] = _("Então clamam ao Senhor na sua tribulação, e ele os livra das suas angústias.");
    b->dados[SALMOS].capitulos[107].versos[29] = _("Faz cessar a tormenta, de modo que se acalmam as ondas.");
    b->dados[SALMOS].capitulos[107].versos[30] = _("Então eles se alegram com a bonança; e assim ele os leva ao porto desejado.");
    b->dados[SALMOS].capitulos[107].versos[31] = _("Dêem graças ao Senhor pela sua benignidade, e pelas suas maravilhas para com os filhos dos homens!");
    b->dados[SALMOS].capitulos[107].versos[32] = _("Exaltem-no na congregação do povo, e louvem-no na assembléia dos anciãos!");
    b->dados[SALMOS].capitulos[107].versos[33] = _("Ele converte rios em deserto, e nascentes em terra sedenta;");
    b->dados[SALMOS].capitulos[107].versos[34] = _("a terra frutífera em deserto salgado, por causa da maldade dos que nela habitam.");
    b->dados[SALMOS].capitulos[107].versos[35] = _("Converte o deserto em lagos, e a terra seca em nascentes.");
    b->dados[SALMOS].capitulos[107].versos[36] = _("E faz habitar ali os famintos, que edificam uma cidade para sua habitação;");
    b->dados[SALMOS].capitulos[107].versos[37] = _("semeiam campos e plantam vinhas, que produzem frutos abundantes.");
    b->dados[SALMOS].capitulos[107].versos[38] = _("Ele os abençoa, de modo que se multiplicam sobremaneira; e não permite que o seu gado diminua.");
    b->dados[SALMOS].capitulos[107].versos[39] = _("Quando eles decrescem e são abatidos pela opressão, aflição e tristeza,");
    b->dados[SALMOS].capitulos[107].versos[40] = _("ele lança o desprezo sobre os príncipes, e os faz desgarrados pelo deserto, onde não há caminho.");
    b->dados[SALMOS].capitulos[107].versos[41] = _("Mas levanta da opressão o necessitado para um alto retiro, e dá-lhe famílias como um rebanho.");
    b->dados[SALMOS].capitulos[107].versos[42] = _("Os retos o vêem e se regozijam, e toda a iniqüidade tapa a sua própria boca.");
    b->dados[SALMOS].capitulos[107].versos[43] = _("Quem é sábio observe estas coisas, e considere atentamente as benignidades do Senhor.");

    b->dados[SALMOS].capitulos[108].versos[1] = _("Preparado está o meu coração, ó Deus; cantarei, sim, cantarei louvores, com toda a minha alma.");
    b->dados[SALMOS].capitulos[108].versos[2] = _("Despertai, saltério e harpa; eu mesmo despertarei a aurora.");
    b->dados[SALMOS].capitulos[108].versos[3] = _("Louvar-te-ei entre os povos, Senhor, cantar-te-ei louvores entre as nações.");
    b->dados[SALMOS].capitulos[108].versos[4] = _("Pois grande, acima dos céus, é a tua benignidade, e a tua verdade ultrapassa as mais altas nuvens.");
    b->dados[SALMOS].capitulos[108].versos[5] = _("Sê exaltado, ó Deus, acima dos céus, e seja a tua glória acima de toda a terra!");
    b->dados[SALMOS].capitulos[108].versos[6] = _("Para que sejam livres os teus amados, salva-nos com a tua destra, e ouve-nos.");
    b->dados[SALMOS].capitulos[108].versos[7] = _("Deus falou no seu santuário: Eu me regozijarei; repartirei Siquém, e medirei o vale de Sucote.");
    b->dados[SALMOS].capitulos[108].versos[8] = _("Meu é Gileade, meu é Manassés; também Efraim é o meu capacete; Judá o meu cetro.");
    b->dados[SALMOS].capitulos[108].versos[9] = _("Moabe a minha bacia de lavar; sobre Edom lançarei o meu sapato; sobre a Filístia bradarei em triunfo.");
    b->dados[SALMOS].capitulos[108].versos[10] = _("Quem me conduzirá à cidade fortificada? Quem me guiará até Edom?");
    b->dados[SALMOS].capitulos[108].versos[11] = _("Porventura não nos rejeitaste, ó Deus? Não sais, ó Deus, com os nossos exércitos.");
    b->dados[SALMOS].capitulos[108].versos[12] = _("Dá-nos auxílio contra o adversário, pois vão é o socorro da parte do homem.");
    b->dados[SALMOS].capitulos[108].versos[13] = _("Em Deus faremos proezas; porque é ele quem calcará aos pés os nossos inimigos.");

    b->dados[SALMOS].capitulos[109].versos[1] = _("Ó Deus do meu louvor, não te cales;");
    b->dados[SALMOS].capitulos[109].versos[2] = _("pois a boca do ímpio e a boca fraudulenta se abrem contra mim; falam contra mim com uma língua mentirosa.");
    b->dados[SALMOS].capitulos[109].versos[3] = _("Eles me cercam com palavras de ódio, e pelejam contra mim sem causa.");
    b->dados[SALMOS].capitulos[109].versos[4] = _("Em paga do meu amor são meus adversários; mas eu me dedico à oração.");
    b->dados[SALMOS].capitulos[109].versos[5] = _("Retribuem-me o mal pelo bem, e o ódio pelo amor.");
    b->dados[SALMOS].capitulos[109].versos[6] = _("Põe sobre ele um ímpio, e esteja à sua direita um acusador.");
    b->dados[SALMOS].capitulos[109].versos[7] = _("Quando ele for julgado, saia condenado; e em pecado se lhe torne a sua oração!");
    b->dados[SALMOS].capitulos[109].versos[8] = _("Sejam poucos os seus dias, e outro tome o seu ofício!");
    b->dados[SALMOS].capitulos[109].versos[9] = _("Fiquem órfãos os seus filhos, e viúva a sua mulher!");
    b->dados[SALMOS].capitulos[109].versos[10] = _("Andem errantes os seus filhos, e mendiguem; esmolem longe das suas habitações assoladas.");
    b->dados[SALMOS].capitulos[109].versos[11] = _("O credor lance mão de tudo quanto ele tenha, e despojem-no os estranhos do fruto do seu trabalho!");
    b->dados[SALMOS].capitulos[109].versos[12] = _("Não haja ninguém que se compadeça dele, nem haja quem tenha pena dos seus órfãos!");
    b->dados[SALMOS].capitulos[109].versos[13] = _("Seja extirpada a sua posteridade; o seu nome seja apagado na geração seguinte!");
    b->dados[SALMOS].capitulos[109].versos[14] = _("Esteja na memória do Senhor a iniqüidade de seus pais; e não se apague o pecado de sua mãe!");
    b->dados[SALMOS].capitulos[109].versos[15] = _("Antes estejam sempre perante o Senhor, para que ele faça desaparecer da terra a memória deles!");
    b->dados[SALMOS].capitulos[109].versos[16] = _("Porquanto não se lembrou de usar de benignidade; antes perseguiu o varão aflito e o necessitado, como também o quebrantado de coração, para o matar.");
    b->dados[SALMOS].capitulos[109].versos[17] = _("Visto que amou a maldição, que ela lhe sobrevenha! Como não desejou a bênção, que ela se afaste dele!");
    b->dados[SALMOS].capitulos[109].versos[18] = _("Assim como se vestiu de maldição como dum vestido, assim penetre ela nas suas entranhas como água, e em seus ossos como azeite!");
    b->dados[SALMOS].capitulos[109].versos[19] = _("Seja para ele como o vestido com que ele se cobre, e como o cinto com que sempre anda cingido!");
    b->dados[SALMOS].capitulos[109].versos[20] = _("Seja este, da parte do Senhor, o galardão dos meus adversários, e dos que falam mal contra mim!");
    b->dados[SALMOS].capitulos[109].versos[21] = _("Mas tu, ó Deus, meu Senhor age em meu favor por amor do teu nome; pois que é boa a tua benignidade, livra-me;");
    b->dados[SALMOS].capitulos[109].versos[22] = _("pois sou pobre e necessitado, e dentro de mim está ferido o meu coração.");
    b->dados[SALMOS].capitulos[109].versos[23] = _("Eis que me vou como a sombra que declina; sou arrebatado como o gafanhoto.");
    b->dados[SALMOS].capitulos[109].versos[24] = _("Os meus joelhos estão enfraquecidos pelo jejum, e a minha carne perde a sua gordura.");
    b->dados[SALMOS].capitulos[109].versos[25] = _("Eu sou para eles objeto de opróbrio; ao me verem, meneiam a cabeça.");
    b->dados[SALMOS].capitulos[109].versos[26] = _("Ajuda-me, Senhor, Deus meu; salva-me segundo a tua benignidade.");
    b->dados[SALMOS].capitulos[109].versos[27] = _("Saibam que nisto está a tua mão, e que tu, Senhor, o fizeste.");
    b->dados[SALMOS].capitulos[109].versos[28] = _("Amaldiçoem eles, mas abençoa tu; fiquem confundidos os meus adversários; mas alegre-se o teu servo!");
    b->dados[SALMOS].capitulos[109].versos[29] = _("Vistam-se de ignomínia os meus acusadores, e cubram-se da sua própria vergonha como dum manto!");
    b->dados[SALMOS].capitulos[109].versos[30] = _("Muitas graças darei ao Senhor com a minha boca;");
    b->dados[SALMOS].capitulos[109].versos[31] = _("Pois ele se coloca à direita do poder, para o salvar dos que o condenam.");

    b->dados[SALMOS].capitulos[110].versos[1] = _("Disse o Senhor ao meu Senhor: Assenta-te à minha direita, até que eu ponha os teus inimigos por escabelo dos teus pés.");
    b->dados[SALMOS].capitulos[110].versos[2] = _("O Senhor enviará de Sião o cetro do teu poder. Domina no meio dos teus inimigos.");
    b->dados[SALMOS].capitulos[110].versos[3] = _("O teu povo apresentar-se-á voluntariamente no dia do teu poder, em trajes santos; como vindo do próprio seio da alva, será o orvalho da tua mocidade.");
    b->dados[SALMOS].capitulos[110].versos[4] = _("Jurou o Senhor, e não se arrependerá: Tu és sacerdote para sempre, segundo a ordem de Melquisedeque.");
    b->dados[SALMOS].capitulos[110].versos[5] = _("O Senhor, à tua direita, quebrantará reis no dia da sua ira.");
    b->dados[SALMOS].capitulos[110].versos[6] = _("Julgará entre as nações; enchê-las-á de cadáveres; quebrantará os cabeças por toda a terra.");
    b->dados[SALMOS].capitulos[110].versos[7] = _("Pelo caminho beberá da corrente, e prosseguirá de cabeça erguida.");

    b->dados[SALMOS].capitulos[111].versos[1] = _("Louvai ao Senhor. De todo o coração darei graças ao Senhor, no concílio dos retos e na congregação.");
    b->dados[SALMOS].capitulos[111].versos[2] = _("Grandes são as obras do Senhor, e para serem estudadas por todos os que nelas se comprazem.");
    b->dados[SALMOS].capitulos[111].versos[3] = _("Glória e majestade há em sua obra; e a sua justiça permanece para sempre.");
    b->dados[SALMOS].capitulos[111].versos[4] = _("Ele fez memoráveis as suas maravilhas; compassivo e misericordioso é o Senhor.");
    b->dados[SALMOS].capitulos[111].versos[5] = _("Dá mantimento aos que o temem; lembra-se sempre do seu pacto.");
    b->dados[SALMOS].capitulos[111].versos[6] = _("Mostrou ao seu povo o poder das suas obras, dando-lhe a herança das nações.");
    b->dados[SALMOS].capitulos[111].versos[7] = _("As obras das suas mãos são verdade e justiça; fiéis são todos os seus preceitos;");
    b->dados[SALMOS].capitulos[111].versos[8] = _("firmados estão para todo o sempre; são feitos em verdade e retidão.");
    b->dados[SALMOS].capitulos[111].versos[9] = _("Enviou ao seu povo a redenção; ordenou para sempre o seu pacto; santo e tremendo é o seu nome.");
    b->dados[SALMOS].capitulos[111].versos[10] = _("O temor do Senhor é o princípio da sabedoria; têm bom entendimento todos os que cumprem os seus preceitos; o seu louvor subsiste para sempre.");

    b->dados[SALMOS].capitulos[112].versos[1] = _("Louvai ao Senhor. Bem-aventurado o homem que teme ao Senhor, que em seus mandamentos tem grande prazer!");
    b->dados[SALMOS].capitulos[112].versos[2] = _("A sua descendência será poderosa na terra; a geração dos retos será abençoada.");
    b->dados[SALMOS].capitulos[112].versos[3] = _("Bens e riquezas há na sua casa; e a sua justiça permanece para sempre.");
    b->dados[SALMOS].capitulos[112].versos[4] = _("Aos retos nasce luz nas trevas; ele é compassivo, misericordioso e justo.");
    b->dados[SALMOS].capitulos[112].versos[5] = _("Ditoso é o homem que se compadece, e empresta, que conduz os seus negócios com justiça;");
    b->dados[SALMOS].capitulos[112].versos[6] = _("pois ele nunca será abalado; o justo ficará em memória eterna.");
    b->dados[SALMOS].capitulos[112].versos[7] = _("Ele não teme más notícias; o seu coração está firme, confiando no Senhor.");
    b->dados[SALMOS].capitulos[112].versos[8] = _("O seu coração está bem firmado, ele não terá medo, até que veja cumprido o seu desejo sobre os seus adversários.");
    b->dados[SALMOS].capitulos[112].versos[9] = _("Espalhou, deu aos necessitados; a sua justiça subsiste para sempre; o seu poder será exaltado em honra.");
    b->dados[SALMOS].capitulos[112].versos[10] = _("O ímpio vê isto e se enraivece; range os dentes e se consome; o desejo dos ímpios perecerá.");

    b->dados[SALMOS].capitulos[113].versos[1] = _("Louvai ao Senhor. Louvai, servos do Senhor, louvai o nome do Senhor.");
    b->dados[SALMOS].capitulos[113].versos[2] = _("Bendito seja o nome do Senhor, desde agora e para sempre.");
    b->dados[SALMOS].capitulos[113].versos[3] = _("Desde o nascimento do sol até o seu ocaso, há de ser louvado o nome do Senhor.");
    b->dados[SALMOS].capitulos[113].versos[4] = _("Exaltado está o Senhor acima de todas as nações, e a sua glória acima dos céus.");
    b->dados[SALMOS].capitulos[113].versos[5] = _("Quem é semelhante ao Senhor nosso Deus, que tem o seu assento nas alturas,");
    b->dados[SALMOS].capitulos[113].versos[6] = _("que se inclina para ver o que está no céu e na terra?");
    b->dados[SALMOS].capitulos[113].versos[7] = _("Ele levanta do pó o pobre, e do monturo ergue o necessitado,");
    b->dados[SALMOS].capitulos[113].versos[8] = _("para o fazer sentar com os príncipes, sim, com os príncipes do seu povo.");
    b->dados[SALMOS].capitulos[113].versos[9] = _("Ele faz com que a mulher estéril habite em família, e seja alegre mãe de filhos. Louvai ao Senhor.");

    b->dados[SALMOS].capitulos[114].versos[1] = _("Quando Israel saiu do Egito, e a casa de Jacó dentre um povo de língua estranha,");
    b->dados[SALMOS].capitulos[114].versos[2] = _("Judá tornou-lhe o santuário, e Israel o seu domínio.");
    b->dados[SALMOS].capitulos[114].versos[3] = _("O mar viu isto, e fugiu; o Jordão tornou atrás.");
    b->dados[SALMOS].capitulos[114].versos[4] = _("Os montes saltaram como carneiros, e os outeiros como cordeiros do rebanho.");
    b->dados[SALMOS].capitulos[114].versos[5] = _("Que tens tu, ó mar, para fugires? e tu, ó Jordão, para tornares atrás?");
    b->dados[SALMOS].capitulos[114].versos[6] = _("E vós, montes, que saltais como carneiros, e vós outeiros, como cordeiros do rebanho?");
    b->dados[SALMOS].capitulos[114].versos[7] = _("Treme, ó terra, na presença do Senhor, na presença do Deus de Jacó,");
    b->dados[SALMOS].capitulos[114].versos[8] = _("o qual converteu a rocha em lago de águas, a pederneira em manancial.");

    b->dados[SALMOS].capitulos[115].versos[1] = _("Não a nós, Senhor, não a nós, mas ao teu nome dá glória, por amor da tua benignidade e da tua verdade.");
    b->dados[SALMOS].capitulos[115].versos[2] = _("Por que perguntariam as nações: Onde está o seu Deus?");
    b->dados[SALMOS].capitulos[115].versos[3] = _("Mas o nosso Deus está nos céus; ele faz tudo o que lhe apraz.");
    b->dados[SALMOS].capitulos[115].versos[4] = _("Os ídolos deles são prata e ouro, obra das mãos do homem.");
    b->dados[SALMOS].capitulos[115].versos[5] = _("Têm boca, mas não falam; têm olhos, mas não vêem;");
    b->dados[SALMOS].capitulos[115].versos[6] = _("têm ouvidos, mas não ouvem; têm nariz, mas não cheiram;");
    b->dados[SALMOS].capitulos[115].versos[7] = _("têm mãos, mas não apalpam; têm pés, mas não andam; nem som algum sai da sua garganta.");
    b->dados[SALMOS].capitulos[115].versos[8] = _("Semelhantes a eles sejam os que fazem, e todos os que neles confiam.");
    b->dados[SALMOS].capitulos[115].versos[9] = _("Confia, ó Israel, no Senhor; ele é seu auxílio e seu escudo.");
    b->dados[SALMOS].capitulos[115].versos[10] = _("Casa de Arão, confia no Senhor; ele é seu auxílio e seu escudo.");
    b->dados[SALMOS].capitulos[115].versos[11] = _("Vós, os que temeis ao Senhor, confiai no Senhor; ele é seu auxílio e seu escudo.");
    b->dados[SALMOS].capitulos[115].versos[12] = _("O Senhor tem-se lembrado de nós, abençoar-nos-á; abençoará a casa de Israel; abençoará a casa de Arão;");
    b->dados[SALMOS].capitulos[115].versos[13] = _("abençoará os que temem ao Senhor, tanto pequenos como grandes.");
    b->dados[SALMOS].capitulos[115].versos[14] = _("Aumente-vos o Senhor cada vez mais, a vós e a vossos filhos.");
    b->dados[SALMOS].capitulos[115].versos[15] = _("Sede vós benditos do Senhor, que fez os céus e a terra.");
    b->dados[SALMOS].capitulos[115].versos[16] = _("Os céus são os céus do Senhor, mas a terra, deu-a ele aos filhos dos homens.");
    b->dados[SALMOS].capitulos[115].versos[17] = _("Os mortos não louvam ao Senhor, nem os que descem ao silêncio;");
    b->dados[SALMOS].capitulos[115].versos[18] = _("nós, porém, bendiremos ao Senhor, desde agora e para sempre. Louvai ao Senhor.");

    b->dados[SALMOS].capitulos[116].versos[1] = _("Amo ao Senhor, porque ele ouve a minha voz e a minha súplica.");
    b->dados[SALMOS].capitulos[116].versos[2] = _("Porque inclina para mim o seu ouvido, invocá-lo-ei enquanto viver.");
    b->dados[SALMOS].capitulos[116].versos[3] = _("Os laços da morte me cercaram; as angústias do Seol se apoderaram de mim; sofri tribulação e tristeza.");
    b->dados[SALMOS].capitulos[116].versos[4] = _("Então invoquei o nome do Senhor, dizendo: Ó Senhor, eu te rogo, livra-me.");
    b->dados[SALMOS].capitulos[116].versos[5] = _("Compassivo é o Senhor, e justo; sim, misericordioso é o nosso Deus.");
    b->dados[SALMOS].capitulos[116].versos[6] = _("O Senhor guarda os simples; quando me acho abatido, ele me salva.");
    b->dados[SALMOS].capitulos[116].versos[7] = _("Volta, minha alma, ao teu repouso, pois o Senhor te fez bem.");
    b->dados[SALMOS].capitulos[116].versos[8] = _("Pois livraste a minha alma da morte, os meus olhos das lágrimas, e os meus pés de tropeçar.");
    b->dados[SALMOS].capitulos[116].versos[9] = _("Andarei perante o Senhor, na terra dos viventes.");
    b->dados[SALMOS].capitulos[116].versos[10] = _("Cri, por isso falei; estive muito aflito.");
    b->dados[SALMOS].capitulos[116].versos[11] = _("Eu dizia na minha precipitação: Todos os homens são mentirosos.");
    b->dados[SALMOS].capitulos[116].versos[12] = _("Que darei eu ao Senhor por todos os benefícios que me tem feito?");
    b->dados[SALMOS].capitulos[116].versos[13] = _("Tomarei o cálice da salvação, e invocarei o nome do Senhor.");
    b->dados[SALMOS].capitulos[116].versos[14] = _("Pagarei os meus votos ao Senhor, na presença de todo o seu povo.");
    b->dados[SALMOS].capitulos[116].versos[15] = _("Preciosa é à vista do Senhor a morte dos seus santos.");
    b->dados[SALMOS].capitulos[116].versos[16] = _("Ó Senhor, deveras sou teu servo; sou teu servo, filho da tua serva; soltaste as minhas cadeias.");
    b->dados[SALMOS].capitulos[116].versos[17] = _("Oferecer-te-ei sacrifícios de ação de graças, e invocarei o nome do Senhor.");
    b->dados[SALMOS].capitulos[116].versos[18] = _("Pagarei os meus votos ao Senhor, na presença de todo o seu povo,");
    b->dados[SALMOS].capitulos[116].versos[19] = _("nos átrios da casa do Senhor, no meio de ti, ó Jerusalém! Louvai ao Senhor.");

    b->dados[SALMOS].capitulos[117].versos[1] = _("Louvai ao Senhor todas as nações, exaltai-o todos os povos.");
    b->dados[SALMOS].capitulos[117].versos[2] = _("Porque a sua benignidade é grande para conosco, e a verdade do Senhor dura para sempre. Louvai ao Senhor.");

    b->dados[SALMOS].capitulos[118].versos[1] = _("Dai graças ao Senhor, porque ele é bom; porque a sua benignidade dura para sempre.");
    b->dados[SALMOS].capitulos[118].versos[2] = _("Diga, pois, Israel: A sua benignidade dura para sempre.");
    b->dados[SALMOS].capitulos[118].versos[3] = _("Diga, pois, a casa de Arão: A sua benignidade dura para sempre.");
    b->dados[SALMOS].capitulos[118].versos[4] = _("Digam, pois, os que temem ao Senhor: A sua benignidade dura para sempre.");
    b->dados[SALMOS].capitulos[118].versos[5] = _("Do meio da angústia invoquei o Senhor; o Senhor me ouviu, e me pôs em um lugar largo.");
    b->dados[SALMOS].capitulos[118].versos[6] = _("O Senhor é por mim, não recearei; que me pode fazer o homem?");
    b->dados[SALMOS].capitulos[118].versos[7] = _("O Senhor é por mim entre os que me ajudam; pelo que verei cumprido o meu desejo sobre os que me odeiam.");
    b->dados[SALMOS].capitulos[118].versos[8] = _("É melhor refugiar-se no Senhor do que confiar no homem.");
    b->dados[SALMOS].capitulos[118].versos[9] = _("É melhor refugiar-se no Senhor do que confiar nos príncipes.");
    b->dados[SALMOS].capitulos[118].versos[10] = _("Todas as nações me cercaram, mas em nome do Senhor eu as exterminei.");
    b->dados[SALMOS].capitulos[118].versos[11] = _("Cercaram-me, sim, cercaram-me; mas em nome do Senhor eu as exterminei.");
    b->dados[SALMOS].capitulos[118].versos[12] = _("Cercaram-me como abelhas, mas apagaram-se como fogo de espinhos; pois em nome do Senhor as exterminei.");
    b->dados[SALMOS].capitulos[118].versos[13] = _("Com força me impeliste para me fazeres cair, mas o Senhor me ajudou.");
    b->dados[SALMOS].capitulos[118].versos[14] = _("O Senhor é a minha força e o meu cântico; tornou-se a minha salvação.");
    b->dados[SALMOS].capitulos[118].versos[15] = _("Nas tendas dos justos há jubiloso cântico de vitória; a destra do Senhor faz proezas.");
    b->dados[SALMOS].capitulos[118].versos[16] = _("A destra do Senhor se exalta, a destra do Senhor faz proezas.");
    b->dados[SALMOS].capitulos[118].versos[17] = _("Não morrerei, mas viverei, e contarei as obras do Senhor.");
    b->dados[SALMOS].capitulos[118].versos[18] = _("O Senhor castigou-me muito, mas não me entregou à morte.");
    b->dados[SALMOS].capitulos[118].versos[19] = _("Abre-me as portas da justiça, para que eu entre por elas e dê graças ao Senhor.");
    b->dados[SALMOS].capitulos[118].versos[20] = _("Esta é a porta do Senhor; por ela os justos entrarão.");
    b->dados[SALMOS].capitulos[118].versos[21] = _("Graças te dou porque me ouviste, e te tornaste a minha salvação.");
    b->dados[SALMOS].capitulos[118].versos[22] = _("A pedra que os edificadores rejeitaram, essa foi posta como pedra angular.");
    b->dados[SALMOS].capitulos[118].versos[23] = _("Foi o Senhor que fez isto e é maravilhoso aos nossos olhos.");
    b->dados[SALMOS].capitulos[118].versos[24] = _("Este é o dia que o Senhor fez; regozijemo-nos, e alegremo-nos nele.");
    b->dados[SALMOS].capitulos[118].versos[25] = _("Ó Senhor, salva, nós te pedimos; ó Senhor, nós te pedimos, envia-nos a prosperidade.");
    b->dados[SALMOS].capitulos[118].versos[26] = _("Bendito aquele que vem em nome do Senhor; da casa do Senhor vos bendizemos.");
    b->dados[SALMOS].capitulos[118].versos[27] = _("O Senhor é Deus, e nos concede a luz; atai a vítima da festa com cordas às pontas do altar.");
    b->dados[SALMOS].capitulos[118].versos[28] = _("Tu és o meu Deus, e eu te darei graças; tu és o meu Deus, e eu te exaltarei.");
    b->dados[SALMOS].capitulos[118].versos[29] = _("Dai graças ao Senhor, porque ele é bom; porque a sua benignidade dura para sempre. a tua palavra.");

    b->dados[SALMOS].capitulos[119].versos[1] = _("Bem-aventurados os que trilham com integridade o seu caminho, os que andam na lei do Senhor!");
    b->dados[SALMOS].capitulos[119].versos[2] = _("Bem-aventurados os que guardam os seus testemunhos, que o buscam de todo o coração,");
    b->dados[SALMOS].capitulos[119].versos[3] = _("que não praticam iniqüidade, mas andam nos caminhos dele!");
    b->dados[SALMOS].capitulos[119].versos[4] = _("Tu ordenaste os teus preceitos, para que fossem diligentemente observados.");
    b->dados[SALMOS].capitulos[119].versos[5] = _("Oxalá sejam os meus caminhos dirigidos de maneira que eu observe os teus estatutos!");
    b->dados[SALMOS].capitulos[119].versos[6] = _("Então não ficarei confundido, atentando para todos os teus mandamentos.");
    b->dados[SALMOS].capitulos[119].versos[7] = _("Louvar-te-ei com retidão de coração, quando tiver aprendido as tuas retas ordenanças.");
    b->dados[SALMOS].capitulos[119].versos[8] = _("Observarei os teus estatutos; não me desampares totalmente!");
    b->dados[SALMOS].capitulos[119].versos[9] = _("Como purificará o jovem o seu caminho? Observando-o de acordo com a tua palavra.");
    b->dados[SALMOS].capitulos[119].versos[10] = _("De todo o meu coração tenho te buscado; não me deixes desviar dos teus mandamentos.");
    b->dados[SALMOS].capitulos[119].versos[11] = _("Escondi a tua palavra no meu coração, para não pecar contra ti.");
    b->dados[SALMOS].capitulos[119].versos[12] = _("Bendito és tu, ó Senhor; ensina-me os teus estatutos.");
    b->dados[SALMOS].capitulos[119].versos[13] = _("Com os meus lábios declaro todas as ordenanças da tua boca.");
    b->dados[SALMOS].capitulos[119].versos[14] = _("Regozijo-me no caminho dos teus testemunhos, tanto como em todas as riquezas.");
    b->dados[SALMOS].capitulos[119].versos[15] = _("Em teus preceitos medito, e observo os teus caminhos.");
    b->dados[SALMOS].capitulos[119].versos[16] = _("Deleitar-me-ei nos teus estatutos; não me esquecerei da tua palavra.");
    b->dados[SALMOS].capitulos[119].versos[17] = _("Faze bem ao teu servo, para que eu viva; assim observarei a tua palavra.");
    b->dados[SALMOS].capitulos[119].versos[18] = _("Desvenda os meus olhos, para que eu veja as maravilhas da tua lei.");
    b->dados[SALMOS].capitulos[119].versos[19] = _("Sou peregrino na terra; não escondas de mim os teus mandamentos.");
    b->dados[SALMOS].capitulos[119].versos[20] = _("A minha alma se consome de anelos por tuas ordenanças em todo o tempo.");
    b->dados[SALMOS].capitulos[119].versos[21] = _("Tu repreendeste os soberbos, os malditos, que se desviam dos teus mandamentos.");
    b->dados[SALMOS].capitulos[119].versos[22] = _("Tira de sobre mim o opróbrio e o desprezo, pois tenho guardado os teus testemunhos.");
    b->dados[SALMOS].capitulos[119].versos[23] = _("Príncipes sentaram-se e falavam contra mim, mas o teu servo meditava nos teus estatutos.");
    b->dados[SALMOS].capitulos[119].versos[24] = _("Os teus testemunhos são o meu prazer e os meus conselheiros.");
    b->dados[SALMOS].capitulos[119].versos[25] = _("A minha alma apega-se ao pó; vivifica-me segundo a tua palavra.");
    b->dados[SALMOS].capitulos[119].versos[26] = _("Meus caminhos te descrevi, e tu me ouviste; ensina-me os teus estatutos.");
    b->dados[SALMOS].capitulos[119].versos[27] = _("Faze-me entender o caminho dos teus preceitos; assim meditarei nas tuas maravilhas.");
    b->dados[SALMOS].capitulos[119].versos[28] = _("A minha alma se consome de tristeza; fortalece-me segundo a tua palavra.");
    b->dados[SALMOS].capitulos[119].versos[29] = _("Desvia de mim o caminho da falsidade, e ensina-me benignidade a tua lei.");
    b->dados[SALMOS].capitulos[119].versos[30] = _("Escolhi o caminho da fidelidade; diante de mim pus as tuas ordenanças.");
    b->dados[SALMOS].capitulos[119].versos[31] = _("Apego-me aos teus testemunhos, ó Senhor; não seja eu envergonhado.");
    b->dados[SALMOS].capitulos[119].versos[32] = _("Percorrerei o caminho dos teus mandamentos, quando dilatares o meu coração.");
    b->dados[SALMOS].capitulos[119].versos[33] = _("Ensina-me, ó Senhor, o caminho dos teus estatutos, e eu o guardarei até o fim.");
    b->dados[SALMOS].capitulos[119].versos[34] = _("Dá-me entendimento, para que eu guarde a tua lei, e a observe de todo o meu coração.");
    b->dados[SALMOS].capitulos[119].versos[35] = _("Faze-me andar na vereda dos teus mandamentos, porque nela me comprazo.");
    b->dados[SALMOS].capitulos[119].versos[36] = _("Inclina o meu coração para os teus testemunhos, e não para a cobiça.");
    b->dados[SALMOS].capitulos[119].versos[37] = _("Desvia os meus olhos de contemplarem a vaidade, e vivifica-me no teu caminho.");
    b->dados[SALMOS].capitulos[119].versos[38] = _("Confirma a tua promessa ao teu servo, que se inclina ao teu temor.");
    b->dados[SALMOS].capitulos[119].versos[39] = _("Desvia de mim o opróbrio que temo, pois as tuas ordenanças são boas.");
    b->dados[SALMOS].capitulos[119].versos[40] = _("Eis que tenho anelado os teus preceitos; vivifica-me por tua justiça.");
    b->dados[SALMOS].capitulos[119].versos[41] = _("Venha também sobre mim a tua benignidade, ó Senhor, e a tua salvação, segundo a tua palavra.");
    b->dados[SALMOS].capitulos[119].versos[42] = _("Assim terei o que responder ao que me afronta, pois confio na tua palavra.");
    b->dados[SALMOS].capitulos[119].versos[43] = _("De minha boca não tires totalmente a palavra da verdade, pois tenho esperado nos teus juízos.");
    b->dados[SALMOS].capitulos[119].versos[44] = _("Assim observarei de contínuo a tua lei, para sempre e eternamente;");
    b->dados[SALMOS].capitulos[119].versos[45] = _("e andarei em liberdade, pois tenho buscado os teus preceitos.");
    b->dados[SALMOS].capitulos[119].versos[46] = _("Falarei dos teus testemunhos perante os reis, e não me envergonharei.");
    b->dados[SALMOS].capitulos[119].versos[47] = _("Deleitar-me-ei em teus mandamentos, que eu amo.");
    b->dados[SALMOS].capitulos[119].versos[48] = _("Também levantarei as minhas mãos para os teus mandamentos, que amo, e meditarei nos teus estatutos.");
    b->dados[SALMOS].capitulos[119].versos[49] = _("Lembra-te da palavra dada ao teu servo, na qual me fizeste esperar.");
    b->dados[SALMOS].capitulos[119].versos[50] = _("Isto é a minha consolação na minha angústia, que a tua promessa me vivifica.");
    b->dados[SALMOS].capitulos[119].versos[51] = _("Os soberbos zombaram grandemente de mim; contudo não me desviei da tua lei.");
    b->dados[SALMOS].capitulos[119].versos[52] = _("Lembro-me dos teus juízos antigos, ó Senhor, e assim me consolo.");
    b->dados[SALMOS].capitulos[119].versos[53] = _("Grande indignação apoderou-se de mim, por causa dos ímpios que abandonam a tua lei.");
    b->dados[SALMOS].capitulos[119].versos[54] = _("Os teus estatutos têm sido os meus cânticos na casa da minha peregrinação.");
    b->dados[SALMOS].capitulos[119].versos[55] = _("De noite me lembrei do teu nome, ó Senhor, e observei a tua lei.");
    b->dados[SALMOS].capitulos[119].versos[56] = _("Isto me sucedeu, porque tenho guardado os teus preceitos.");
    b->dados[SALMOS].capitulos[119].versos[57] = _("O Senhor é o meu quinhão; prometo observar as tuas palavras.");
    b->dados[SALMOS].capitulos[119].versos[58] = _("De todo o meu coração imploro o teu favor; tem piedade de mim, segundo a tua palavra.");
    b->dados[SALMOS].capitulos[119].versos[59] = _("Quando considero os meus caminhos, volto os meus pés para os teus testemunhos.");
    b->dados[SALMOS].capitulos[119].versos[60] = _("Apresso-me sem detença a observar os teus mandamentos.");
    b->dados[SALMOS].capitulos[119].versos[61] = _("Enleiam-me os laços dos ímpios; mas eu não me esqueço da tua lei.");
    b->dados[SALMOS].capitulos[119].versos[62] = _("À meia-noite me levanto para dar-te graças, por causa dos teus retos juízos.");
    b->dados[SALMOS].capitulos[119].versos[63] = _("Companheiro sou de todos os que te temem, e dos que guardam os teus preceitos.");
    b->dados[SALMOS].capitulos[119].versos[64] = _("A terra, ó Senhor, está cheia da tua benignidade; ensina-me os teus estatutos.");
    b->dados[SALMOS].capitulos[119].versos[65] = _("Tens usado de bondade para com o teu servo, Senhor, segundo a tua palavra.");
    b->dados[SALMOS].capitulos[119].versos[66] = _("Ensina-me bom juízo e ciência, pois creio nos teus mandamentos.");
    b->dados[SALMOS].capitulos[119].versos[67] = _("Antes de ser afligido, eu me extraviava; mas agora guardo a tua palavra.");
    b->dados[SALMOS].capitulos[119].versos[68] = _("Tu és bom e fazes o bem; ensina-me os teus estatutos.");
    b->dados[SALMOS].capitulos[119].versos[69] = _("Os soberbos forjam mentiras contra mim; mas eu de todo o coração guardo os teus preceitos.");
    b->dados[SALMOS].capitulos[119].versos[70] = _("Torna-se-lhes insensível o coração como a gordura; mas eu me deleito na tua lei.");
    b->dados[SALMOS].capitulos[119].versos[71] = _("Foi-me bom ter sido afligido, para que aprendesse os teus estatutos.");
    b->dados[SALMOS].capitulos[119].versos[72] = _("Melhor é para mim a lei da tua boca do que milhares de ouro e prata.");
    b->dados[SALMOS].capitulos[119].versos[73] = _("As tuas mãos me fizeram e me formaram; dá-me entendimento para que aprenda os teus mandamentos.");
    b->dados[SALMOS].capitulos[119].versos[74] = _("Os que te temem me verão e se alegrarão, porque tenho esperado na tua palavra.");
    b->dados[SALMOS].capitulos[119].versos[75] = _("Bem sei eu, ó Senhor, que os teus juízos são retos, e que em tua fidelidade me afligiste.");
    b->dados[SALMOS].capitulos[119].versos[76] = _("Sirva, pois, a tua benignidade para me consolar, segundo a palavra que deste ao teu servo.");
    b->dados[SALMOS].capitulos[119].versos[77] = _("Venham sobre mim as tuas ternas misericórdias, para que eu viva, pois a tua lei é o meu deleite.");
    b->dados[SALMOS].capitulos[119].versos[78] = _("Envergonhados sejam os soberbos, por me haverem subvertido sem causa; mas eu meditarei nos teus preceitos.");
    b->dados[SALMOS].capitulos[119].versos[79] = _("Voltem-se para mim os que te temem, para que conheçam os teus testemunhos.");
    b->dados[SALMOS].capitulos[119].versos[80] = _("Seja perfeito o meu coração nos teus estatutos, para que eu não seja envergonhado.");
    b->dados[SALMOS].capitulos[119].versos[81] = _("Desfalece a minha alma, aguardando a tua salvação; espero na tua palavra.");
    b->dados[SALMOS].capitulos[119].versos[82] = _("Os meus olhos desfalecem, esperando por tua promessa, enquanto eu pergunto: Quando me consolarás tu?");
    b->dados[SALMOS].capitulos[119].versos[83] = _("Pois tornei-me como odre na fumaça, mas não me esqueci dos teus estatutos.");
    b->dados[SALMOS].capitulos[119].versos[84] = _("Quantos serão os dias do teu servo? Até quando não julgarás aqueles que me perseguem?");
    b->dados[SALMOS].capitulos[119].versos[85] = _("Abriram covas para mim os soberbos, que não andam segundo a tua lei.");
    b->dados[SALMOS].capitulos[119].versos[86] = _("Todos os teus mandamentos são fiéis. Sou perseguido injustamente; ajuda-me!");
    b->dados[SALMOS].capitulos[119].versos[87] = _("Quase que me consumiram sobre a terra, mas eu não deixei os teus preceitos.");
    b->dados[SALMOS].capitulos[119].versos[88] = _("Vivifica-me segundo a tua benignidade, para que eu guarde os testemunhos da tua boca.");
    b->dados[SALMOS].capitulos[119].versos[89] = _("Para sempre, ó Senhor, a tua palavra está firmada nos céus.");
    b->dados[SALMOS].capitulos[119].versos[90] = _("A tua fidelidade estende-se de geração a geração; tu firmaste a terra, e firme permanece.");
    b->dados[SALMOS].capitulos[119].versos[91] = _("Conforme a tua ordenança, tudo se mantém até hoje, porque todas as coisas te obedecem.");
    b->dados[SALMOS].capitulos[119].versos[92] = _("Se a tua lei não fora o meu deleite, então eu teria perecido na minha angústia.");
    b->dados[SALMOS].capitulos[119].versos[93] = _("Nunca me esquecerei dos teus preceitos, pois por eles me tens vivificado.");
    b->dados[SALMOS].capitulos[119].versos[94] = _("Sou teu, salva-me; pois tenho buscado os teus preceitos.");
    b->dados[SALMOS].capitulos[119].versos[95] = _("Os ímpios me espreitam para me destruírem, mas eu atento para os teus testemunhos.");
    b->dados[SALMOS].capitulos[119].versos[96] = _("A toda perfeição vi limite, mas o teu mandamento é ilimitado.");
    b->dados[SALMOS].capitulos[119].versos[97] = _("Oh! quanto amo a tua lei! ela é a minha meditação o dia todo.");
    b->dados[SALMOS].capitulos[119].versos[98] = _("O teu mandamento me faz mais sábio do que meus inimigos, pois está sempre comigo.");
    b->dados[SALMOS].capitulos[119].versos[99] = _("Tenho mais entendimento do que todos os meus mestres, porque os teus testemunhos são a minha meditação.");
    b->dados[SALMOS].capitulos[119].versos[100] = _("Sou mais entendido do que os velhos, porque tenho guardado os teus preceitos.");
    b->dados[SALMOS].capitulos[119].versos[101] = _("Retenho os meus pés de todo caminho mau, a fim de observar a tua palavra.");
    b->dados[SALMOS].capitulos[119].versos[102] = _("Não me aperto das tuas ordenanças, porque és tu quem me instrui.");
    b->dados[SALMOS].capitulos[119].versos[103] = _("Oh! quão doces são as tuas palavras ao meu paladar! mais doces do que o mel à minha boca.");
    b->dados[SALMOS].capitulos[119].versos[104] = _("Pelos teus preceitos alcanço entendimento, pelo que aborreço toda vereda de falsidade.");
    b->dados[SALMOS].capitulos[119].versos[105] = _("Lâmpada para os meus pés é a tua palavra, e luz para o meu caminho.");
    b->dados[SALMOS].capitulos[119].versos[106] = _("Fiz juramento, e o confirmei, de guardar as tuas justas ordenanças.");
    b->dados[SALMOS].capitulos[119].versos[107] = _("Estou aflitíssimo; vivifica-me, ó Senhor, segundo a tua palavra.");
    b->dados[SALMOS].capitulos[119].versos[108] = _("Aceita, Senhor, eu te rogo, as oferendas voluntárias da minha boca, e ensina-me as tuas ordenanças.");
    b->dados[SALMOS].capitulos[119].versos[109] = _("Estou continuamente em perigo de vida; todavia não me esqueço da tua lei.");
    b->dados[SALMOS].capitulos[119].versos[110] = _("Os ímpios me armaram laço, contudo não me desviei dos teus preceitos.");
    b->dados[SALMOS].capitulos[119].versos[111] = _("Os teus testemunhos são a minha herança para sempre, pois são eles o gozo do meu coração.");
    b->dados[SALMOS].capitulos[119].versos[112] = _("Inclino o meu coração a cumprir os teus estatutos, para sempre, até o fim.");
    b->dados[SALMOS].capitulos[119].versos[113] = _("Aborreço a duplicidade, mas amo a tua lei.");
    b->dados[SALMOS].capitulos[119].versos[114] = _("Tu és o meu refúgio e o meu escudo; espero na tua palavra.");
    b->dados[SALMOS].capitulos[119].versos[115] = _("Apartai-vos de mim, malfeitores, para que eu guarde os mandamentos do meu Deus.");
    b->dados[SALMOS].capitulos[119].versos[116] = _("Ampara-me conforme a tua palavra, para que eu viva; e não permitas que eu seja envergonhado na minha esperança.");
    b->dados[SALMOS].capitulos[119].versos[117] = _("Sustenta-me, e serei salvo, e de contínuo terei respeito aos teus estatutos.");
    b->dados[SALMOS].capitulos[119].versos[118] = _("Desprezas todos os que se desviam dos teus estatutos, pois a astúcia deles é falsidade.");
    b->dados[SALMOS].capitulos[119].versos[119] = _("Deitas fora, como escória, todos os ímpios da terra; pelo que amo os teus testemunhos.");
    b->dados[SALMOS].capitulos[119].versos[120] = _("Arrepia-se-me a carne com temor de ti, e tenho medo dos teus juízos.");
    b->dados[SALMOS].capitulos[119].versos[121] = _("Tenho praticado a retidão e a justiça; não me abandones aos meus opressores.");
    b->dados[SALMOS].capitulos[119].versos[122] = _("Fica por fiador do teu servo para o bem; não me oprimem os soberbos.");
    b->dados[SALMOS].capitulos[119].versos[123] = _("Os meus olhos desfalecem à espera da tua salvação e da promessa da tua justiça.");
    b->dados[SALMOS].capitulos[119].versos[124] = _("Trata com o teu servo segundo a tua benignidade, e ensina-me os teus estatutos.");
    b->dados[SALMOS].capitulos[119].versos[125] = _("Sou teu servo; dá-me entendimento, para que eu conheça os teus testemunhos.");
    b->dados[SALMOS].capitulos[119].versos[126] = _("É tempo de agires, ó Senhor, pois eles violaram a tua lei.");
    b->dados[SALMOS].capitulos[119].versos[127] = _("Pelo que amo os teus mandamentos mais do que o ouro, sim, mais do que o ouro fino.");
    b->dados[SALMOS].capitulos[119].versos[128] = _("Por isso dirijo os meus passos por todos os teus preceitos, e aborreço toda vereda de falsidade.");
    b->dados[SALMOS].capitulos[119].versos[129] = _("Maravilhosos são os teus testemunhos, por isso a minha alma os guarda.");
    b->dados[SALMOS].capitulos[119].versos[130] = _("A exposição das tuas palavras dá luz; dá entendimento aos simples.");
    b->dados[SALMOS].capitulos[119].versos[131] = _("Abro a minha boca e arquejo, pois estou anelante pelos teus mandamentos.");
    b->dados[SALMOS].capitulos[119].versos[132] = _("Volta-te para mim, e compadece-te de mim, conforme usas para com os que amam o teu nome.");
    b->dados[SALMOS].capitulos[119].versos[133] = _("Firma os meus passos na tua palavra; e não se apodere de mim iniqüidade alguma.");
    b->dados[SALMOS].capitulos[119].versos[134] = _("Resgata-me da opressão do homem; assim guardarei os teus preceitos.");
    b->dados[SALMOS].capitulos[119].versos[135] = _("Faze resplandecer o teu rosto sobre o teu servo, e ensina-me os teus estatutos.");
    b->dados[SALMOS].capitulos[119].versos[136] = _("Os meus olhos derramam rios de lágrimas, porque os homens não guardam a tua lei.");
    b->dados[SALMOS].capitulos[119].versos[137] = _("Justo és, ó Senhor, e retos são os teus juízos.");
    b->dados[SALMOS].capitulos[119].versos[138] = _("Ordenaste os teus testemunhos com retidão, e com toda a fidelidade.");
    b->dados[SALMOS].capitulos[119].versos[139] = _("O meu zelo me consome, porque os meus inimigos se esquecem da tua palavra.");
    b->dados[SALMOS].capitulos[119].versos[140] = _("A tua palavra é fiel a toda prova, por isso o teu servo a ama.");
    b->dados[SALMOS].capitulos[119].versos[141] = _("Pequeno sou e desprezado, mas não me esqueço dos teus preceitos.");
    b->dados[SALMOS].capitulos[119].versos[142] = _("A tua justiça é justiça eterna, e a tua lei é a verdade.");
    b->dados[SALMOS].capitulos[119].versos[143] = _("Tribulação e angústia se apoderaram de mim; mas os teus mandamentos são o meu prazer.");
    b->dados[SALMOS].capitulos[119].versos[144] = _("Justos são os teus testemunhos para sempre; dá-me entendimento, para que eu viva.");
    b->dados[SALMOS].capitulos[119].versos[145] = _("Clamo de todo o meu coração; atende-me, Senhor! Eu guardarei os teus estatutos.");
    b->dados[SALMOS].capitulos[119].versos[146] = _("A ti clamo; salva-me, para que guarde os teus testemunhos.");
    b->dados[SALMOS].capitulos[119].versos[147] = _("Antecipo-me à alva da manhã e clamo; aguardo com esperança as tuas palavras.");
    b->dados[SALMOS].capitulos[119].versos[148] = _("Os meus olhos se antecipam às vigílias da noite, para que eu medite na tua palavra.");
    b->dados[SALMOS].capitulos[119].versos[149] = _("Ouve a minha voz, segundo a tua benignidade; vivifica-me, ó Senhor, segundo a tua justiça.");
    b->dados[SALMOS].capitulos[119].versos[150] = _("Aproximam-se os que me perseguem maliciosamente; andam afastados da tua lei.");
    b->dados[SALMOS].capitulos[119].versos[151] = _("Tu estás perto, Senhor, e todos os teus mandamentos são verdade.");
    b->dados[SALMOS].capitulos[119].versos[152] = _("Há muito sei eu dos teus testemunhos que os fundaste para sempre.");
    b->dados[SALMOS].capitulos[119].versos[153] = _("Olha para a minha aflição, e livra-me, pois não me esqueço da tua lei.");
    b->dados[SALMOS].capitulos[119].versos[154] = _("Pleiteia a minha causa, e resgata-me; vivifica-me segundo a tua palavra.");
    b->dados[SALMOS].capitulos[119].versos[155] = _("A salvação está longe dos ímpios, pois não buscam os teus estatutos.");
    b->dados[SALMOS].capitulos[119].versos[156] = _("Muitas são, Senhor, as tuas misericórdias; vivifica-me segundo os teus juízos.");
    b->dados[SALMOS].capitulos[119].versos[157] = _("Muitos são os meus perseguidores e os meus adversários, mas não me desvio dos teus testemunhos.");
    b->dados[SALMOS].capitulos[119].versos[158] = _("Vi os pérfidos, e me afligi, porque não guardam a tua palavra.");
    b->dados[SALMOS].capitulos[119].versos[159] = _("Considera como amo os teus preceitos; vivifica-me, Senhor, segundo a tua benignidade.");
    b->dados[SALMOS].capitulos[119].versos[160] = _("A soma da tua palavra é a verdade, e cada uma das tuas justas ordenanças dura para sempre.");
    b->dados[SALMOS].capitulos[119].versos[161] = _("Príncipes me perseguem sem causa, mas o meu coração teme as tuas palavras.");
    b->dados[SALMOS].capitulos[119].versos[162] = _("Regozijo-me com a tua palavra, como quem acha grande despojo.");
    b->dados[SALMOS].capitulos[119].versos[163] = _("Odeio e abomino a falsidade; amo, porém, a tua lei.");
    b->dados[SALMOS].capitulos[119].versos[164] = _("Sete vezes no dia te louvo pelas tuas justas ordenanças.");
    b->dados[SALMOS].capitulos[119].versos[165] = _("Muita paz têm os que amam a tua lei, e não há nada que os faça tropeçar.");
    b->dados[SALMOS].capitulos[119].versos[166] = _("Espero, Senhor, na tua salvação, e cumpro os teus mandamentos.");
    b->dados[SALMOS].capitulos[119].versos[167] = _("A minha alma observa os teus testemunhos; amo-os extremamente.");
    b->dados[SALMOS].capitulos[119].versos[168] = _("Observo os teus preceitos e os teus testemunhos, pois todos os meus caminhos estão diante de ti.");
    b->dados[SALMOS].capitulos[119].versos[169] = _("Chegue a ti o meu clamor, ó Senhor; dá-me entendimento conforme a tua palavra.");
    b->dados[SALMOS].capitulos[119].versos[170] = _("Chegue à tua presença a minha súplica; livra-me segundo a tua palavra.");
    b->dados[SALMOS].capitulos[119].versos[171] = _("Profiram louvor os meus lábios, pois me ensinas os teus estatutos.");
    b->dados[SALMOS].capitulos[119].versos[172] = _("Celebre a minha língua a tua palavra, pois todos os teus mandamentos são justos.");
    b->dados[SALMOS].capitulos[119].versos[173] = _("Esteja pronta a tua mão para me socorrer, pois escolhi os teus preceitos.");
    b->dados[SALMOS].capitulos[119].versos[174] = _("Anelo por tua salvação, ó Senhor; a tua lei é o meu prazer.");
    b->dados[SALMOS].capitulos[119].versos[175] = _("Que minha alma viva, para que te louve; ajudem-me as tuas ordenanças.");
    b->dados[SALMOS].capitulos[119].versos[176] = _("Desgarrei-me como ovelha perdida; busca o teu servo, pois não me esqueço dos teus mandamentos.");

    b->dados[SALMOS].capitulos[120].versos[1] = _("Na minha angústia clamei ao Senhor, e ele me ouviu.");
    b->dados[SALMOS].capitulos[120].versos[2] = _("Senhor, livra-me dos lábios mentirosos e da língua enganadora.");
    b->dados[SALMOS].capitulos[120].versos[3] = _("Que te será dado, ou que te será acrescentado, língua enganadora?");
    b->dados[SALMOS].capitulos[120].versos[4] = _("Flechas agudas do valente, com brasas vivas de zimbro!");
    b->dados[SALMOS].capitulos[120].versos[5] = _("Ai de mim, que peregrino em Meseque, e habito entre as tendas de Quedar!");
    b->dados[SALMOS].capitulos[120].versos[6] = _("Há muito que eu habito com aqueles que odeiam a paz.");
    b->dados[SALMOS].capitulos[120].versos[7] = _("Eu sou pela paz; mas quando falo, eles são pela guerra.");

    b->dados[SALMOS].capitulos[121].versos[1] = _("Elevo os meus olhos para os montes; de onde me vem o socorro?");
    b->dados[SALMOS].capitulos[121].versos[2] = _("O meu socorro vem do Senhor, que fez os céus e a terra.");
    b->dados[SALMOS].capitulos[121].versos[3] = _("Não deixará vacilar o teu pé; aquele que te guarda não dormitará.");
    b->dados[SALMOS].capitulos[121].versos[4] = _("Eis que não dormitará nem dormirá aquele que guarda a Israel.");
    b->dados[SALMOS].capitulos[121].versos[5] = _("O Senhor é quem te guarda; o Senhor é a tua sombra à tua mão direita.");
    b->dados[SALMOS].capitulos[121].versos[6] = _("De dia o sol não te ferirá, nem a lua de noite.");
    b->dados[SALMOS].capitulos[121].versos[7] = _("O Senhor te guardará de todo o mal; ele guardará a tua vida.");
    b->dados[SALMOS].capitulos[121].versos[8] = _("O Senhor guardará a tua saída e a tua entrada, desde agora e para sempre.");

    b->dados[SALMOS].capitulos[122].versos[1] = _("Alegrei-me quando me disseram: Vamos à casa do Senhor.");
    b->dados[SALMOS].capitulos[122].versos[2] = _("Os nossos pés estão parados dentro das tuas portas, ó Jerusalém!");
    b->dados[SALMOS].capitulos[122].versos[3] = _("Jerusalém, que és edificada como uma cidade compacta,");
    b->dados[SALMOS].capitulos[122].versos[4] = _("aonde sobem as tribos, as tribos do Senhor, como testemunho para Israel, a fim de darem graças ao nome do Senhor.");
    b->dados[SALMOS].capitulos[122].versos[5] = _("Pois ali estão postos os tronos de julgamento, os tronos da casa de Davi.");
    b->dados[SALMOS].capitulos[122].versos[6] = _("Orai pela paz de Jerusalém; prosperem aqueles que te amam.");
    b->dados[SALMOS].capitulos[122].versos[7] = _("Haja paz dentro de teus muros, e prosperidade dentro dos teus palácios.");
    b->dados[SALMOS].capitulos[122].versos[8] = _("Por causa dos meus irmãos e amigos, direi: Haja paz dentro de ti.");
    b->dados[SALMOS].capitulos[122].versos[9] = _("Por causa da casa do Senhor, nosso Deus, buscarei o teu bem.");

    b->dados[SALMOS].capitulos[123].versos[1] = _("A ti levanto os meus olhos, ó tu que estás entronizado nos céus.");
    b->dados[SALMOS].capitulos[123].versos[2] = _("Eis que assim como os olhos dos servos atentam para a mão do seu senhor, e os olhos da serva para a mão de sua senhora, assim os nossos olhos atentam para o Senhor nosso Deus, até que ele se compadeça de nós.");
    b->dados[SALMOS].capitulos[123].versos[3] = _("Compadece-te de nós, ó Senhor, compadece-te de nós, pois estamos sobremodo fartos de desprezo.");
    b->dados[SALMOS].capitulos[123].versos[4] = _("A nossa alma está sobremodo farta da zombaria dos arrogantes, e do desprezo dos soberbos.");

    b->dados[SALMOS].capitulos[124].versos[1] = _("Se não fora o Senhor, que esteve ao nosso lado, ora diga Israel:");
    b->dados[SALMOS].capitulos[124].versos[2] = _("Se não fora o Senhor, que esteve ao nosso lado, quando os homens se levantaram contra nós,");
    b->dados[SALMOS].capitulos[124].versos[3] = _("eles nos teriam tragado vivos, quando a sua ira se acendeu contra nós;");
    b->dados[SALMOS].capitulos[124].versos[4] = _("as águas nos teriam submergido, e a torrente teria passado sobre nós;");
    b->dados[SALMOS].capitulos[124].versos[5] = _("sim, as águas impetuosas teriam passado sobre nós.");
    b->dados[SALMOS].capitulos[124].versos[6] = _("Bendito seja o Senhor, que não nos entregou, como presa, aos dentes deles.");
    b->dados[SALMOS].capitulos[124].versos[7] = _("Escapamos, como um pássaro, do laço dos passarinheiros; o laço quebrou-se, e nós escapamos.");
    b->dados[SALMOS].capitulos[124].versos[8] = _("O nosso socorro está no nome do Senhor, que fez os céus e a terra.");

    b->dados[SALMOS].capitulos[125].versos[1] = _("Aqueles que confiam no Senhor são como o monte Sião, que não pode ser abalado, mas permanece para sempre.");
    b->dados[SALMOS].capitulos[125].versos[2] = _("Como estão os montes ao redor de Jerusalém, assim o Senhor está ao redor do seu povo, desde agora e para sempre.");
    b->dados[SALMOS].capitulos[125].versos[3] = _("Porque o cetro da impiedade não repousará sobre a sorte dos justos, para que os justos não estendam as suas mãos para cometer a iniqüidade.");
    b->dados[SALMOS].capitulos[125].versos[4] = _("Faze o bem, ó Senhor, aos bons e aos que são retos de coração.");
    b->dados[SALMOS].capitulos[125].versos[5] = _("Mas aos que se desviam para os seus caminhos tortuosos, levá-los-á o Senhor juntamente com os que praticam a maldade. Que haja paz sobre Israel.");

    b->dados[SALMOS].capitulos[126].versos[1] = _("Quando o Senhor trouxe do cativeiro os que voltaram a Sião, éramos como os que estão sonhando.");
    b->dados[SALMOS].capitulos[126].versos[2] = _("Então a nossa boca se encheu de riso e a nossa língua de cânticos. Então se dizia entre as nações: Grandes coisas fez o Senhor por eles.");
    b->dados[SALMOS].capitulos[126].versos[3] = _("Sim, grandes coisas fez o Senhor por nós, e por isso estamos alegres.");
    b->dados[SALMOS].capitulos[126].versos[4] = _("Faze regressar os nossos cativos, Senhor, como as correntes no sul.");
    b->dados[SALMOS].capitulos[126].versos[5] = _("Os que semeiam em lágrimas, com cânticos de júbilo segarão.");
    b->dados[SALMOS].capitulos[126].versos[6] = _("Aquele que sai chorando, levando a semente para semear, voltará com cânticos de júbilo, trazendo consigo os seus molhos.");

    b->dados[SALMOS].capitulos[127].versos[1] = _("Se o Senhor não edificar a casa, em vão trabalham os que a edificam; se o Senhor não guardar a cidade, em vão vigia a sentinela.");
    b->dados[SALMOS].capitulos[127].versos[2] = _("Inútil vos será levantar de madrugada, repousar tarde, comer o pão de dores, pois ele supre aos seus amados enquanto dormem.");
    b->dados[SALMOS].capitulos[127].versos[3] = _("Eis que os filhos são herança da parte do Senhor, e o fruto do ventre o seu galardão.");
    b->dados[SALMOS].capitulos[127].versos[4] = _("Como flechas na mão dum homem valente, assim os filhos da mocidade.");
    b->dados[SALMOS].capitulos[127].versos[5] = _("Bem-aventurado o homem que enche deles a sua aljava; não serão confundidos, quando falarem com os seus inimigos à porta.");

    b->dados[SALMOS].capitulos[128].versos[1] = _("Bem-aventurado todo aquele que teme ao Senhor e anda nos seus caminhos.");
    b->dados[SALMOS].capitulos[128].versos[2] = _("Pois comerás do trabalho das tuas mãos; feliz serás, e te irá bem.");
    b->dados[SALMOS].capitulos[128].versos[3] = _("A tua mulher será como a videira frutífera, no interior da tua casa; os teus filhos como plantas de oliveira, ao redor da tua mesa.");
    b->dados[SALMOS].capitulos[128].versos[4] = _("Eis que assim será abençoado o homem que teme ao Senhor.");
    b->dados[SALMOS].capitulos[128].versos[5] = _("De Sião o Senhor te abençoará; verás a prosperidade de Jerusalém por todos os dias da tua vida,");
    b->dados[SALMOS].capitulos[128].versos[6] = _("e verás os filhos de teus filhos. A paz seja sobre Israel.");

    b->dados[SALMOS].capitulos[129].versos[1] = _("Gravemente me angustiaram desde a minha mocidade, diga agora Israel;");
    b->dados[SALMOS].capitulos[129].versos[2] = _("gravemente me angustiaram desde a minha mocidade, todavia não prevaleceram contra mim.");
    b->dados[SALMOS].capitulos[129].versos[3] = _("Os lavradores araram sobre as minhas costas; compridos fizeram os seus sulcos.");
    b->dados[SALMOS].capitulos[129].versos[4] = _("O Senhor é justo; ele corta as cordas dos ímpios.");
    b->dados[SALMOS].capitulos[129].versos[5] = _("Sejam envergonhados e repelidos para trás todos os que odeiam a Sião.");
    b->dados[SALMOS].capitulos[129].versos[6] = _("Sejam como a erva dos telhados, que seca antes de florescer;");
    b->dados[SALMOS].capitulos[129].versos[7] = _("com a qual o segador não enche a mão, nem o regaço o que ata os feixes;");
    b->dados[SALMOS].capitulos[129].versos[8] = _("nem dizem os que passam: A bênção do Senhor seja sobre vós; nós vos abençoamos em nome do Senhor.");

    b->dados[SALMOS].capitulos[130].versos[1] = _("Das profundezas clamo a ti, ó Senhor.");
    b->dados[SALMOS].capitulos[130].versos[2] = _("Senhor, escuta a minha voz; estejam os teus ouvidos atentos à voz das minhas súplicas.");
    b->dados[SALMOS].capitulos[130].versos[3] = _("Se tu, Senhor, observares as iniqüidades, Senhor, quem subsistirá?");
    b->dados[SALMOS].capitulos[130].versos[4] = _("Mas contigo está o perdão, para que sejas temido.");
    b->dados[SALMOS].capitulos[130].versos[5] = _("Aguardo ao Senhor; a minha alma o aguarda, e espero na sua palavra.");
    b->dados[SALMOS].capitulos[130].versos[6] = _("A minha alma anseia pelo Senhor, mais do que os guardas pelo romper da manhã, sim, mais do que os guardas pela manhã.");
    b->dados[SALMOS].capitulos[130].versos[7] = _("Espera, ó Israel, no Senhor! pois com o Senhor há benignidade, e com ele há copiosa redenção;");
    b->dados[SALMOS].capitulos[130].versos[8] = _("e ele remirá a Israel de todas as suas iniqüidades.");

    b->dados[SALMOS].capitulos[131].versos[1] = _("Senhor, o meu coração não é soberbo, nem os meus olhos são altivos; não me ocupo de assuntos grandes e maravilhosos demais para mim.");
    b->dados[SALMOS].capitulos[131].versos[2] = _("Pelo contrário, tenho feito acalmar e sossegar a minha alma; qual criança desmamada sobre o seio de sua mãe, qual criança desmamada está a minha alma para comigo.");
    b->dados[SALMOS].capitulos[131].versos[3] = _("Espera, ó Israel, no Senhor, desde agora e para sempre.");

    b->dados[SALMOS].capitulos[132].versos[1] = _("Lembra-te, Senhor, a bem de Davi, de todas as suas aflições;");
    b->dados[SALMOS].capitulos[132].versos[2] = _("como jurou ao Senhor, e fez voto ao Poderoso de Jacó, dizendo:");
    b->dados[SALMOS].capitulos[132].versos[3] = _("Não entrarei na casa em que habito, nem subirei ao leito em que durmo;");
    b->dados[SALMOS].capitulos[132].versos[4] = _("não darei sono aos meus olhos, nem adormecimento às minhas pálpebras,");
    b->dados[SALMOS].capitulos[132].versos[5] = _("até que eu ache um lugar para o Senhor uma morada para o Poderoso de Jacó.");
    b->dados[SALMOS].capitulos[132].versos[6] = _("Eis que ouvimos falar dela em Efrata, e a achamos no campo de Jaar.");
    b->dados[SALMOS].capitulos[132].versos[7] = _("Entremos nos seus tabernáculos; prostremo-nos ante o escabelo de seus pés.");
    b->dados[SALMOS].capitulos[132].versos[8] = _("Levanta-te, Senhor, entra no lugar do teu repouso, tu e a arca da tua força.");
    b->dados[SALMOS].capitulos[132].versos[9] = _("Vistam-se os teus sacerdotes de justiça, e exultem de júbilo os teus santos.");
    b->dados[SALMOS].capitulos[132].versos[10] = _("Por amor de Davi, teu servo, não rejeites a face do teu ungido.");
    b->dados[SALMOS].capitulos[132].versos[11] = _("O Senhor jurou a Davi com verdade, e não se desviará dela: Do fruto das tuas entranhas porei sobre o teu trono.");
    b->dados[SALMOS].capitulos[132].versos[12] = _("Se os teus filhos guardarem o meu pacto, e os meus testemunhos, que eu lhes hei de ensinar, também os seus filhos se assentarão perpetuamente no teu trono.");
    b->dados[SALMOS].capitulos[132].versos[13] = _("Porque o Senhor escolheu a Sião; desejou-a para sua habitação, dizendo:");
    b->dados[SALMOS].capitulos[132].versos[14] = _("Este é o lugar do meu repouso para sempre; aqui habitarei, pois o tenho desejado.");
    b->dados[SALMOS].capitulos[132].versos[15] = _("Abençoarei abundantemente o seu mantimento; fartarei de pão os seus necessitados.");
    b->dados[SALMOS].capitulos[132].versos[16] = _("Vestirei de salvação os seus sacerdotes; e de júbilo os seus santos exultarão");
    b->dados[SALMOS].capitulos[132].versos[17] = _("Ali farei brotar a força de Davi; preparei uma lâmpada para o meu ungido.");
    b->dados[SALMOS].capitulos[132].versos[18] = _("Vestirei de confusão os seus inimigos; mas sobre ele resplandecerá a sua coroa.");

    b->dados[SALMOS].capitulos[133].versos[1] = _("Oh! quão bom e quão suave é que os irmãos vivam em união!");
    b->dados[SALMOS].capitulos[133].versos[2] = _("É como o óleo precioso sobre a cabeça, que desceu sobre a barba, a barba de Arão, que desceu sobre a gola das suas vestes;");
    b->dados[SALMOS].capitulos[133].versos[3] = _("como o orvalho de Hermom, que desce sobre os montes de Sião; porque ali o Senhor ordenou a bênção, a vida para sempre.");

    b->dados[SALMOS].capitulos[134].versos[1] = _("Eis aqui, bendizei ao Senhor, todos vós, servos do Senhor, que de noite assistis na casa do Senhor.");
    b->dados[SALMOS].capitulos[134].versos[2] = _("Erguei as mãos para o santuário, e bendizei ao Senhor.");
    b->dados[SALMOS].capitulos[134].versos[3] = _("Desde Sião te abençoe o Senhor, que fez os céus e a terra.");

    b->dados[SALMOS].capitulos[135].versos[1] = _("Louvai ao Senhor. Louvai o nome do Senhor; louvai-o, servos do Senhor,");
    b->dados[SALMOS].capitulos[135].versos[2] = _("vós que assistis na casa do Senhor, nos átrios da casa do nosso Deus.");
    b->dados[SALMOS].capitulos[135].versos[3] = _("Louvai ao Senhor, porque o Senhor é bom; cantai louvores ao seu nome, porque ele é bondoso.");
    b->dados[SALMOS].capitulos[135].versos[4] = _("Porque o Senhor escolheu para si a Jacó, e a Israel para seu tesouro peculiar.");
    b->dados[SALMOS].capitulos[135].versos[5] = _("Porque eu conheço que o Senhor é grande e que o nosso Senhor está acima de todos os deuses.");
    b->dados[SALMOS].capitulos[135].versos[6] = _("Tudo o que o Senhor deseja ele o faz, no céu e na terra, nos mares e em todos os abismos.");
    b->dados[SALMOS].capitulos[135].versos[7] = _("Faz subir os vapores das extremidades da terra; faz os relâmpagos para a chuva; tira os ventos dos seus tesouros.");
    b->dados[SALMOS].capitulos[135].versos[8] = _("Foi ele que feriu os primogênitos do Egito, desde os homens até os animais;");
    b->dados[SALMOS].capitulos[135].versos[9] = _("que operou sinais e prodígios no meio de ti, ó Egito, contra Faraó e contra os seus servos;");
    b->dados[SALMOS].capitulos[135].versos[10] = _("que feriu muitas nações, e matou reis poderosos:");
    b->dados[SALMOS].capitulos[135].versos[11] = _("a Siom, rei dos amorreus, e a Ogue, rei de Basã, e a todos os reinos de Canaã;");
    b->dados[SALMOS].capitulos[135].versos[12] = _("e deu a terra deles em herança, em herança a Israel, seu povo.");
    b->dados[SALMOS].capitulos[135].versos[13] = _("O teu nome, ó Senhor, subsiste para sempre; e a tua memória, ó Senhor, por todas as gerações.");
    b->dados[SALMOS].capitulos[135].versos[14] = _("Pois o Senhor julgará o seu povo, e se compadecerá dos seus servos.");
    b->dados[SALMOS].capitulos[135].versos[15] = _("Os ídolos das nações são prata e ouro, obra das mãos dos homens;");
    b->dados[SALMOS].capitulos[135].versos[16] = _("têm boca, mas não falam; têm olhos, mas não vêem;");
    b->dados[SALMOS].capitulos[135].versos[17] = _("têm ouvidos, mas não ouvem; nem há sopro algum na sua boca.");
    b->dados[SALMOS].capitulos[135].versos[18] = _("Semelhantemente a eles se tornarão os que os fazem, e todos os que neles confiam.");
    b->dados[SALMOS].capitulos[135].versos[19] = _("Ó casa de Israel, bendizei ao Senhor; ó casa de Arão, bendizei ao Senhor;");
    b->dados[SALMOS].capitulos[135].versos[20] = _("ó casa de Levi, bendizei ao Senhor; vós, os que temeis ao Senhor, bendizei ao Senhor.");
    b->dados[SALMOS].capitulos[135].versos[21] = _("Desde Sião seja bendito o Senhor, que habita em Jerusalém. Louvai ao Senhor.");

    b->dados[SALMOS].capitulos[136].versos[1] = _("Dai graças ao Senhor, porque ele é bom; porque a sua benignidade dura para sempre.");
    b->dados[SALMOS].capitulos[136].versos[2] = _("Dai graças ao Deus dos deuses, porque a sua benignidade dura para sempre");
    b->dados[SALMOS].capitulos[136].versos[3] = _("Dai graças ao Senhor dos senhores, porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[136].versos[4] = _("ao único que faz grandes maravilhas, porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[136].versos[5] = _("àquele que com entendimento fez os céus, porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[136].versos[6] = _("àquele que estendeu a terra sobre as águas, porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[136].versos[7] = _("àquele que fez os grandes luminares, porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[136].versos[8] = _("o sol para governar de dia, porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[136].versos[9] = _("a lua e as estrelas para presidirem a noite, porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[136].versos[10] = _("àquele que feriu o Egito nos seus primogênitos, porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[136].versos[11] = _("e que tirou a Israel do meio deles, porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[136].versos[12] = _("com mão forte, e com braço estendido, porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[136].versos[13] = _("àquele que dividiu o Mar Vermelho em duas partes, porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[136].versos[14] = _("e fez passar Israel pelo meio dele, porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[136].versos[15] = _("mas derrubou a Faraó com o seu exército no Mar Vermelho, porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[136].versos[16] = _("àquele que guiou o seu povo pelo deserto, porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[136].versos[17] = _("àquele que feriu os grandes reis, porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[136].versos[18] = _("e deu a morte a reis famosos, porque a sua benignidade dura para sempre.");
    b->dados[SALMOS].capitulos[136].versos[19] = _("a Siom, rei dos amorreus, porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[136].versos[20] = _("e a Ogue, rei de Basã, porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[136].versos[21] = _("e deu a terra deles em herança, porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[136].versos[22] = _("sim, em herança a Israel, seu servo, porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[136].versos[23] = _("que se lembrou de nós em nossa humilhação, porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[136].versos[24] = _("e nos libertou dos nossos inimigos, porque a sua benignidade dura para sempre;");
    b->dados[SALMOS].capitulos[136].versos[25] = _("que dá alimento a toda a carne, porque a sua benignidade dura para sempre.");
    b->dados[SALMOS].capitulos[136].versos[26] = _("Dai graças ao Deus dos céus, porque a sua benignidade dura para sempre.");

    b->dados[SALMOS].capitulos[137].versos[1] = _("Junto aos rios de Babilônia, ali nos assentamos e nos pusemos a chorar, recordando-nos de Sião.");
    b->dados[SALMOS].capitulos[137].versos[2] = _("Nos salgueiros que há no meio dela penduramos as nossas harpas,");
    b->dados[SALMOS].capitulos[137].versos[3] = _("pois ali aqueles que nos levaram cativos nos pediam canções; e os que nos atormentavam, que os alegrássemos, dizendo: Cantai-nos um dos cânticos de Sião.");
    b->dados[SALMOS].capitulos[137].versos[4] = _("Mas como entoaremos o cântico do Senhor em terra estrangeira?");
    b->dados[SALMOS].capitulos[137].versos[5] = _("Se eu me esquecer de ti, ó Jerusalém, esqueça-se a minha destra da sua destreza.");
    b->dados[SALMOS].capitulos[137].versos[6] = _("Apegue-se-me a língua ao céu da boca, se não me lembrar de ti, se eu não preferir Jerusalém à minha maior alegria.");
    b->dados[SALMOS].capitulos[137].versos[7] = _("Lembra-te, Senhor, contra os edomitas, do dia de Jerusalém, porque eles diziam: Arrasai-a, arrasai-a até os seus alicerces.");
    b->dados[SALMOS].capitulos[137].versos[8] = _("Ah! filha de Babilônia, devastadora; feliz aquele que te retribuir consoante nos fizeste a nós;");
    b->dados[SALMOS].capitulos[137].versos[9] = _("feliz aquele que pegar em teus pequeninos e der com eles nas pedra.");

    b->dados[SALMOS].capitulos[138].versos[1] = _("Graças te dou de todo o meu coração; diante dos deuses a ti canto louvores.");
    b->dados[SALMOS].capitulos[138].versos[2] = _("Inclino-me para o teu santo templo, e louvo o teu nome pela tua benignidade, e pela tua fidelidade; pois engrandeceste acima de tudo o teu nome e a tua palavra.");
    b->dados[SALMOS].capitulos[138].versos[3] = _("No dia em que eu clamei, atendeste-me; alentaste-me, fortalecendo a minha alma.");
    b->dados[SALMOS].capitulos[138].versos[4] = _("Todos os reis da terra de louvarão, ó Senhor, quando ouvirem as palavras da tua boca;");
    b->dados[SALMOS].capitulos[138].versos[5] = _("e cantarão os caminhos do Senhor, pois grande é a glória do Senhor.");
    b->dados[SALMOS].capitulos[138].versos[6] = _("Ainda que o Senhor é excelso, contudo atenta para o humilde; mas ao soberbo, conhece-o de longe.");
    b->dados[SALMOS].capitulos[138].versos[7] = _("Embora eu ande no meio da angústia, tu me revivificas; contra a ira dos meus inimigos estendes a tua mão, e a tua destra me salva.");
    b->dados[SALMOS].capitulos[138].versos[8] = _("O Senhor aperfeiçoará o que me diz respeito. A tua benignidade, ó Senhor, dura para sempre; não abandones as obras das tuas mãos.");

    b->dados[SALMOS].capitulos[139].versos[1] = _("Senhor, tu me sondas, e me conheces.");
    b->dados[SALMOS].capitulos[139].versos[2] = _("Tu conheces o meu sentar e o meu levantar; de longe entendes o meu pensamento.");
    b->dados[SALMOS].capitulos[139].versos[3] = _("Esquadrinhas o meu andar, e o meu deitar, e conheces todos os meus caminhos.");
    b->dados[SALMOS].capitulos[139].versos[4] = _("Sem que haja uma palavra na minha língua, eis que, ó Senhor, tudo conheces.");
    b->dados[SALMOS].capitulos[139].versos[5] = _("Tu me cercaste em volta, e puseste sobre mim a tua mão.");
    b->dados[SALMOS].capitulos[139].versos[6] = _("Tal conhecimento é maravilhoso demais para mim; elevado é, não o posso atingir.");
    b->dados[SALMOS].capitulos[139].versos[7] = _("Para onde me irei do teu Espírito, ou para onde fugirei da tua presença?");
    b->dados[SALMOS].capitulos[139].versos[8] = _("Se subir ao céu, tu aí estás; se fizer no Seol a minha cama, eis que tu ali estás também.");
    b->dados[SALMOS].capitulos[139].versos[9] = _("Se tomar as asas da alva, se habitar nas extremidades do mar,");
    b->dados[SALMOS].capitulos[139].versos[10] = _("ainda ali a tua mão me guiará e a tua destra me susterá.");
    b->dados[SALMOS].capitulos[139].versos[11] = _("Se eu disser: Ocultem-me as trevas; torne-se em noite a luz que me circunda;");
    b->dados[SALMOS].capitulos[139].versos[12] = _("nem ainda as trevas são escuras para ti, mas a noite resplandece como o dia; as trevas e a luz são para ti a mesma coisa.");
    b->dados[SALMOS].capitulos[139].versos[13] = _("Pois tu formaste os meus rins; entreteceste-me no ventre de minha mãe.");
    b->dados[SALMOS].capitulos[139].versos[14] = _("Eu te louvarei, porque de um modo tão admirável e maravilhoso fui formado; maravilhosas são as tuas obras, e a minha alma o sabe muito bem.");
    b->dados[SALMOS].capitulos[139].versos[15] = _("Os meus ossos não te foram encobertos, quando no oculto fui formado, e esmeradamente tecido nas profundezas da terra.");
    b->dados[SALMOS].capitulos[139].versos[16] = _("Os teus olhos viram a minha substância ainda informe, e no teu livro foram escritos os dias, sim, todos os dias que foram ordenados para mim, quando ainda não havia nem um deles.");
    b->dados[SALMOS].capitulos[139].versos[17] = _("E quão preciosos me são, ó Deus, os teus pensamentos! Quão grande é a soma deles!");
    b->dados[SALMOS].capitulos[139].versos[18] = _("Se eu os contasse, seriam mais numerosos do que a areia; quando acordo ainda estou contigo.");
    b->dados[SALMOS].capitulos[139].versos[19] = _("Oxalá que matasses o perverso, ó Deus, e que os homens sanguinários se apartassem de mim,");
    b->dados[SALMOS].capitulos[139].versos[20] = _("homens que se rebelam contra ti, e contra ti se levantam para o mal.");
    b->dados[SALMOS].capitulos[139].versos[21] = _("Não odeio eu, ó Senhor, aqueles que te odeiam? e não me aflijo por causa dos que se levantam contra ti?");
    b->dados[SALMOS].capitulos[139].versos[22] = _("Odeio-os com ódio completo; tenho-os por inimigos.");
    b->dados[SALMOS].capitulos[139].versos[23] = _("Sonda-me, ó Deus, e conhece o meu coração; prova-me, e conhece os meus pensamentos;");
    b->dados[SALMOS].capitulos[139].versos[24] = _("vê se há em mim algum caminho perverso, e guia-me pelo caminho eterno.");

    b->dados[SALMOS].capitulos[140].versos[1] = _("Livra-me, ó Senhor, dos homens maus; guarda-me dos homens violentos,");
    b->dados[SALMOS].capitulos[140].versos[2] = _("os quais maquinam maldades no coração; estão sempre projetando guerras.");
    b->dados[SALMOS].capitulos[140].versos[3] = _("Aguçaram as línguas como a serpente; peçonha de áspides está debaixo dos seus lábios.");
    b->dados[SALMOS].capitulos[140].versos[4] = _("Guarda-me, ó Senhor, das mãos dos ímpios; preserva-me dos homens violentos, os quais planejaram transtornar os meus passos.");
    b->dados[SALMOS].capitulos[140].versos[5] = _("Os soberbos armaram-me laços e cordas; estenderam uma rede à beira do caminho; puseram-me armadilhas.");
    b->dados[SALMOS].capitulos[140].versos[6] = _("Eu disse, ao Senhor: Tu és o meu Deus; dá ouvidos, ó Senhor, à voz das minhas súplicas.");
    b->dados[SALMOS].capitulos[140].versos[7] = _("Ó Senhor, meu Senhor, meu forte libertador, tu cobriste a minha cabeça no dia da batalha.");
    b->dados[SALMOS].capitulos[140].versos[8] = _("Não concedas, ó Senhor, aos ímpios os seus desejos; não deixes ir por diante o seu mau propósito.");
    b->dados[SALMOS].capitulos[140].versos[9] = _("Não levantem a cabeça os que me cercam; cubra-os a maldade dos seus lábios.");
    b->dados[SALMOS].capitulos[140].versos[10] = _("Caiam sobre eles brasas vivas; sejam lançados em covas profundas, para que não se tornem a levantar!");
    b->dados[SALMOS].capitulos[140].versos[11] = _("Não se estabeleça na terra o caluniador; o mal persiga o homem violento com golpe sobre golpe.");
    b->dados[SALMOS].capitulos[140].versos[12] = _("Sei que o Senhor manterá a causa do aflito, e o direito do necessitado.");
    b->dados[SALMOS].capitulos[140].versos[13] = _("Decerto os justos louvarão o teu nome; os retos habitarão na tua presença.");

    b->dados[SALMOS].capitulos[141].versos[1] = _("Ó Senhor, a ti clamo; dá-te pressa em me acudir! Dá ouvidos à minha voz, quando a ti clamo!");
    b->dados[SALMOS].capitulos[141].versos[2] = _("Suba a minha oração, como incenso, diante de ti, e seja o levantar das minhas mãos como o sacrifício da tarde!");
    b->dados[SALMOS].capitulos[141].versos[3] = _("Põe, ó Senhor, uma guarda à minha boca; vigia a porta dos meus lábios!");
    b->dados[SALMOS].capitulos[141].versos[4] = _("Não inclines o meu coração para o mal, nem para se ocupar de coisas más, com aqueles que praticam a iniqüidade; e não coma eu das suas gulodices!");
    b->dados[SALMOS].capitulos[141].versos[5] = _("Fira-me o justo, será isso uma benignidade; e repreenda-me, isso será como óleo sobre a minha cabeça; não o recuse a minha cabeça; mas continuarei a orar contra os feitos dos ímpios.");
    b->dados[SALMOS].capitulos[141].versos[6] = _("Quando os seus juízes forem arremessados duma penha abaixo, saberão que as palavras do Senhor são verdadeiras.");
    b->dados[SALMOS].capitulos[141].versos[7] = _("Como quando alguém lavra e sulca a terra, são os nossos ossos espalhados à boca do Seol.");
    b->dados[SALMOS].capitulos[141].versos[8] = _("Mas os meus olhos te contemplam, ó Senhor, meu Senhor; em ti tenho buscado refúgio; não me deixes sem defesa!");
    b->dados[SALMOS].capitulos[141].versos[9] = _("Guarda-me do laço que me armaram, e das armadilhas dos que praticam a iniqüidade.");
    b->dados[SALMOS].capitulos[141].versos[10] = _("Caiam os ímpios nas suas próprias redes, até que eu tenha escapado inteiramente.");

    b->dados[SALMOS].capitulos[142].versos[1] = _("Com a minha voz clamo ao Senhor; com a minha voz ao Senhor suplico.");
    b->dados[SALMOS].capitulos[142].versos[2] = _("Derramo perante ele a minha queixa; diante dele exponho a minha tribulação.");
    b->dados[SALMOS].capitulos[142].versos[3] = _("Quando dentro de mim esmorece o meu espírito, então tu conheces a minha vereda; no caminho em que eu ando ocultaram-me um laço.");
    b->dados[SALMOS].capitulos[142].versos[4] = _("Olha para a minha mão direita, e vê, pois não há quem me conheça; refúgio me faltou; ninguém se interessa por mim.");
    b->dados[SALMOS].capitulos[142].versos[5] = _("A ti, ó Senhor, clamei; eu disse: Tu és o meu refúgio, o meu quinhão na terra dos viventes.");
    b->dados[SALMOS].capitulos[142].versos[6] = _("Atende ao meu clamor, porque estou muito abatido; livra-me dos meus perseguidores, porque são mais fortes do que eu.");
    b->dados[SALMOS].capitulos[142].versos[7] = _("Tira-me da prisão, para que eu louve o teu nome; os justos me rodearão, pois me farás muito bem.");

    b->dados[SALMOS].capitulos[143].versos[1] = _("Ó Senhor, ouve a minha oração, dá ouvidos às minhas súplicas! Atende-me na tua fidelidade, e na tua retidão;");
    b->dados[SALMOS].capitulos[143].versos[2] = _("e não entres em juízo com o teu servo, porque à tua vista não se achará justo nenhum vivente.");
    b->dados[SALMOS].capitulos[143].versos[3] = _("Pois o inimigo me perseguiu; abateu-me até o chão; fez-me habitar em lugares escuros, como aqueles que morreram há muito.");
    b->dados[SALMOS].capitulos[143].versos[4] = _("Pelo que dentro de mim esmorece o meu espírito, e em mim está desolado o meu coração.");
    b->dados[SALMOS].capitulos[143].versos[5] = _("Lembro-me dos dias antigos; considero todos os teus feitos; medito na obra das tuas mãos.");
    b->dados[SALMOS].capitulos[143].versos[6] = _("A ti estendo as minhas mãos; a minha alma, qual terra sedenta, tem sede de ti.");
    b->dados[SALMOS].capitulos[143].versos[7] = _("Atende-me depressa, ó Senhor; o meu espírito desfalece; não escondas de mim o teu rosto, para que não me torne semelhante aos que descem à cova.");
    b->dados[SALMOS].capitulos[143].versos[8] = _("Faze-me ouvir da tua benignidade pela manhã, pois em ti confio; faze-me saber o caminho que devo seguir, porque a ti elevo a minha alma.");
    b->dados[SALMOS].capitulos[143].versos[9] = _("Livra-me, ó Senhor, dos meus inimigos; porque em ti é que eu me refugio.");
    b->dados[SALMOS].capitulos[143].versos[10] = _("Ensina-me a fazer a tua vontade, pois tu és o meu Deus; guie-me o teu bom Espírito por terreno plano.");
    b->dados[SALMOS].capitulos[143].versos[11] = _("Vivifica-me, ó Senhor, por amor do teu nome; por amor da tua justiça, tira-me da tribulação.");
    b->dados[SALMOS].capitulos[143].versos[12] = _("E por tua benignidade extermina os meus inimigos, e destrói todos os meus adversários, pois eu sou servo.");

    b->dados[SALMOS].capitulos[144].versos[1] = _("Bendito seja o Senhor, minha rocha, que adestra as minhas mãos para a peleja e os meus dedos para a guerra;");
    b->dados[SALMOS].capitulos[144].versos[2] = _("meu refúgio e minha fortaleza, meu alto retiro e meu e meu libertador, escudo meu, em quem me refugio; ele é quem me sujeita o meu povo.");
    b->dados[SALMOS].capitulos[144].versos[3] = _("Ó Senhor, que é o homem, para que tomes conhecimento dele, e o filho do homem, para que o consideres?");
    b->dados[SALMOS].capitulos[144].versos[4] = _("O homem é semelhante a um sopro; os seus dias são como a sombra que passa.");
    b->dados[SALMOS].capitulos[144].versos[5] = _("Abaixa, ó Senhor, o teu céu, e desce! Toca os montes, para que fumeguem!");
    b->dados[SALMOS].capitulos[144].versos[6] = _("Arremessa os teus raios, e dissipa-os; envia as tuas flechas, e desbarata-os!");
    b->dados[SALMOS].capitulos[144].versos[7] = _("Estende as tuas mãos desde o alto; livra-me, e arrebata-me das poderosas águas e da mão do estrangeiro,");
    b->dados[SALMOS].capitulos[144].versos[8] = _("cuja boca fala vaidade, e cuja mão direita é a destra da falsidade.");
    b->dados[SALMOS].capitulos[144].versos[9] = _("A ti, ó Deus, cantarei um cântico novo; com a harpa de dez cordas te cantarei louvores,");
    b->dados[SALMOS].capitulos[144].versos[10] = _("sim, a ti que dás a vitória aos reis, e que livras da espada maligna a teu servo Davi.");
    b->dados[SALMOS].capitulos[144].versos[11] = _("Livra-me, e tira-me da mão do estrangeiro, cuja boca fala mentiras, e cuja mão direita é a destra da falsidade.");
    b->dados[SALMOS].capitulos[144].versos[12] = _("Sejam os nossos filhos, na sua mocidade, como plantas bem desenvolvidas, e as nossas filhas como pedras angulares lavradas, como as de um palácio.");
    b->dados[SALMOS].capitulos[144].versos[13] = _("Estejam repletos os nossos celeiros, fornecendo toda sorte de provisões; as nossas ovelhas produzam a milhares e a dezenas de milhares em nossos campos;");
    b->dados[SALMOS].capitulos[144].versos[14] = _("os nossos bois levem ricas cargas; e não haja assaltos, nem sortidas, nem clamores em nossas ruas!");
    b->dados[SALMOS].capitulos[144].versos[15] = _("Bem-aventurado o povo a quem assim sucede! Bem-aventurado o povo cujo Deus é o Senhor.");

    b->dados[SALMOS].capitulos[145].versos[1] = _("Eu te exaltarei, ó Deus, rei meu; e bendirei o teu nome pelos séculos dos séculos.");
    b->dados[SALMOS].capitulos[145].versos[2] = _("Cada dia te bendirei, e louvarei o teu nome pelos séculos dos séculos.");
    b->dados[SALMOS].capitulos[145].versos[3] = _("Grande é o Senhor, e mui digno de ser louvado; e a sua grandeza é insondável.");
    b->dados[SALMOS].capitulos[145].versos[4] = _("Uma geração louvará as tuas obras à outra geração, e anunciará os teus atos poderosos.");
    b->dados[SALMOS].capitulos[145].versos[5] = _("Na magnificência gloriosa da tua majestade e nas tuas obras maravilhosas meditarei;");
    b->dados[SALMOS].capitulos[145].versos[6] = _("falar-se-á do poder dos teus feitos tremendos, e eu contarei a tua grandeza.");
    b->dados[SALMOS].capitulos[145].versos[7] = _("Publicarão a memória da tua grande bondade, e com júbilo celebrarão a tua justiça.");
    b->dados[SALMOS].capitulos[145].versos[8] = _("Bondoso e compassivo é o Senhor, tardio em irar-se, e de grande benignidade.");
    b->dados[SALMOS].capitulos[145].versos[9] = _("O Senhor é bom para todos, e as suas misericórdias estão sobre todas as suas obras.");
    b->dados[SALMOS].capitulos[145].versos[10] = _("Todas as tuas obras te louvarão, ó Senhor, e os teus santos te bendirão.");
    b->dados[SALMOS].capitulos[145].versos[11] = _("Falarão da glória do teu reino, e relatarão o teu poder,");
    b->dados[SALMOS].capitulos[145].versos[12] = _("para que façam saber aos filhos dos homens os teus feitos poderosos e a glória do esplendor do teu reino.");
    b->dados[SALMOS].capitulos[145].versos[13] = _("O teu reino é um reino eterno; o teu domínio dura por todas as gerações.");
    b->dados[SALMOS].capitulos[145].versos[14] = _("O Senhor sustém a todos os que estão a cair, e levanta a todos os que estão abatidos.");
    b->dados[SALMOS].capitulos[145].versos[15] = _("Os olhos de todos esperam em ti, e tu lhes dás o seu mantimento a seu tempo;");
    b->dados[SALMOS].capitulos[145].versos[16] = _("abres a mão, e satisfazes o desejo de todos os viventes.");
    b->dados[SALMOS].capitulos[145].versos[17] = _("Justo é o Senhor em todos os seus caminhos, e benigno em todas as suas obras.");
    b->dados[SALMOS].capitulos[145].versos[18] = _("Perto está o Senhor de todos os que o invocam, de todos os que o invocam em verdade.");
    b->dados[SALMOS].capitulos[145].versos[19] = _("Ele cumpre o desejo dos que o temem; ouve o seu clamor, e os salva.");
    b->dados[SALMOS].capitulos[145].versos[20] = _("O Senhor preserva todos os que o amam, mas a todos os ímpios ele os destrói.");
    b->dados[SALMOS].capitulos[145].versos[21] = _("Publique a minha boca o louvor do Senhor; e bendiga toda a carne o seu santo nome para todo o sempre.");

    b->dados[SALMOS].capitulos[146].versos[1] = _("Louvai ao Senhor. Ó minha alma, louva ao Senhor.");
    b->dados[SALMOS].capitulos[146].versos[2] = _("Louvarei ao Senhor durante a minha vida; cantarei louvores ao meu Deus enquanto viver.");
    b->dados[SALMOS].capitulos[146].versos[3] = _("Não confieis em príncipes, nem em filho de homem, em quem não há auxílio.");
    b->dados[SALMOS].capitulos[146].versos[4] = _("Sai-lhe o espírito, e ele volta para a terra; naquele mesmo dia perecem os seus pensamentos.");
    b->dados[SALMOS].capitulos[146].versos[5] = _("Bem-aventurado aquele que tem o Deus de Jacó por seu auxílio, e cuja esperança está no Senhor seu Deus");
    b->dados[SALMOS].capitulos[146].versos[6] = _("que fez os céus e a terra, o mar e tudo quanto neles há, e que guarda a verdade para sempre;");
    b->dados[SALMOS].capitulos[146].versos[7] = _("que faz justiça aos oprimidos, que dá pão aos famintos. O Senhor solta os encarcerados;");
    b->dados[SALMOS].capitulos[146].versos[8] = _("o Senhor abre os olhos aos cegos; o Senhor levanta os abatidos; o Senhor ama os justos.");
    b->dados[SALMOS].capitulos[146].versos[9] = _("O Senhor preserva os peregrinos; ampara o órfão e a viúva; mas transtorna o caminho dos ímpios.");
    b->dados[SALMOS].capitulos[146].versos[10] = _("O Senhor reinará eternamente: o teu Deus, ó Sião, reinará por todas as gerações. Louvai ao Senhor!");

    b->dados[SALMOS].capitulos[147].versos[1] = _("Louvai ao Senhor; porque é bom cantar louvores ao nosso Deus; pois isso é agradável, e decoroso é o louvor.");
    b->dados[SALMOS].capitulos[147].versos[2] = _("O Senhor edifica Jerusalém, congrega os dispersos de Israel;");
    b->dados[SALMOS].capitulos[147].versos[3] = _("sara os quebrantados de coração, e cura-lhes as feridas;");
    b->dados[SALMOS].capitulos[147].versos[4] = _("conta o número das estrelas, chamando-as a todas pelos seus nomes.");
    b->dados[SALMOS].capitulos[147].versos[5] = _("Grande é o nosso Senhor, e de grande poder; não há limite ao seu entendimento.");
    b->dados[SALMOS].capitulos[147].versos[6] = _("O Senhor eleva os humildes, e humilha os perversos até a terra.");
    b->dados[SALMOS].capitulos[147].versos[7] = _("Cantai ao Senhor em ação de graças; com a harpa cantai louvores ao nosso Deus.");
    b->dados[SALMOS].capitulos[147].versos[8] = _("Ele é que cobre o céu de nuvens, que prepara a chuva para a terra, e que faz produzir erva sobre os montes;");
    b->dados[SALMOS].capitulos[147].versos[9] = _("que dá aos animais o seu alimento, e aos filhos dos corvos quando clamam.");
    b->dados[SALMOS].capitulos[147].versos[10] = _("Não se deleita na força do cavalo, nem se compraz nas pernas do homem.");
    b->dados[SALMOS].capitulos[147].versos[11] = _("O Senhor se compraz nos que o temem, nos que esperam na sua benignidade.");
    b->dados[SALMOS].capitulos[147].versos[12] = _("Louva, ó Jerusalém, ao Senhor; louva, ó Sião, ao teu Deus.");
    b->dados[SALMOS].capitulos[147].versos[13] = _("Porque ele fortalece as trancas das tuas portas; abençoa aos teus filhos dentro de ti.");
    b->dados[SALMOS].capitulos[147].versos[14] = _("Ele é quem estabelece a paz nas tuas fronteiras; quem do mais fino trigo te farta;");
    b->dados[SALMOS].capitulos[147].versos[15] = _("quem envia o seu mandamento pela terra; a sua palavra corre mui velozmente.");
    b->dados[SALMOS].capitulos[147].versos[16] = _("Ele dá a neve como lã, esparge a geada como cinza,");
    b->dados[SALMOS].capitulos[147].versos[17] = _("e lança o seu gelo em pedaços; quem pode resistir ao seu frio?");
    b->dados[SALMOS].capitulos[147].versos[18] = _("Manda a sua palavra, e os derrete; faz soprar o vento, e correm as águas;");
    b->dados[SALMOS].capitulos[147].versos[19] = _("ele revela a sua palavra a Jacó, os seus estatutos e as suas ordenanças a Israel.");
    b->dados[SALMOS].capitulos[147].versos[20] = _("Não fez assim a nenhuma das outras nações; e, quanto às suas ordenanças, elas não as conhecem. Louvai ao Senhor!");

    b->dados[SALMOS].capitulos[148].versos[1] = _("Louvai ao Senhor! Louvai ao Senhor desde o céu, louvai-o nas alturas!");
    b->dados[SALMOS].capitulos[148].versos[2] = _("Louvai-o, todos os seus anjos; louvai-o, todas as suas hostes!");
    b->dados[SALMOS].capitulos[148].versos[3] = _("Louvai-o, sol e lua; louvai-o, todas as estrelas luzentes!");
    b->dados[SALMOS].capitulos[148].versos[4] = _("Louvai-o, céus dos céus, e as águas que estão sobre os céus!");
    b->dados[SALMOS].capitulos[148].versos[5] = _("Louvem eles o nome do Senhor; pois ele deu ordem, e logo foram criados.");
    b->dados[SALMOS].capitulos[148].versos[6] = _("Também ele os estabeleceu para todo sempre; e lhes fixou um limite que nenhum deles ultrapassará.");
    b->dados[SALMOS].capitulos[148].versos[7] = _("Louvai ao Senhor desde a terra, vós, monstros marinhos e todos os abismos;");
    b->dados[SALMOS].capitulos[148].versos[8] = _("fogo e saraiva, neve e vapor; vento tempestuoso que escuta a sua palavra;");
    b->dados[SALMOS].capitulos[148].versos[9] = _("montes e todos os outeiros; árvores frutíferas e todos os cedros;");
    b->dados[SALMOS].capitulos[148].versos[10] = _("feras e todo o gado; répteis e aves voadoras;");
    b->dados[SALMOS].capitulos[148].versos[11] = _("reis da terra e todos os povos; príncipes e todos os juízes da terra;");
    b->dados[SALMOS].capitulos[148].versos[12] = _("mancebos e donzelas; velhos e crianças!");
    b->dados[SALMOS].capitulos[148].versos[13] = _("Louvem eles o nome do Senhor, pois só o seu nome é excelso; a sua glória é acima da terra e do céu.");
    b->dados[SALMOS].capitulos[148].versos[14] = _("Ele também exalta o poder do seu povo, o louvor de todos os seus santos, dos filhos de Israel, um povo que lhe é chegado. Louvai ao Senhor!");

    b->dados[SALMOS].capitulos[149].versos[1] = _("Louvai ao Senhor! Cantai ao Senhor um cântico novo, e o seu louvor na assembléia dos santos!");
    b->dados[SALMOS].capitulos[149].versos[2] = _("Alegre-se Israel naquele que o fez; regozijem-se os filhos de Sião no seu Rei.");
    b->dados[SALMOS].capitulos[149].versos[3] = _("Louvem-lhe o nome com danças, cantem-lhe louvores com adufe e harpa.");
    b->dados[SALMOS].capitulos[149].versos[4] = _("Porque o Senhor se agrada do seu povo; ele adorna os mansos com a salvação.");
    b->dados[SALMOS].capitulos[149].versos[5] = _("Exultem de glória os santos, cantem de alegria nos seus leitos.");
    b->dados[SALMOS].capitulos[149].versos[6] = _("Estejam na sua garganta os altos louvores de Deus, e na sua mão espada de dois gumes,");
    b->dados[SALMOS].capitulos[149].versos[7] = _("para exercerem vingança sobre as nações, e castigos sobre os povos;");
    b->dados[SALMOS].capitulos[149].versos[8] = _("para prenderem os seus reis com cadeias, e os seus nobres com grilhões de ferro;");
    b->dados[SALMOS].capitulos[149].versos[9] = _("para executarem neles o juízo escrito; esta honra será para todos os santos. Louvai ao Senhor!");

    b->dados[SALMOS].capitulos[150].versos[1] = _("Louvai ao Senhor! Louvai a Deus no seu santuário; louvai-o no firmamento do seu poder!");
    b->dados[SALMOS].capitulos[150].versos[2] = _("Louvai-o pelos seus atos poderosos; louvai-o conforme a excelência da sua grandeza!");
    b->dados[SALMOS].capitulos[150].versos[3] = _("Louvai-o ao som de trombeta; louvai-o com saltério e com harpa!");
    b->dados[SALMOS].capitulos[150].versos[4] = _("Louvai-o com adufe e com danças; louvai-o com instrumentos de cordas e com flauta!");
    b->dados[SALMOS].capitulos[150].versos[5] = _("Louvai-o com címbalos sonoros; louvai-o com címbalos altissonantes!");
    b->dados[SALMOS].capitulos[150].versos[6] = _("Tudo quanto tem fôlego louve ao Senhor. Louvai ao Senhor!");

}
